/**
 * Get the native language flag emoji based on user's "Переклад" picker selection.
 * Falls back to 🇷🇺 if not found.
 */
function getNativeLangFlag(): string {
    const code = getNativeLanguage();
    const lang = LANGUAGES.find(l => l.code === code);
    return lang?.flag || '🇷🇺';
}

/**
 * Get the native language name (e.g. "Russian", "Japanese") for prompt injection.
 */
function getNativeLangName(): string {
    const code = getNativeLanguage();
    const lang = LANGUAGES.find(l => l.code === code);
    return lang?.nameEn || 'Russian';
}

