/** Track which blocks we've already processed */
const enrichedBlockIds = new Set<string>();
/** Prevent concurrent enrichment runs */
let isEnriching = false;
/** Debounce timer */
let enrichTimer: ReturnType<typeof setTimeout> | null = null;

/**
 * Handler for structured tool call data (Gemini Function Calling).
 * Replaces the need to run the Text Bot fallback.
 */
export function handleReplicaMetadata(args: { replica_id?: number, original_text?: string, translation?: string, hint_grammar?: string, answer_options?: string[] }): void {
    const chatContainer = document.getElementById('chat-messages');
    if (!chatContainer) return;
    
    // Find ALL dialogue blocks
    let allBlocks = Array.from(chatContainer.querySelectorAll('.dialogue-block'));
    if (allBlocks.length === 0) {
        // RACE CONDITION FALLBACK: The tool call arrived BEFORE the Voice AI streamed the text that creates the block.
        // We must create an empty block in the current active AI message so the metadata isn't lost!
        const lastAiMessage = chatContainer.querySelector('.message.ai:last-child .message-bubble');
        if (lastAiMessage) {
            const replNum = args.replica_id || 1;
            lastAiMessage.innerHTML = `<div class="dialogue-block" data-dialogue-id="dlg-${replNum}">
                <div class="dialogue-header">
                    <span class="dialogue-number">${replNum}</span>
                    <span class="dialogue-speaker-label">ГРАММИНИ</span>
                </div>
                <div class="dialogue-content"><span class="translation-icon translation" style="margin-right: 8px;">🇩🇪</span></div>
            </div>`;
            allBlocks = Array.from(chatContainer.querySelectorAll('.dialogue-block'));
        } else {
            return;
        }
    }
    
    let block: HTMLElement | undefined;

    // 1. Try to find the exact block by replica_id
    if (args.replica_id) {
        const matchingBlocks = allBlocks.filter(b => b.getAttribute('data-dialogue-id') === `dlg-${args.replica_id}`);
        block = matchingBlocks.length > 0 ? matchingBlocks[matchingBlocks.length - 1] as HTMLElement : undefined;
    }

    // 2. Fallback to finding the first block without a tool_call
    if (!block) {
        block = allBlocks.find(b => !b.querySelector('.hint-container[data-enriched="tool_call"]')) as HTMLElement;
    }
    
    // 3. Fallback to the last block if all somehow got enriched (shouldn't happen)
    if (!block) {
        block = allBlocks[allBlocks.length - 1] as HTMLElement;
    }

    const dialogueContent = block.querySelector('.dialogue-content');
    if (!dialogueContent) return;

    // Build Hint HTML directly from the structured arguments
    let hintStr = args.hint_grammar || '';
    if (!hintStr.includes('📜 ГРАММАТИКА')) {
        hintStr = `📜 ГРАММАТИКА\n${hintStr}`;
    }

    let answerStr = '';
    if (args.answer_options && Array.isArray(args.answer_options)) {
        answerStr = 'ОТВЕТ / ANSWER\n' + args.answer_options.join('\n');
    }

    const cleanSection = `<hint>\n${hintStr}\n</hint>\n<answer>\n${answerStr}\n</answer>`;
    
    // 0. UPDATE GERMAN TEXT & REMOVE ROGUE AI COMMENTARY (fixes truncation & extra text!)
    // The websocket stream might have skipped words or added English commentary at the end.
    // We wipe the dialogue content and ONLY restore the perfect original_text + TTS button + translation.
    if (args.original_text && args.original_text.trim() !== '') {
        const iconSpan = dialogueContent.querySelector('.translation-icon');
        const existingTtsBtn = dialogueContent.querySelector('.german-tts-btn');
        const existingTransBlock = dialogueContent.querySelector('.translation-block, .translation');
        
        // Preserve 🔈 emoji if the bot included it at the end of its speech but omitted it in the tool call
        const currentText = dialogueContent.textContent?.replace('🇩🇪', '').trim() || '';
        const hasAudioEmoji = currentText.includes('🔈');
        let finalGermanText = args.original_text;

        // --- CLEAN UP AI HALLUCINATIONS FROM ORIGINAL TEXT ---
        // 1. Remove ANY "REPLICA X:" prefixes that the AI incorrectly included in the tool call text
        finalGermanText = finalGermanText.replace(/REPLICA\s*\d+\s*:?/gi, '').trim();
        
        // 2. Remove duplicated text if the AI repeated itself inside original_text
        // (e.g. "Sentence. Sentence." -> "Sentence.")
        // Check if the string is exactly the same string concatenated to itself
        const halfLen = Math.floor(finalGermanText.length / 2);
        if (finalGermanText.length > 20) {
            // First we trim both halves to account for potential spaces between the duplicates
            // We search for a repeating pattern
            for (let i = Math.floor(finalGermanText.length / 3); i <= halfLen + 5; i++) {
                const firstPart = finalGermanText.substring(0, i).trim();
                const remainder = finalGermanText.substring(i).trim();
                if (firstPart.length > 10 && remainder.startsWith(firstPart)) {
                    console.warn(`[Enrichment] ⚠️ Detected AI text duplication in original_text! Cleaning it.`);
                    finalGermanText = firstPart;
                    break;
                }
            }
        }

        // ALWAYS use original_text from the tool call — it is the authoritative source.
        // The streamed text may be truncated (missing beginning) or have extra junk at the end.
        // Trust the structured function call data over the raw stream.
        console.log(`[Enrichment] ✅ Using cleaned original_text (${finalGermanText.length} chars) — streamed was ${currentText.length} chars`);

        if (hasAudioEmoji && !finalGermanText.includes('🔈')) {
            finalGermanText += ' 🔈';
        }
        
        // Also try to retain karaoke spans if the text length is very similar (we just want to append elements)
        // But the requirements ask just to restore original_text with TTS. So we use finalGermanText.
        
        dialogueContent.innerHTML = '';
        if (iconSpan) dialogueContent.appendChild(iconSpan);
        
        // Wrap text in a span so it flows inline with the TTS button
        const textSpan = document.createElement('span');
        let escapedText = escapeHtml(finalGermanText);
        let formattedText = escapedText.replace(/([.!?])\s{1,3}([A-ZÄÖÜА-ЯЁ])/g, '$1<br>$2');
        textSpan.innerHTML = ' ' + formattedText + ' ';
        dialogueContent.appendChild(textSpan);
        
        if (existingTtsBtn) {
            dialogueContent.appendChild(existingTtsBtn);
        } else {
            // Create it if it doesn't exist yet so it's placed inline immediately
            const newTtsBtn = document.createElement('button');
            newTtsBtn.className = 'tts-inline-btn german-tts-btn';
            newTtsBtn.title = 'Прослушать немецкий (Gemini)';
            newTtsBtn.textContent = '🔊';
            newTtsBtn.setAttribute('onclick', 'playDialogueText(this)');
            dialogueContent.appendChild(newTtsBtn);
        }
        
        if (existingTransBlock) dialogueContent.appendChild(existingTransBlock);
    }
    
    // 1. Update translation
    if (args.translation) {
        // ALWAYS build a fresh translation block since we might have wiped the old one
        // to save the German text from truncation above.
        let escapedTranslation = escapeHtml(args.translation);
        let formattedTranslation = escapedTranslation.replace(/([.!?])\s{1,3}([A-ZÄÖÜА-ЯЁ])/g, '$1<br>$2');

        let textHtml = `<div class="translation-text-section" style="display: flex; flex-direction: row; align-items: flex-start; gap: 6px; margin-top: 4px; padding-top: 4px; border-top: 1px dashed rgba(255,255,255,0.1);">
                            <span class="translation-icon" style="flex-shrink: 0;">${getNativeLangFlag()}</span> 
                            <span class="translation-text" style="flex-grow: 1;">${formattedTranslation}</span>
                            <button class="tts-inline-btn translation-tts-btn" style="flex-shrink: 0;" onclick="playTranslationText(this)" title="Прослушать">🔊</button>
                        </div>`;

        const transDiv = document.createElement('div');
        transDiv.className = 'translation-block translation selected-theme';
        transDiv.innerHTML = textHtml;
        // Search if we accidentally kept one in dialogueContent to avoid duplicates
        const existingInDom = dialogueContent.querySelector('.translation-block, .translation');
        if (existingInDom) existingInDom.remove();
        
        // Append to bottom (after German TTS button)
        dialogueContent.appendChild(transDiv);
    } else if (args.original_text) {
        // Translation was missing from tool_call (AI omitted it despite being required)
        console.warn(`[Enrichment] ⚠️ Translation missing for replica ${args.replica_id} — AI omitted it from tool_call`);
        const placeholderDiv = document.createElement('div');
        placeholderDiv.className = 'translation-block translation selected-theme';
        placeholderDiv.setAttribute('data-needs-translation', 'true');
        placeholderDiv.innerHTML = `<div class="translation-text-section" style="display: flex; flex-direction: row; align-items: flex-start; gap: 6px; margin-top: 4px; padding-top: 4px; border-top: 1px dashed rgba(255,255,255,0.1);">
            <span class="translation-icon" style="flex-shrink: 0;">${getNativeLangFlag()}</span> 
            <span class="translation-text" style="flex-grow: 1; color: rgba(255,255,255,0.4); font-style: italic;">⏳ перевод загружается...</span>
        </div>`;
        const existingInDom2 = dialogueContent.querySelector('.translation-block, .translation');
        if (existingInDom2) existingInDom2.remove();
        dialogueContent.appendChild(placeholderDiv);
    }

    const Vocabulary = (window as any).Vocabulary;
    let combinedHtml = '';
    
    if (Vocabulary && typeof Vocabulary.buildHintAnswerHtml === 'function') {
        const hintMatch = cleanSection.match(/<hint>([\s\S]*?)<\/hint>/i);
        const answerMatch = cleanSection.match(/<answer>([\s\S]*?)<\/answer>/i);
        const hintContent = hintMatch ? hintMatch[1].trim() : '';
        const answerContent = answerMatch ? answerMatch[1].trim() : '';
        combinedHtml = Vocabulary.buildHintAnswerHtml(hintContent, answerContent);
    } else {
        combinedHtml = parseBlockSection(cleanSection);
    }
    
    // Remove old loaders/hints
    block.querySelectorAll('.enrichment-loader').forEach(el => el.remove());
    block.querySelectorAll('.hint-container').forEach(el => el.remove());

    // Inject the new Hint/Answer container
    const wrapper = document.createElement('div');
    wrapper.innerHTML = combinedHtml;
    
    const newHint = wrapper.firstElementChild;
    if (newHint) {
         newHint.setAttribute('data-enriched', 'tool_call');
         block.appendChild(newHint); // Append to block directly for flex styling
    }
    
    // ====== RE-WRAP KARAOKE WORDS (enrichment destroys them via innerHTML = '') ======
    // Without this, accordion highlighting stops working after translations/hints arrive
    try {
        const SKIP_CLASSES = ['translation', 'translation-block', 'translation-icon', 'hint-text', 'answer-text', 'hint-container', 'answer-container', 'dialogue-header', 'dialogue-number', 'dialogue-speaker-label', 'hint-btn', 'tts-play-btn', 'german-tts-btn', 'hint-column', 'hint-panel', 'answer-item', 'answer-list', 'answer-header', 'hint-header', 'hint-list', 'hint-item', 'thought-details', 'ai-thinking-inline', 'thought-title', 'thought-content', 'karaoke-word'];
        const wrapTextNodesForKaraoke = (node: Node): void => {
            if (node.nodeType === Node.TEXT_NODE) {
                const text = node.textContent || '';
                if (text.trim()) {
                    const wrapper = document.createDocumentFragment();
                    let wordIdx = 0;
                    const parts = text.split(/(\s+)/);
                    parts.forEach(part => {
                        if (part.trim()) {
                            const span = document.createElement('span');
                            span.className = 'karaoke-word';
                            span.id = `kw-enrich-${Date.now()}-${wordIdx++}`;
                            span.textContent = part;
                            wrapper.appendChild(span);
                        } else if (part) {
                            wrapper.appendChild(document.createTextNode(part));
                        }
                    });
                    node.parentNode?.replaceChild(wrapper, node);
                }
            } else if (node.nodeType === Node.ELEMENT_NODE) {
                const el = node as HTMLElement;
                if (!SKIP_CLASSES.some(cls => el.classList.contains(cls))) {
                    Array.from(node.childNodes).forEach(child => wrapTextNodesForKaraoke(child));
                }
            }
        };
        // Re-wrap dialogue-content text nodes (the spoken parts)
        const dcForKaraoke = block.querySelectorAll('.dialogue-content');
        dcForKaraoke.forEach(dc => {
            Array.from(dc.childNodes).forEach(child => wrapTextNodesForKaraoke(child));
        });
    } catch (e) {
        console.warn('[Enrichment] Karaoke re-wrap failed (non-fatal):', e);
    }

    injectInlineTtsButtons();

    // If the message has already finalized, we must explicitly update localStorage
    // otherwise the tool call changes are lost on page reload!
    const parentMsg = block.closest('.message.ai');
    if (parentMsg && !parentMsg.classList.contains('streaming')) {
        const chatId = (window as any).ChatSessions?.getCurrentChatId?.() || '';
        const bubble = parentMsg.querySelector('.message-bubble');
        if (chatId && bubble && typeof (window as any).ChatSessions?.updateLastAiMessageText === 'function') {
            (window as any).ChatSessions.updateLastAiMessageText(chatId, bubble.innerHTML);
        }
    }
}

/**
 * Scan for dialogue blocks that need <hint>/<answer> enrichment.
 * Called after finalize() in streaming-display.ts.
 * Uses debounce to batch blocks that arrive close together.
 */
export function enrichDialogueBlocks(isTurnComplete: boolean = false): void {
    // Debounce: wait 2s for more blocks to arrive before batching
    if (enrichTimer) clearTimeout(enrichTimer);
    enrichTimer = setTimeout(() => {
        enrichTimer = null;
        doEnrichment(isTurnComplete);
    }, 2000);
}

async function doEnrichment(isTurnComplete: boolean = false): Promise<void> {
    if (isEnriching) return; // Already running

    // Text Bot enrichment strategy per DELIVERY MODE:
    // - fast_text / auto_10 → Text Bot runs for replicas 2-10
    // - interactive → Voice AI sends Tool Calls. If Voice AI FORGETS the tool call, 
    //   and the turn completes (isTurnComplete=true), this function will pick it up as a fallback!
    const teacherModeRadio = document.querySelector('input[name="teacher-mode"]:checked') as HTMLInputElement;
    const deliveryMode = ((window as any).getDeliveryMode?.() || 'interactive');
    
    if (teacherModeRadio?.value === 'active' && deliveryMode !== 'fast_text') {
        if (!isTurnComplete) {
            console.log(`[Enrichment] 🛑 Text Bot disabled (Active + ${deliveryMode} mode — waiting for Tool Calls).`);
            return;
        } else {
            console.log(`[Enrichment] 🔄 Turn complete in ${deliveryMode} mode. Text Bot will run as fallback for missed metadata.`);
        }
    }

    // 🛡️ CRITICAL FIX: The isTurnComplete flag might be STALE after the 2.5s debounce delay!
    // Voice AI might have already received turn_complete but started streaming the NEXT block immediately.
    // If there's an active streaming AI message, the turn is ALWAYS incomplete!
    const streamingModule = (window as any).StreamingDisplay;
    if (streamingModule?.streamingAiMsg) {
        if (isTurnComplete) {
            console.warn(`[Enrichment] ⚠️ Overriding isTurnComplete=true because Voice AI started a NEW stream during the debounce delay!`);
            isTurnComplete = false;
        }
    }

    const chatContainer = document.getElementById('chat-messages');
    if (!chatContainer) return;

    // Collect ALL blocks
    const allBlocks = Array.from(chatContainer.querySelectorAll('.dialogue-block[data-dialogue-id]'));

    const blocksToEnrich: Array<{
        id: string;
        num: string;
        germanText: string;
        translation: string;
        element: HTMLElement;
    }> = [];

    allBlocks.forEach((block, index) => {
        const blockId = block.getAttribute('data-dialogue-id') || '';

        // PROTECT THE LIVE STREAMING BLOCK 
        // If the Voice AI is just taking a breath (isTurnComplete is false),
        // we MUST NOT let the Text Bot harvest the very last block, because the Voice AI
        // is still actively typing into it. It will cause a generation collision!
        // We only grant permission to rewrite the final block if the stream is dead (isTurnComplete).
        if (!isTurnComplete && index === allBlocks.length - 1) {
            console.log(`[Enrichment] 🛡️ Protecting active live block ${blockId} from Parallel Harvest.`);
            return;
        }

        // Prevent Duplicate requests (if block is already actively loading)
        if (block.querySelector('.enrichment-loader')) {
            return;
        }

        // Skip blocks that already have a hint-container — whether from Voice AI or Text Bot.
        // Voice AI inline hints are GOOD ENOUGH! Do NOT replace them.
        const existingHintContainer = block.querySelector('.hint-container');
        if (existingHintContainer) {
            enrichedBlockIds.add(blockId);
            return;
        }

        const contentEl = block.querySelector('.dialogue-content');
        if (!contentEl) return;

        const germanText = contentEl.textContent?.trim() || '';
        const translationEl = block.querySelector('.translation');
        const translationText = translationEl?.textContent?.trim() || '';
        const numEl = block.querySelector('.dialogue-number');
        const dialogueNum = numEl?.textContent?.trim() || blockId;

        // If block has less than 10 chars, it's a corrupted/empty block (e.g. AI disconnected immediately after block header).
        // We MUST treat it as a dummy block and let Text Bot overwrite it!
        if (germanText.length < 10) {
            // CRITICAL FIX: Only treat it as missing if the turn is COMPLETE.
            // If Voice AI is still streaming, a short block is simply not finished yet!
            if (!isTurnComplete) {
                console.log(`[Enrichment] 🛡️ Skipping short block ${blockId} because Voice AI is still writing to it.`);
                return;
            }
            blocksToEnrich.push({
                id: blockId,
                num: dialogueNum,
                germanText: '', // Empty means missing / needs rewrite
                translation: '',
                element: block as HTMLElement,
            });
            return;
        }

        const germanHtml = contentEl ? contentEl.innerHTML || '' : '';

        // Only skip blocks that are actively streaming an incomplete <hint> tag right now.
        // Fully streamed hints were already removed above (Voice AI inline hint → replaced).
        // We only protect blocks mid-stream where <hint is open but </hint> hasn't arrived yet.
        if (!isTurnComplete && /<hint\b/i.test(germanHtml) && !/<\/hint>/i.test(germanHtml)) {
            console.log(`[Enrichment] 🛡️ Skipping Block ${blockId} — Voice AI is still streaming a <hint> tag.`);
            return;
        }

        blocksToEnrich.push({
            id: blockId,
            num: dialogueNum,
            germanText,
            translation: translationText,
            element: block as HTMLElement,
        });
    });

    // === MISSING BLOCKS: Create dummy blocks for replicas 5-10 that Voice AI never generated ===
    // This MUST run even if blocksToEnrich is empty (all existing blocks have hints).
    // We count ALL blocks in DOM (including already enriched ones) to determine how many are missing.
    let expectedReplicas = (window as any).StreamingDisplay?.lastPromisedCount || 0;
    const allBlocksNow = Array.from(chatContainer.querySelectorAll('.dialogue-block[data-dialogue-id]'));

    if (allBlocksNow.length > 0) {
        // Check delivery mode
        const currentDeliveryMode = ((window as any).getDeliveryMode?.() || 'interactive');
        
        if (currentDeliveryMode !== 'fast_text') {
            // INTERACTIVE / AUTO_10: expect only 1 replica per turn — do NOT create dummy blocks
            expectedReplicas = 1;
        } else if (!expectedReplicas || expectedReplicas < 3) {
            const teacherModeRadio = document.querySelector('input[name="teacher-mode"]:checked') as HTMLInputElement;
            const mode = teacherModeRadio?.value || 'standard';
            expectedReplicas = mode === 'active' ? 10 : 5;
        }

        if (isTurnComplete && expectedReplicas > allBlocksNow.length) {
            const missingCount = expectedReplicas - allBlocksNow.length;
            console.log(`[Enrichment] Missing ${missingCount} blocks. Generating them with Text Bot.`);

            const event = new CustomEvent('system-message', {
                detail: { text: `⏳ Стрим Voice AI прерван. Текстовый ИИ восстанавливает недостающие ${missingCount} диалога... (ожидайте ~40 сек)` }
            });
            window.dispatchEvent(event);

            let appendTarget = allBlocksNow[allBlocksNow.length - 1] as HTMLElement | null;
            let startNum = allBlocksNow.length + 1;

            for (let i = 0; i < missingCount; i++) {
                const blockNum = startNum + i;
                const blockId = 'dlg-' + blockNum;

                const dummyBlock = document.createElement('div');
                dummyBlock.className = 'dialogue-block';
                dummyBlock.setAttribute('data-dialogue-id', blockId);
                dummyBlock.innerHTML = `
                <div class="dialogue-header">
                    <span class="dialogue-number">${blockNum}</span>
                    <span class="dialogue-speaker-label">ГРАММИНИ</span>
                    <button class="tts-play-btn" onclick="playDialogueText(this)" title="Прослушать">🔊</button>
                </div>
                <div class="dialogue-content">
                    <div class="enrichment-loader">
                        <div class="preloader-spinner"></div>
                        <span>Сборка блока от Текстового ИИ...</span>
                    </div>
                </div>
            `;

                if (appendTarget) {
                    appendTarget.after(dummyBlock);
                } else {
                    chatContainer.appendChild(dummyBlock);
                }
                appendTarget = dummyBlock;

                blocksToEnrich.push({
                    id: blockId,
                    num: blockNum.toString(),
                    germanText: '',
                    translation: '',
                    element: dummyBlock
                });
            }

            chatContainer.scrollTo({
                top: chatContainer.scrollHeight,
                behavior: 'smooth'
            });
        }
    }

    if (blocksToEnrich.length === 0) return;

    isEnriching = true;
    console.log(`[Enrichment] Batching ${blocksToEnrich.length} blocks into 1 API call`);
    SessionLogger.log('ENRICH', `Batching ${blocksToEnrich.length} blocks`);

    // Show loaders on ALL blocks
    const loaders = new Map<string, HTMLElement>();

    blocksToEnrich.forEach(b => {
        enrichedBlockIds.add(b.id); // Mark as in-progress
        // Only add loader for blocks that don't already have one (dummy blocks have built-in loaders)
        const existingLoader = b.element.querySelector('.enrichment-loader');
        if (!existingLoader) {
            const loader = document.createElement('div');
            loader.className = 'enrichment-loader';
            loader.setAttribute('data-enrich-id', b.id);
            loader.innerHTML = `<div class="preloader-spinner"></div> <span>Генерирую подсказки для блока ${b.num}...</span>`;
            b.element.appendChild(loader);
            loaders.set(b.id, loader);
        } else {
            // Re-use existing loader
            loaders.set(b.id, existingLoader as HTMLElement);
        }
    });

    // Get API key from all available keys (main + extras)
    const apiKeyInput = document.getElementById('api-key') as HTMLInputElement;
    const baseApiKey = apiKeyInput?.value?.trim() || localStorage.getItem('gemini_api_key') || '';
    const allKeys = (window as any).getAllIllustrationKeys ? (window as any).getAllIllustrationKeys() : baseApiKey;

    if (!baseApiKey && !allKeys) {
        console.warn('[Enrichment] No API key available');
        loaders.forEach(l => l.remove());
        isEnriching = false;
        return;
    }

    // The user explicitly requested grouping ALL dialogues into exactly 1 single request.
    const BATCH_SIZE = blocksToEnrich.length > 0 ? blocksToEnrich.length : 1;
    const chunks: typeof blocksToEnrich[] = [];
    for (let i = 0; i < blocksToEnrich.length; i += BATCH_SIZE) {
        chunks.push(blocksToEnrich.slice(i, i + BATCH_SIZE));
    }

    console.log(`[Enrichment] Processing ${blocksToEnrich.length} blocks in ${chunks.length} batches of max ${BATCH_SIZE}`);
    SessionLogger.log('ENRICH', `Starting ${chunks.length} batches`);

    for (let c = 0; c < chunks.length; c++) {
        const chunk = chunks[c];
        console.log(`[Enrichment] Fetching batch ${c + 1}/${chunks.length} (blocks ${chunk.map(b => b.num).join(', ')})`);

        const prompt = buildBatchPrompt(chunk);

        // Extract recent conversation history to provide context to the Text Bot
        const state = getState();
        const recentContext = state?.conversationHistory ? state.conversationHistory.slice(-5).map(m => ({
            role: m.role || 'user', // The backend expects 'role', not 'type'
            text: m.parts?.[0]?.text || m.text || ''
        })) : [];

        const requestPayload = {
            api_key: allKeys,
            message: prompt,
            context: recentContext,
            custom_instructions: ENRICHMENT_SYSTEM_PROMPT,
            response_format: 'json'
        };

        console.log(`[Enrichment] 🔑 Sending batch request with API Key length: ${allKeys.length}, starts with: ${allKeys.substring(0, 5)}...`);

        try {
            const response = await fetch('/api/chat', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(requestPayload),
            });

            if (!response.ok) {
                const errText = await response.text().catch(() => '');
                console.error(`[Enrichment] API error in batch ${c + 1}: ${response.status}`, errText);
                chunk.forEach(b => {
                    const l = loaders.get(b.id);
                    if (l) {
                        l.innerHTML = `
                            <div style="background:#422; border:1px solid #f66; padding:10px; border-radius:8px; margin-top:5px; margin-bottom: 20px;">
                                <span style="color:#f66;font-size:12px; font-weight:bold;">❌ Ошибка API: ${response.status}</span>
                                <pre style="color:#ddd; font-size:10px; white-space:pre-wrap; max-height:150px; overflow-y:auto;">${escapeHtml(errText)}</pre>
                            </div>
                        `;
                    }
                    // CRITICAL FIX: Mark as enriched even on failure to prevent infinite 5-second retries
                    enrichedBlockIds.add(b.id);
                });
                continue; // Try next batch
            }

            const data = await response.json();
            const text = data.text || '';

            if (text) {
                console.log(`[Enrichment] Got response for batch ${c + 1} (${text.length} chars), parsing...`);
                // Parse response and distribute ONLY to the blocks in this chunk
                distributeEnrichment(text, chunk, loaders);
            } else {
                chunk.forEach(b => {
                    const l = loaders.get(b.id);
                    if (l) {
                        l.innerHTML = `<span style="color:#f66;font-size:12px;">❌ Пустой ответ от ИИ</span>`;
                        // Do NOT remove the loader, let it stay so the block stays marked visually
                    }
                });
            }

            // Introduce a 5-second delay between batches to prevent 429 Burst Rate Limiting
            if (c < chunks.length - 1) {
                console.log(`[Enrichment] Pacing batches. Waiting 5 seconds before next request...`);
                await new Promise(resolve => setTimeout(resolve, 5000));
            }
        } catch (err) {
            console.error(`[Enrichment] Error in batch ${c + 1}:`, err);
            chunk.forEach(b => {
                const l = loaders.get(b.id);
                if (l) {
                    const msg = err instanceof Error ? err.message : 'Сетевая ошибка';
                    l.innerHTML = `<span style="color:#f66;font-size:12px;">❌ Ошибка: ${msg}</span>`;
                }
            });
        }
    }

    isEnriching = false;
}

/**
 * Build ONE prompt that requests <hint>+<answer> for ALL blocks at once.
 */
function buildBatchPrompt(blocks: Array<{ num: string; germanText: string; translation: string }>): string {
    const nativeLang = getNativeLangName();
    let prompt = `Analyze ${blocks.length} C2 German dialogue replicas. Output a JSON array with ${blocks.length} objects.\n\n`;

    prompt += `Each object structure:\n`;
    prompt += `{\n`;
    prompt += `  "blockNum": "N",\n`;
    prompt += `  "fixedGerman": "MANDATORY: ALWAYS ONLY pure German text! The complete German C2 sentence. For [MISSING BLOCK]: generate a NEW 30+ word C2 German sentence continuing the conversation topic. NO TRANSLATION HERE.",\n`;
    prompt += `  "fixedTranslation": "MANDATORY: Pure ${nativeLang} translation of the German sentence.",\n`;
    prompt += `  "hint": "📜 ГРАММАТИКА / GRAMMAR\\n▸ SATZPERIODE: [syntactic analysis]\\n▸ STILISTIK: [register + devices]\\n▸ RHETORIK: [rhetorical figures]\\n▸ KONTEXT: [discourse function]\\n▸ WORTWAHL: [3-5 C2 vocab items with German explanations]",\n`;
    prompt += `  "answer": "+ [C2 German 15+ words] (${nativeLang} translation)\\n- [C2 German 15+ words] (${nativeLang} translation)\\n~ [C2 German 15+ words] (${nativeLang} translation)\\n🎓 [C2 German 15+ words] (${nativeLang} translation)\\n🏆 [C2 German 15+ words] (${nativeLang} translation)"\n`;
    prompt += `}\n\n`;

    prompt += `CRITICAL RULES:\n`;
    prompt += `- Raw JSON ONLY. No markdown, no \`\`\`json.\n`;
    prompt += `- EXACTLY ${blocks.length} objects in the array.\n`;
    prompt += `- fixedGerman MUST NEVER be empty! ONLY GERMAN TEXT. NO ${nativeLang.toUpperCase()} TEXT INSIDE fixedGerman.\n`;
    prompt += `- fixedTranslation MUST NEVER be empty! PUT THE ${nativeLang.toUpperCase()} TRANSLATION HERE.\n`;
    prompt += `- ALL 5 hint sections required (SATZPERIODE, STILISTIK, RHETORIK, KONTEXT, WORTWAHL).\n`;
    prompt += `- Each answer option: 15+ words C2 German + (${nativeLang} translation in parentheses).\n`;
    prompt += `- 🚫 NO meta-talk ("Диалог завершён!", "Как вам?").\n\n`;

    blocks.forEach((b, i) => {
        prompt += `--- BLOCK ${i + 1} (num: ${b.num}) ---\n`;
        if (b.germanText) {
            prompt += `DE: "${b.germanText}"\n`;
            if (b.translation) {
                prompt += `${nativeLang}: ${b.translation}\n`;
            }
        } else {
            prompt += `[MISSING BLOCK — generate new C2 German sentence FOR "fixedGerman" AND ${nativeLang} translation FOR "fixedTranslation" continuing conversation topic]\n`;
        }
        prompt += '\n';
    });

    return prompt;
}

/**
 * Parse batched response and distribute <hint>/<answer> to each block's DOM.
 */
function distributeEnrichment(
    text: string,
    blocks: Array<{ id: string; num: string; element: HTMLElement }>,
    loaders: Map<string, HTMLElement>
): void {
    let parsedBlocks: any[] = [];
    try {
        let cleanText = text.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
        const arrayStart = cleanText.indexOf('[');
        const objectStart = cleanText.indexOf('{');
        
        // Determine if we have an array or single object
        const hasArray = arrayStart !== -1 && (objectStart === -1 || arrayStart < objectStart);
        
        if (hasArray) {
            cleanText = cleanText.substring(arrayStart);
            // Robust parsing: Find the correct closing bracket even if there's trailing garbage
            let possibleEnds: number[] = [];
            for (let i = 0; i < cleanText.length; i++) {
                if (cleanText[i] === ']') possibleEnds.push(i);
            }

            let success = false;
            // Iterate backwards through all possible array closures
            for (let i = possibleEnds.length - 1; i >= 0; i--) {
                try {
                    const testJson = cleanText.substring(0, possibleEnds[i] + 1);
                    parsedBlocks = JSON.parse(testJson);
                    success = true;
                    break;
                } catch (e) {
                    // Ignore error and try the next shorter matching bracket closure
                }
            }

            if (!success) {
                // JSON was truncated by API — try to repair by finding last complete object
                console.warn('[Enrichment] JSON truncated, attempting repair...');
                const lastCloseBrace = cleanText.lastIndexOf('}');
                if (lastCloseBrace > 0) {
                    try {
                        const repaired = cleanText.substring(0, lastCloseBrace + 1) + ']';
                        parsedBlocks = JSON.parse(repaired);
                        success = true;
                        console.log(`[Enrichment] ✅ JSON repaired successfully (${parsedBlocks.length} blocks recovered)`);
                    } catch (e2) {
                        // Still broken — nothing we can do
                    }
                }
                if (!success) {
                    throw new Error("Could not extract valid JSON array (truncated)");
                }
            }
        } else if (objectStart !== -1) {
            // No array bracket — AI returned a single object or text-wrapped object
            cleanText = cleanText.substring(objectStart);
            
            // Try to find the matching closing brace for a single object
            let possibleEnds: number[] = [];
            for (let i = 0; i < cleanText.length; i++) {
                if (cleanText[i] === '}') possibleEnds.push(i);
            }
            
            let success = false;
            for (let i = possibleEnds.length - 1; i >= 0; i--) {
                try {
                    const testJson = cleanText.substring(0, possibleEnds[i] + 1);
                    const parsed = JSON.parse(testJson);
                    parsedBlocks = Array.isArray(parsed) ? parsed : [parsed];
                    success = true;
                    console.log(`[Enrichment] ✅ Parsed single JSON object (no array brackets)`);
                    break;
                } catch (e) {
                    // Try next
                }
            }
            
            if (!success) {
                throw new Error("Could not extract valid JSON object");
            }
        } else {
            parsedBlocks = JSON.parse(cleanText);
        }

        if (!Array.isArray(parsedBlocks)) {
            parsedBlocks = [parsedBlocks];
        }
    } catch (e) {
        console.error('[Enrichment] Failed to parse JSON response.');
        console.error('[Enrichment] RAW AI RESPONSE:', text);
        loaders.forEach(l => {
            const rawDump = escapeHtml(text);
            l.innerHTML = `
                <div style="background:#311; border:1px solid #f44; padding:10px; border-radius:8px; margin-top:5px; margin-bottom: 20px;">
                    <div style="color:#f66;font-size:12px; font-weight:bold; margin-bottom:5px;">❌ Ошибка: ИИ вернул не JSON. Сырой ответ:</div>
                    <textarea readonly style="width:100%; height:100px; background:#111; color:#0f0; font-family:monospace; font-size:10px; border:1px solid #333; padding:5px; border-radius:4px;">${rawDump}</textarea>
                </div>
            `;
        });
        return;
    }

    console.log(`[Enrichment] Parsed ${parsedBlocks.length} JSON objects for ${blocks.length} blocks`);

    // Load current history text ONCE to perform precise in-place string injection
    let currentHistoryText = '';
    const state = getState();
    if (state && state.conversationHistory) {
        for (let i = state.conversationHistory.length - 1; i >= 0; i--) {
            if (state.conversationHistory[i].role === 'model') {
                const msg = state.conversationHistory[i];
                currentHistoryText = msg.parts?.[0]?.text || msg.text || '';
                break;
            }
        }
    }

    blocks.forEach((block, i) => {
        const bd = parsedBlocks[i] || parsedBlocks.find(p => p.blockNum == block.num) || null;
        const loader = loaders.get(block.id);

        if (!bd) {
            if (loader) {
                loader.innerHTML = `<span style="color:#f90;font-size:12px;">⚠️ Пропущен блок ${block.num} (ИИ не вернул данные)</span>`;
            }
            return;
        }

        // === DEBUG: Log all field names the API returned for this block ===
        const bdKeys = Object.keys(bd);
        console.log(`[Enrichment] Block ${block.num} API keys: [${bdKeys.join(', ')}]`);

        // Extract German text — try EVERY possible field name the AI might use
        const rawGerman = (
            bd.fixedGerman || bd.fixed_german || bd.german || bd.germanText || bd.german_text ||
            bd.text || bd.DE || bd.de || bd.sentence || bd.germanSentence || bd.content || ''
        ).toString().trim();
        const fixedGerman = rawGerman.length > 5 ? rawGerman : null;

        // Extract translation — try multiple field names
        const rawTrans = (
            bd.fixedTranslation || bd.fixed_translation || bd.translation || bd.russianTranslation ||
            bd.russian || bd.RU || bd.ru || bd.trans || ''
        ).toString().trim();
        const fixedTrans = rawTrans.length > 3 ? rawTrans : null;

        console.log(`[Enrichment] Block ${block.num}: german=${fixedGerman ? fixedGerman.substring(0, 60) + '...' : 'NULL'}, trans=${fixedTrans ? fixedTrans.substring(0, 40) + '...' : 'NULL'}`);

        // === RENDER GERMAN TEXT + TRANSLATION INTO DIALOGUE-CONTENT ===
        const dialogueContent = block.element.querySelector('.dialogue-content') as HTMLElement;
        const isDummyBlock = dialogueContent && !dialogueContent.querySelector('.dialogue-text, span:not(.enrichment-loader span)');

        if (dialogueContent && (fixedGerman || fixedTrans)) {
            console.log(`[Enrichment] 🔧 Rendering text for Block ${block.num}`);
            const Vocabulary = (window as any).Vocabulary;

            // Clear dialogue-content completely (remove loader + any old content)
            dialogueContent.innerHTML = '';

            // 1. German text
            if (fixedGerman) {
                const germanHtml = Vocabulary?.formatMessage ? Vocabulary.formatMessage(fixedGerman) : escapeHtml(fixedGerman);
                const textWrapper = document.createElement('div');
                textWrapper.className = 'dialogue-text';
                textWrapper.innerHTML = germanHtml;
                // Add TTS button
                const ttsBtn = document.createElement('button');
                ttsBtn.className = 'tts-inline-btn german-tts-btn';
                ttsBtn.title = 'Прослушать';
                ttsBtn.textContent = '🔊';
                ttsBtn.setAttribute('onclick', 'playDialogueText(this)');
                textWrapper.appendChild(ttsBtn);
                dialogueContent.appendChild(textWrapper);
            }

            // 2. Translation
            if (fixedTrans) {
                const transDiv = document.createElement('div');
                transDiv.className = 'translation-block translation selected-theme';
                let escapedTrans = escapeHtml(fixedTrans);
                let formattedTrans = escapedTrans.replace(/([.!?])\s{1,3}([A-ZÄÖÜА-ЯЁ])/g, '$1<br>$2');
                
                transDiv.innerHTML = `<div class="translation-text-section" style="display: flex; flex-direction: row; align-items: flex-start; gap: 6px; margin-top: 4px; padding-top: 4px; border-top: 1px dashed rgba(255,255,255,0.1);">
                    <span class="translation-icon" style="flex-shrink: 0;">${getNativeLangFlag()}</span>
                    <span class="translation-text" style="flex-grow: 1;">${formattedTrans}</span>
                    <button class="tts-inline-btn translation-tts-btn" style="flex-shrink: 0;" onclick="playTranslationText(this)" title="Прослушать">🔊</button>
                </div>`;
                dialogueContent.appendChild(transDiv);
            }
        } else if (dialogueContent && isDummyBlock && !fixedGerman) {
            // Dummy block with no German text from API — show error with raw data
            console.warn(`[Enrichment] ⚠️ Block ${block.num}: No German text found in API response! Keys: [${bdKeys.join(', ')}]`);
            dialogueContent.innerHTML = `<div style="color: #f90; padding: 10px; font-size: 12px;">
                ⚠️ Текстовый ИИ не вернул немецкий текст для блока ${block.num}.
                <br>Поля: [${bdKeys.join(', ')}]
            </div>`;
        }

        // Build the precise history injection string
        let injectionStr = '';
        if (fixedGerman) {
            injectionStr += `[REPLICA ${block.num}]:\n${fixedGerman} ${fixedTrans ? `(${fixedTrans})` : ''}\n`;
        }

        const hintStr = bd.hint || '';
        const answerStr = bd.answer || '';

        // Reconstruct XML so parseBlockSection doesn't need to be fully rewritten
        const cleanSection = `<hint>\n${hintStr}\n</hint>\n<answer>\n${answerStr}\n</answer>`;
        injectionStr += cleanSection.trim() + '\n';

        // Helper to inject into a buffer (either history or live stream)
        const injectIntoBuffer = (buffer: string): string => {
            if (!buffer) return buffer;
            
            const currentBlockRegex = new RegExp(`(?:^|\\n|\\.\\s+)(?:\\[?REPLICA\\s+)?${block.num}(?:\\]?|\\.)\\s*:?`, 'i');
            const nextBlockNum = parseInt(block.num) + 1;
            const nextBlockRegex = new RegExp(`(?:^|\\n|\\.\\s+)(?:\\[?REPLICA\\s+)?${nextBlockNum}(?:\\]?|\\.)\\s*:?`, 'i');
            
            const currentMatch = buffer.match(currentBlockRegex);
            const nextMatch = buffer.match(nextBlockRegex);

            // If we are replacing the text (fixedGerman), we MUST remove the old text first to prevent duplicates!
            if (fixedGerman && currentMatch) {
                const startIdx = currentMatch.index!;
                const endIdx = nextMatch ? nextMatch.index! : buffer.length;
                return buffer.slice(0, startIdx) + '\n' + injectionStr + buffer.slice(endIdx);
            } 
            else if (!buffer.includes(cleanSection.trim())) {
                if (nextMatch) {
                    return buffer.slice(0, nextMatch.index) + '\n' + injectionStr + buffer.slice(nextMatch.index);
                } else {
                    return buffer + '\n' + injectionStr;
                }
            }
            return buffer;
        };

        // 1. Precise atomic injection into globally finalized currentHistoryText
        currentHistoryText = injectIntoBuffer(currentHistoryText);

        // 2. LIVE STREAM INJECTION into StreamingDisplay
        const streamingDisplay = (window as any).StreamingDisplay;
        if (streamingDisplay && streamingDisplay.aiAccumulatedText !== undefined) {
            streamingDisplay.aiAccumulatedText = injectIntoBuffer(streamingDisplay.aiAccumulatedText);
        }

        // 3. Render hint/answer HTML
        const html = parseBlockSection(cleanSection);
        if (loader && loader.parentNode) {
            loader.outerHTML = html;
        } else {
            // If the loader was wiped out by innerHTML rebuilding, safely append it instead
            block.element.insertAdjacentHTML('beforeend', html);
        }
        // Clean up ANY remaining loaders in this block
        block.element.querySelectorAll('.enrichment-loader').forEach(el => el.remove());
        // Mark the newly inserted hint-container as enriched by Text Bot
        const newHint = block.element.querySelector('.hint-container:not([data-enriched])');
        if (newHint) {
            newHint.setAttribute('data-enriched', 'true');
            // MOVE hint-container from inside .dialogue-content to .dialogue-block (direct child)
            block.element.appendChild(newHint);
        }
        console.log(`[Enrichment] ✅ Block ${block.num} enriched`);
    });

    // Inject inline TTS buttons into ALL dialogue blocks (both Voice AI and Text Bot)
    injectInlineTtsButtons();

    // Save ALL enriched blocks generated by the Text Bot into context history
    // so they are accurately remembered if the user reloads the page.
    if (currentHistoryText) {
        updateLastModelHistoryText(currentHistoryText);
        const chatId = getCurrentChatId();
        if (chatId) {
            updateLastAiMessageText(chatId, currentHistoryText);
        }
    }
}

/**
 * Inject a visible TTS bar between dialogue text and ГРАММАТИКА panel.
 * Creates a .tts-bar with labeled buttons for German and Translation playback.
 * Safe to call multiple times — uses data-tts-injected to prevent duplicates.
 */
export function injectInlineTtsButtons(): void {
    const chatContainer = document.getElementById('chat-container');
    if (!chatContainer) return;

    chatContainer.querySelectorAll('.dialogue-block').forEach(block => {
        if (block.getAttribute('data-tts-injected')) return;

        const dialogueContent = block.querySelector('.dialogue-content');
        if (!dialogueContent) return;

        // Create TTS bar with labeled buttons
        const ttsBar = document.createElement('div');
        ttsBar.className = 'tts-bar';
        ttsBar.innerHTML = `
            <button class="tts-bar-btn" onclick="speakDialogueGerman(this)" title="Озвучить немецкий текст">
                🔊 <span>Немецкий</span>
            </button>
            <button class="tts-bar-btn" onclick="speakDialogueTranslation(this)" title="Озвучить перевод">
                🔊 <span>Перевод</span>
            </button>
        `;

        // Insert BEFORE the first structural element (hint-container, enrichment-loader, ГРАММАТИКА)
        const firstStructural = dialogueContent.querySelector('.hint-container, .enrichment-loader');
        if (firstStructural) {
            dialogueContent.insertBefore(ttsBar, firstStructural);
        } else {
            dialogueContent.appendChild(ttsBar);
        }

        block.setAttribute('data-tts-injected', 'true');
    });
}

/**
 * Parse a single block section into <hint>+<answer> HTML.
 */
function parseBlockSection(section: string): string {
    // Extract ONLY the hint and answer tags. Ignore any conversational garbage from the Observer Bot.
    const hintMatch = section.match(/<hint>([\s\S]*?)<\/hint>/i);
    const answerMatch = section.match(/<answer>([\s\S]*?)<\/answer>/i);

    // If no hint or answer tags are found, treat the whole section as plain grammar text
    if (!hintMatch && !answerMatch) {
        return `<div class="hint-container expanded" style="margin-top:8px;">
            <div class="hint-panel hint-text" style="display:block;">
                <div class="hint-header">📜 GRAMMAR</div>
                <div>${escapeHtml(section.trim()).replace(/\n/g, '<br>')}</div>
            </div>
        </div>`;
    }

    const Vocabulary = (window as any).Vocabulary;

    // If the Vocabulary module is fully loaded, use its robust parser to guarantee styling parity
    if (Vocabulary && typeof Vocabulary.buildHintAnswerHtml === 'function') {
        const hintContent = hintMatch ? hintMatch[1].trim() : '';
        const answerContent = answerMatch ? answerMatch[1].trim() : '';
        return Vocabulary.buildHintAnswerHtml(hintContent, answerContent);
    }

    // --- FALLBACK PARSER (in case Vocabulary module isn't mounted yet) ---
    // This rarely happens since Vocabulary is loaded first, but we keep a basic fallback just in case
    const hintId = 'hint_e_' + Date.now() + '_' + Math.random().toString(36).substr(2, 4);

    // Parse HINT
    let hintHtml = '';
    if (hintMatch) {
        const hintContent = hintMatch[1].trim();
        const parts = hintContent.split('▸').map(p => p.trim()).filter(p => p.length > 0);
        if (parts.length > 1) {
            const title = parts[0];
            const items = parts.slice(1).map(item =>
                `<div class="hint-item"><span class="hint-bullet">▸</span> ${escapeHtml(item)}</div>`
            ).join('');
            hintHtml = `<div class="hint-header">${escapeHtml(title)}</div><div class="hint-list">${items}</div>`;
        } else {
            hintHtml = escapeHtml(hintContent);
        }
    }

    // Parse ANSWER (Basic fallback - doesn't split translations well, rely on Vocabulary parser!)
    let answerHtml = '';
    if (answerMatch) {
        const answerContent = answerMatch[1].trim();
        const lines = answerContent.split('\n').map(l => l.trim()).filter(l => l.length > 0);
        const answerItems = lines.map(line => {
            let cls = 'answer-item-neutral';
            if (line.startsWith('+')) { cls = 'answer-item-positive'; line = line.substring(1).trim(); }
            else if (line.startsWith('-')) { cls = 'answer-item-negative'; line = line.substring(1).trim(); }
            else if (line.startsWith('~')) { cls = 'answer-item-variant'; line = line.substring(1).trim(); }
            else if (line.startsWith('🎓')) { cls = 'answer-item-expert'; line = line.substring(2).trim(); }
            else if (line.startsWith('🏆')) { cls = 'answer-item-champion'; line = line.substring(2).trim(); }

            return `
                <div class="answer-item ${cls}">
                    <div class="answer-content">
                        <span class="answer-german">${escapeHtml(line.trim())}</span>
                    </div>
                </div>
            `;
        }).join('');

        answerHtml = `
            <div class="answer-list">${answerItems}</div>
        `;
    }

    return `
        <div class="hint-container expanded" id="${hintId}">
            <div class="hint-column">
                <button class="hint-btn hint-btn-hint" onclick="revealHint('${hintId}', 'hint', event)" title="Показать подсказку">ГРАММАТИКА</button>
                <div class="hint-panel hint-text hidden" data-type="hint">${hintHtml}</div>
            </div>
            <div class="hint-column">
                <button class="hint-btn hint-btn-answer hidden" onclick="revealHint('${hintId}', 'answer', event)" title="Показать ответ">ОТВЕТ</button>
                <div class="hint-panel hint-text hidden" data-type="answer">${answerHtml}</div>
            </div>
        </div>
    `.replace(/\s+/g, ' ').trim();
}

// Removed fetchWithRetry to prevent frontend spam when API quota is exhausted.

function escapeHtml(text: string): string {
    return text
        .replace(/&/g, '&amp;')
        .replace(/</g, '&lt;')
        .replace(/>/g, '&gt;')
        .replace(/"/g, '&quot;');
}



/**
 * Reset enrichment state (on session start/reset).
 */
export function resetEnrichment(): void {
    enrichedBlockIds.clear();
    isEnriching = false;
    if (enrichTimer) {
        clearTimeout(enrichTimer);
        enrichTimer = null;
    }
}

