/**
 * Settings module - User preferences and theme
 */

import { getElements } from '../core/elements';
import { getState } from '../core/state';
import { stopConversation, startConversation } from '../api/websocket-controller';

export interface UserSettings {
    apiKey: string;
    voice: string;
    speechRate: number;
    theme: string;
    level: string;
    teacherMode: string;
    nativeLanguage: string;
    systemInstruction: string;
}

const STORAGE_KEYS = {
    apiKey: 'gemini_api_key',
    voice: 'gemini_voice',
    speechRate: 'gemini_speech_rate',
    theme: 'gemini_theme',
    level: 'gemini_level',
    teacherMode: 'gemini_teacher_mode',
    nativeLanguage: 'gemini_native_language',
    systemInstruction: 'gemini_system_instruction',
} as const;

/**
 * Load settings from localStorage
 */
export function loadSettings(): UserSettings {
    const settings: UserSettings = {
        apiKey: localStorage.getItem(STORAGE_KEYS.apiKey) || '',
        voice: localStorage.getItem(STORAGE_KEYS.voice) || 'Puck',
        speechRate: parseFloat(localStorage.getItem(STORAGE_KEYS.speechRate) || '1.0'),
        theme: localStorage.getItem(STORAGE_KEYS.theme) || 'dark',
        level: localStorage.getItem(STORAGE_KEYS.level) || 'A1',
        teacherMode: localStorage.getItem(STORAGE_KEYS.teacherMode) || 'standard',
        nativeLanguage: localStorage.getItem(STORAGE_KEYS.nativeLanguage) || 'Russian',
        systemInstruction: localStorage.getItem(STORAGE_KEYS.systemInstruction) || '',
    };

    // Apply to UI
    applySettingsToUI(settings);
    applyTheme(settings.theme);

    return settings;
}

/**
 * Save settings to localStorage
 */
export function saveSettings(): void {
    const elements = getElements();

    const apiKeyInput = document.getElementById('api-key') as HTMLInputElement;
    if (apiKeyInput) {
        localStorage.setItem(STORAGE_KEYS.apiKey, apiKeyInput.value.trim());
    }

    if (elements.voiceSelect?.value) {
        localStorage.setItem(STORAGE_KEYS.voice, elements.voiceSelect.value);
    }

    if (elements.languageLevel?.value) {
        localStorage.setItem(STORAGE_KEYS.level, elements.languageLevel.value);
    }

    // Save teacher mode from radio buttons
    const teacherModeRadio = document.querySelector('input[name="teacher-mode"]:checked') as HTMLInputElement;
    if (teacherModeRadio) {
        localStorage.setItem(STORAGE_KEYS.teacherMode, teacherModeRadio.value);
    }

    // Save native language
    const nativeLangSelect = document.getElementById('native-language') as HTMLSelectElement;
    if (nativeLangSelect?.value) {
        localStorage.setItem(STORAGE_KEYS.nativeLanguage, nativeLangSelect.value);
    }

    // Save speech rate
    const speechRateInput = document.getElementById('speech-rate') as HTMLInputElement;
    if (speechRateInput) {
        localStorage.setItem(STORAGE_KEYS.speechRate, speechRateInput.value);
    }

    // Save extra illustration keys
    saveExtraKeys();

    console.log('[Settings] Saved');
}

/**
 * Apply theme with smooth transition
 */
export function applyTheme(theme: string): void {
    // Enable smooth transitions during theme switch
    document.body.classList.add('theme-transitioning');

    document.body.dataset.theme = theme;
    document.documentElement.className = theme;
    localStorage.setItem(STORAGE_KEYS.theme, theme);

    // Restore background toggle state
    const bgEnabled = localStorage.getItem('gemini_theme_bg') !== 'false';
    if (bgEnabled) {
        document.body.classList.add('themed-bg');
        // Apply theme particle effects
        import('./theme-effects').then(fx => fx.applyThemeEffects(theme));
    } else {
        document.body.classList.remove('themed-bg');
        import('./theme-effects').then(fx => fx.clearThemeEffects());
    }

    // Remove transition class after animation completes
    setTimeout(() => {
        document.body.classList.remove('theme-transitioning');
    }, 600);
}

/**
 * Setup background toggle checkbox
 */
export function setupBgToggle(): void {
    const toggle = document.getElementById('theme-bg-toggle') as HTMLInputElement;
    if (!toggle) return;

    // Restore state
    const saved = localStorage.getItem('gemini_theme_bg') !== 'false';
    toggle.checked = saved;
    if (saved) {
        document.body.classList.add('themed-bg');
        const theme = document.body.dataset.theme || 'dark';
        import('./theme-effects').then(fx => fx.applyThemeEffects(theme));
    }

    toggle.addEventListener('change', () => {
        localStorage.setItem('gemini_theme_bg', String(toggle.checked));
        if (toggle.checked) {
            document.body.classList.add('themed-bg');
            const theme = document.body.dataset.theme || 'dark';
            import('./theme-effects').then(fx => fx.applyThemeEffects(theme));
        } else {
            document.body.classList.remove('themed-bg');
            import('./theme-effects').then(fx => fx.clearThemeEffects());
        }
    });
}

/**
 * Apply settings to UI elements
 */
function applySettingsToUI(settings: UserSettings): void {
    const elements = getElements();

    const apiKeyInput = document.getElementById('api-key') as HTMLInputElement;
    if (apiKeyInput && settings.apiKey) {
        apiKeyInput.value = settings.apiKey;
    }

    // Render extra illustration keys
    renderExtraKeys();

    if (elements.voiceSelect && settings.voice) {
        elements.voiceSelect.value = settings.voice;
    }

    if (elements.themeSelect && settings.theme) {
        elements.themeSelect.value = settings.theme;
    }

    if (elements.languageLevel && settings.level) {
        elements.languageLevel.value = settings.level;
    }

    // Apply native language
    const nativeLangSelect = document.getElementById('native-language') as HTMLSelectElement;
    if (nativeLangSelect && settings.nativeLanguage) {
        nativeLangSelect.value = settings.nativeLanguage;
    }

    // Apply teacher mode to radio buttons
    const teacherModeRadio = document.querySelector(`input[name="teacher-mode"][value="${settings.teacherMode}"]`) as HTMLInputElement;
    if (teacherModeRadio) {
        teacherModeRadio.checked = true;
    }
    // Show/hide A1S block based on active mode
    updateA1SBlock(settings.teacherMode === 'active');
    updateProgressVisibility(settings.teacherMode === 'standard');

    // Apply speech rate (to slider AND input) - format with 2 decimals
    const speechRateSlider = document.getElementById('speech-rate') as HTMLInputElement;
    const speechRateInput = document.getElementById('speech-rate-input') as HTMLInputElement;
    const rate = settings.speechRate || 1.0;
    if (speechRateSlider) {
        speechRateSlider.value = rate.toFixed(2);
    }
    if (speechRateInput) {
        speechRateInput.value = rate.toFixed(2);
    }
    // Apply to AudioPlayback
    const AudioPlayback = (window as unknown as { AudioPlayback?: { setPlaybackRate?: (rate: number) => void } }).AudioPlayback;
    if (AudioPlayback?.setPlaybackRate) {
        AudioPlayback.setPlaybackRate(rate);
    }
}


