let activeSteps: TutorialStep[] = TUTORIAL_STEPS;
let currentStep = 0;
let overlay: HTMLElement | null = null;

function clearOverlayContent(): void {
    if (!overlay) return;
    overlay.innerHTML = '';
}

function showStep(stepIndex: number): void {
    if (!overlay) return;
    if (stepIndex >= activeSteps.length) {
        closeTutorial();
        return;
    }

    currentStep = stepIndex;
    const step = activeSteps[stepIndex];
    const target = document.querySelector(step.target) as HTMLElement;

    // On mobile, if the target is inside the right sidebar, open it first
    const isMobile = window.innerWidth <= 600;
    if (isMobile && target) {
        const inRightSidebar = target.closest('.sidebar-right');
        const inLeftSidebar = target.closest('.sidebar-left');
        if (inRightSidebar && (window as any).openMobileSidebar) {
            const sidebar = document.getElementById('sidebar-right');
            if (sidebar && !sidebar.classList.contains('mobile-open')) {
                (window as any).openMobileSidebar('right');
            }
        } else if (inLeftSidebar && (window as any).openMobileSidebar) {
            const sidebar = document.getElementById('sidebar-left');
            if (sidebar && !sidebar.classList.contains('mobile-open')) {
                (window as any).openMobileSidebar('left');
            }
        }
    }

    // Small delay to let sidebar animation finish before measuring positions
    const delay = isMobile && target?.closest('.sidebar-left, .sidebar-right') ? 350 : 0;

    setTimeout(() => {
        if (!overlay) return;
        clearOverlayContent();

        // Spotlight
        const spotlight = document.createElement('div');
        spotlight.className = 'tutorial-spotlight';

        if (target && step.position !== 'center') {
            const rect = target.getBoundingClientRect();
            const pad = 8;
            spotlight.style.left = `${rect.left - pad}px`;
            spotlight.style.top = `${rect.top - pad}px`;
            spotlight.style.width = `${rect.width + pad * 2}px`;
            spotlight.style.height = `${rect.height + pad * 2}px`;
            target.scrollIntoView({ behavior: 'smooth', block: 'nearest' });
        } else {
            spotlight.style.display = 'none';
        }
        overlay.appendChild(spotlight);

        // Tooltip card
        const isLast = stepIndex === activeSteps.length - 1;
        const tooltip = document.createElement('div');
        tooltip.className = 'tutorial-tooltip';
        tooltip.innerHTML = `
            <div class="tutorial-step-counter">${stepIndex + 1} / ${activeSteps.length}</div>
            <h3 class="tutorial-title">${step.title}</h3>
            <p class="tutorial-text">${step.text.replace(/\n/g, '<br>')}</p>
            <div class="tutorial-buttons">
                <button class="tutorial-btn tutorial-skip">Пропустити</button>
                <button class="tutorial-btn tutorial-next">${isLast ? '✅ Готово' : 'Далі →'}</button>
            </div>
        `;

        overlay.appendChild(tooltip);

        // Position tooltip — clamped to viewport
        const pos = step.position || 'bottom';
        if (target && pos !== 'center') {
            const rect = target.getBoundingClientRect();
            requestAnimationFrame(() => {
                const tRect = tooltip.getBoundingClientRect();
                const tW = tRect.width || 320;
                const tH = tRect.height || 200;
                const vw = window.innerWidth;
                const vh = window.innerHeight;
                let left = 0;
                let top = 0;

                if (isMobile) {
                    // On mobile, always center horizontally and place below target
                    left = Math.max(10, Math.min(vw - tW - 10, (vw - tW) / 2));
                    top = Math.min(vh - tH - 10, rect.bottom + 15);
                    if (top < 10) top = 10;
                } else {
                    switch (pos) {
                        case 'left': {
                            left = rect.left - tW - 20;
                            if (left < 10) left = rect.right + 20;
                            top = Math.max(10, rect.top);
                            break;
                        }
                        case 'right': {
                            left = rect.right + 20;
                            if (left + tW > vw) left = rect.left - tW - 20;
                            top = Math.max(10, rect.top);
                            break;
                        }
                        case 'top':
                            left = Math.max(10, rect.left);
                            top = rect.top - tH - 15;
                            break;
                        case 'bottom':
                        default:
                            left = Math.max(10, rect.left);
                            top = rect.bottom + 15;
                            break;
                    }
                }

                // Clamp so tooltip never goes off-screen
                left = Math.max(10, Math.min(left, vw - tW - 10));
                top = Math.max(10, Math.min(top, vh - tH - 10));

                tooltip.style.left = `${left}px`;
                tooltip.style.top = `${top}px`;
            });
        } else {
            tooltip.style.left = '50%';
            tooltip.style.top = '50%';
            tooltip.style.transform = 'translate(-50%, -50%)';
        }

        // Bind buttons
        tooltip.querySelector('.tutorial-next')?.addEventListener('click', () => showStep(currentStep + 1));
        tooltip.querySelector('.tutorial-skip')?.addEventListener('click', closeTutorial);
    }, delay);
}

function closeTutorial(): void {
    if (overlay) {
        overlay.remove();
        overlay = null;
    }
    document.body.classList.remove('tutorial-active');
    localStorage.setItem('tutorial_completed', 'true');
}

export function startTutorial(customSteps: TutorialStep[] = TUTORIAL_STEPS): void {
    activeSteps = customSteps;
    currentStep = 0;
    document.getElementById('tutorial-overlay')?.remove();
    overlay = document.createElement('div');
    overlay.className = 'tutorial-overlay';
    overlay.id = 'tutorial-overlay';
    document.body.appendChild(overlay);
    document.body.classList.add('tutorial-active');
    showStep(0);
}

export function initTutorial(): void {
    const completed = localStorage.getItem('tutorial_completed');

    // Add small tutorial button next to the logo
    const logo = document.querySelector('.sidebar-right .logo') as HTMLElement;
    if (logo) {
        const btn = document.createElement('button');
        btn.className = 'tutorial-icon-btn';
        btn.innerHTML = '🎓 Туторіал';
        btn.title = 'Пройти навчальний туторіал';
        btn.addEventListener('click', (e) => {
            e.stopPropagation();
            btn.classList.remove('glow');
            startTutorial();
        });
        logo.appendChild(btn);

        // Glow after 5 seconds for first-time users
        if (!completed) {
            setTimeout(() => {
                btn.classList.add('glow');
            }, 5000);
        }
    }
}

/* ============================================================
   PERIODIC MOBILE HINTS
   Shows floating toast-style hints on mobile screens
   ============================================================ */

const MOBILE_HINTS = [
    { icon: '🔊', text: 'Выделите текст → нажмите «Озвучить»' },
    { icon: '◀', text: 'Потяните стрелку для панели чатов' },
    { icon: '▶', text: 'Потяните стрелку для настроек' },
    { icon: '📖', text: 'Нажмите 📖 — шпаргалка грамматики' },
    { icon: '🎤', text: 'Voice — голосовой урок с AI' },
    { icon: '📊', text: 'Прогресс сохраняется автоматически' },
    { icon: '🎚️', text: 'Скорость речи: настройте в ▶ панели' },
];

let hintIndex = 0;
let hintTimer: ReturnType<typeof setInterval> | null = null;

function showMobileHint(): void {
    if (localStorage.getItem('mobile_hints_dismissed') === 'true') return;
    if (window.innerWidth > 600) return;
    // Don't show if tutorial is active
    if (document.body.classList.contains('tutorial-active')) return;

    const hint = MOBILE_HINTS[hintIndex % MOBILE_HINTS.length];
    hintIndex++;

    const toast = document.createElement('div');
    toast.className = 'mobile-hint-toast';
    toast.innerHTML = `
        <span class="mobile-hint-icon">${hint.icon}</span>
        <span class="mobile-hint-text">${hint.text}</span>
        <button class="mobile-hint-close" title="Больше не показывать">✕</button>
    `;

    document.body.appendChild(toast);

    // Animate in
    requestAnimationFrame(() => {
        toast.classList.add('show');
    });

    // Close permanently
    toast.querySelector('.mobile-hint-close')?.addEventListener('click', (e) => {
        e.stopPropagation();
        toast.classList.remove('show');
        setTimeout(() => toast.remove(), 300);
        localStorage.setItem('mobile_hints_dismissed', 'true');
        if (hintTimer) clearInterval(hintTimer);
    });

    // Auto-hide after 5 seconds
    setTimeout(() => {
        toast.classList.remove('show');
        setTimeout(() => toast.remove(), 300);
    }, 5000);
}

export function initMobileHints(): void {
    if (window.innerWidth > 600) return;
    if (localStorage.getItem('mobile_hints_dismissed') === 'true') return;

    // Add styles
    const style = document.createElement('style');
    style.textContent = `
        .mobile-hint-toast {
            position: fixed;
            bottom: 80px;
            left: 50%;
            transform: translateX(-50%) translateY(20px);
            background: rgba(30, 30, 50, 0.95);
            backdrop-filter: blur(10px);
            border: 1px solid rgba(102, 126, 234, 0.3);
            border-radius: 12px;
            padding: 10px 16px;
            display: flex;
            align-items: center;
            gap: 10px;
            z-index: 9000;
            opacity: 0;
            transition: opacity 0.3s ease, transform 0.3s ease;
            box-shadow: 0 4px 20px rgba(0, 0, 0, 0.4);
            max-width: calc(100vw - 32px);
            pointer-events: auto;
        }
        .mobile-hint-toast.show {
            opacity: 1;
            transform: translateX(-50%) translateY(0);
        }
        .mobile-hint-icon {
            font-size: 20px;
            flex-shrink: 0;
        }
        .mobile-hint-text {
            color: #e0e0f0;
            font-size: 13px;
            line-height: 1.3;
            flex: 1;
        }
        .mobile-hint-close {
            background: none;
            border: none;
            color: rgba(255,255,255,0.4);
            font-size: 14px;
            cursor: pointer;
            padding: 4px;
            flex-shrink: 0;
        }
        .mobile-hint-close:active {
            color: #fff;
        }
    `;
    document.head.appendChild(style);

    // Show first hint after 30 seconds, then every 2 minutes
    setTimeout(() => {
        showMobileHint();
        hintTimer = setInterval(showMobileHint, 120_000);
    }, 30_000);
}
