/**
 * WebSocket Controller - Main communication module
 * Handles connection, message routing, and conversation control
 */

import { getElements } from '../core/elements';
import { getState, setState, setConnected, setPlaying, setWebSocket, addToHistory } from '../core/state';
import { AudioCapture } from '../media/audio-capture';
import { AudioPlayback } from '../media/audio-playback';
import { ScreenCapture } from '../media/screen-capture';
import { StreamingDisplay } from '../chat/streaming-display';
import { saveSession, setCurrentChatId, getCurrentChatId } from '../chat/chat-sessions';
import { Chat } from '../chat/chat';
import { Orchestrator } from './orchestrator';
import { SessionLogger } from '../core/session-logger';
import { handleReplicaMetadata } from '../chat/enrichment';

export type ConversationMode = 'voice' | 'screen' | 'camera';

// Auto-reconnect retry limiting
const MAX_RECONNECT_ATTEMPTS = 3;
let reconnectAttempts = 0;
let autoStartFired = false; // Ensures auto-start greeting fires ONLY ONCE per page load

/**
 * Start a conversation with the given mode
 */
export async function startConversation(mode: ConversationMode): Promise<void> {
    // Use direct API key from localStorage
    const rawKey = localStorage.getItem('gemini_api_key') || '';
    const apiKey = rawKey.split(',')[0].trim();
    const voice = localStorage.getItem('gemini_voice') || 'Puck';
    const systemInstruction = localStorage.getItem('gemini_system_instruction') || '';
    const elements = getElements();
    const state = getState();

    if (!apiKey) {
        console.log('[WebSocket] No API key provided locally, server will use environment variable fallback');
    }

    // Use existing chat if selected, otherwise create new one
    let chatId = getCurrentChatId() || state.currentChatId;
    if (!chatId) {
        chatId = crypto.randomUUID();
        setState({ currentChatId: chatId });
        setCurrentChatId(chatId);
        // Create session entry with mode as preview
        const modeLabel = mode === 'voice' ? '🎤 Голосовой чат' : mode === 'camera' ? '📷 Камера' : '🖥️ Экран';
        saveSession(chatId, modeLabel);
    }

    setStatus('Connecting...', false);
    elements.stopRow?.classList.remove('hidden');

    // Get media stream based on mode
    let videoStream: MediaStream | null = null;

    try {
        if (mode === 'voice') {
            const stream = await navigator.mediaDevices.getUserMedia({ audio: true, video: false });
            setState({ mediaStream: stream });
            addSystemMessage('🎤 Microphone active');
        } else if (mode === 'camera') {
            videoStream = await navigator.mediaDevices.getUserMedia({
                video: { facingMode: state.currentFacingMode, width: { ideal: 1280 }, height: { ideal: 720 } },
                audio: false
            });
            setupVideoPreview(videoStream);

            try {
                const audioStream = await navigator.mediaDevices.getUserMedia({ audio: true, video: false });
                setState({ mediaStream: audioStream });
                addSystemMessage('🎤 Microphone active');
            } catch {
                addSystemMessage('⚠️ No microphone - video only');
            }
            addSystemMessage('📷 Camera active');
            showVideoSection();
        } else if (mode === 'screen') {
            videoStream = await navigator.mediaDevices.getDisplayMedia({
                video: { width: { ideal: 1280 }, height: { ideal: 720 } },
                audio: false
            });
            setupVideoPreview(videoStream);

            try {
                const audioStream = await navigator.mediaDevices.getUserMedia({ audio: true, video: false });
                setState({ mediaStream: audioStream });
                addSystemMessage('🎤 Microphone active');
            } catch {
                addSystemMessage('⚠️ No microphone - screen only');
            }
            addSystemMessage('🖥️ Screen sharing active');
            showVideoSection();
        }
    } catch (e) {
        addSystemMessage(`❌ ${mode === 'voice' ? 'Microphone' : mode === 'camera' ? 'Camera' : 'Screen share'} denied`);
        setStatus('Ready', false);
        return;
    }

    // Create WebSocket connection
    const wsUrl = buildWebSocketUrl(apiKey, voice, systemInstruction);
    const ws = new WebSocket(wsUrl);
    setWebSocket(ws);

    ws.onopen = () => handleWsOpen(ws, mode, systemInstruction);
    ws.onmessage = (e) => handleWsMessage(e);
    ws.onerror = () => {
        addSystemMessage('❌ Connection error');
        stopConversation(false); // soft stop on error too to preserve partially generated text
    };
    ws.onclose = () => {
        if (getState().isConnected) {
            addSystemMessage('📡 Disconnected');

            // Soft stop if we plan to auto-reconnect, so we trigger text recovery!
            const shouldSoftStop = reconnectAttempts < MAX_RECONNECT_ATTEMPTS;
            stopConversation(!shouldSoftStop);

            // Auto-reconnect on unexpected disconnect
            if (reconnectAttempts < MAX_RECONNECT_ATTEMPTS) {
                reconnectAttempts++;
                const delay = 2000 * Math.pow(2, reconnectAttempts - 1);
                addSystemMessage(`🔄 Переподключение (попытка ${reconnectAttempts}/${MAX_RECONNECT_ATTEMPTS}) через ${delay / 1000} сек...`);
                setTimeout(() => {
                    if (!getState().isConnected) {
                        addSystemMessage('🔄 Переподключаемся...');
                        startConversation('voice');
                    }
                }, delay);
            } else {
                addSystemMessage('⚠️ Не удалось переподключиться. Нажмите Voice.');
                reconnectAttempts = 0;
            }
        }
    };
}

/**
 * Stop the current conversation
 * @param isHardStop Try if we should completely wipe the UI and state, false if we just want to halt streaming and trigger recovery.
 */
export function stopConversation(isHardStop: boolean = true): void {
    console.log(`[Stop] Stopping conversation (hardStop=${isHardStop})...`);
    const state = getState();
    const elements = getElements();

    setConnected(false);
    setStatus('Ready', false);

    // Stop all modules
    AudioCapture.stop();
    AudioPlayback.stop();
    ScreenCapture.stop();

    if (isHardStop) {
        StreamingDisplay.hardReset();
    } else {
        // Finalize any streaming text and trigger the Text AI recovery (Missing Blocks generation)
        StreamingDisplay.finalize('ai', '');
        StreamingDisplay.reset();
        StreamingDisplay.triggerEnrichment(true);
    }

    Orchestrator.stopMonitoring();

    // Close WebSocket
    if (state.ws) {
        state.ws.close();
        setWebSocket(null);
    }

    // Stop video
    if (elements.videoPreview?.srcObject) {
        (elements.videoPreview.srcObject as MediaStream).getTracks().forEach(t => t.stop());
        elements.videoPreview.srcObject = null;
    }

    // Stop audio
    if (state.mediaStream) {
        state.mediaStream.getTracks().forEach(t => t.stop());
        setState({ mediaStream: null });
    }

    // Clear keepalive
    if (state.keepaliveInterval) {
        clearInterval(state.keepaliveInterval);
        setState({ keepaliveInterval: null });
    }

    // Hide controls
    elements.stopRow?.classList.add('hidden');
    hideVideoSection();
}

// ========== PRIVATE HELPERS ==========

function buildWebSocketUrl(apiKey: string, voice: string, systemInstruction: string): string {
    const protocol = location.protocol === 'https:' ? 'wss' : 'ws';
    return `${protocol}://${location.host}/ws?gemini_api_key=${encodeURIComponent(apiKey)}&voice=${encodeURIComponent(voice)}&system_instruction=${encodeURIComponent(systemInstruction)}`;
}

function handleWsOpen(ws: WebSocket, mode: ConversationMode, systemInstruction: string): void {
    const elements = getElements();
    const state = getState();

    // Get selected teacher mode from radio buttons
    const teacherModeRadio = document.querySelector('input[name="teacher-mode"]:checked') as HTMLInputElement;
    const teacherMode = teacherModeRadio?.value || 'standard';
    const germanOnlyMode = localStorage.getItem('germanOnlyMode') === 'true';

    const config = {
        api_key: localStorage.getItem('gemini_api_key') || '',
        voice: localStorage.getItem('gemini_voice') || 'Puck',
        has_video: mode === 'camera' || mode === 'screen',
        teacher_mode: teacherMode,
        german_only_mode: germanOnlyMode, // Don't speak Russian translations
        native_language: localStorage.getItem('gemini_native_language') || 'Russian',
        delivery_mode: (window as any).getDeliveryMode?.() || 'interactive', // Delivery: interactive / fast_text / auto_10
        custom_instructions: systemInstruction,
        context: state.conversationHistory.slice(-10).map(m => ({
            type: m.role === 'user' ? 'user' : 'model',
            text: m.parts?.[0]?.text || m.text || ''
        }))
    };

    ws.send(JSON.stringify(config));
    console.log('[WebSocket] Config sent:', { voice: config.voice, has_video: config.has_video, teacher_mode: teacherMode, german_only_mode: germanOnlyMode, native_language: config.native_language });

    setConnected(true);
    setStatus('Connected!', true);

    // Start Orchestrator monitoring for this session
    Orchestrator.startMonitoring();
    // Start session logging
    SessionLogger.startSession(teacherMode || 'standard', 'C2');
    SessionLogger.wsConfig(config);
    addSystemMessage('✅ Connected to Gemini');

    // Reset reconnect counter on successful connection
    reconnectAttempts = 0;

    // AUTO-START: Send a trigger message so the bot starts its greeting immediately
    // Only fires ONCE per page load — prevents restart after skip/reconnect
    if (!autoStartFired) {
        autoStartFired = true;
        (window as any)._deliveredReplicaCount = 0; // Reset replica counter for new session
        setTimeout(() => {
            if (getState().isConnected && ws.readyState === WebSocket.OPEN) {
                // Backend expects { type: 'text', data: '...' } — field must be 'data' not 'text'
                ws.send(JSON.stringify({ type: 'text', data: 'Начинай!' }));
                console.log('[WebSocket] ✅ Auto-start greeting sent (one-time)');
            }
        }, 1500);
    }

    // Start audio capture
    if (state.mediaStream) {
        AudioCapture.start(state.mediaStream, ws, {
            micLevelEl: elements.micLevel,
            isPlaying: () => getState().isPlaying || AudioPlayback.getIsPlaying(),
            isConnected: () => getState().isConnected
        });
    }

    // Start screen capture
    if (elements.videoPreview?.srcObject) {
        ScreenCapture.start(elements.videoPreview, ws, {
            isConnected: () => getState().isConnected,
            interval: 1000
        });
    }

    // Keepalive
    const keepaliveInterval = window.setInterval(() => {
        if (getState().ws?.readyState === WebSocket.OPEN) {
            getState().ws!.send(JSON.stringify({ type: 'keepalive' }));
        }
    }, 25000);
    setState({ keepaliveInterval });
}

function handleWsMessage(event: MessageEvent): void {
    try {
        const msg = JSON.parse(event.data);
        console.log('[WS] Received:', msg.type, msg.data?.substring?.(0, 50) ?? '');

        switch (msg.type) {
            case 'audio':
                if (msg.data) {
                    AudioPlayback.playChunk(msg.data);
                    // Tell Orchestrator audio is still flowing (don't interrupt!)
                    Orchestrator.onAudioReceived();
                    // Update activity bar to show AI is speaking
                    const activityBar = document.getElementById('widget-activity-bar');
                    if (activityBar) {
                        activityBar.classList.add('speaking');
                        clearTimeout((window as any)._activityTimeout);
                        (window as any)._activityTimeout = setTimeout(() => {
                            activityBar.classList.remove('speaking');
                        }, 500);
                    }
                }
                break;

            case 'text':
                handleTextMessage(msg);
                break;

            case 'transcript':
                handleTranscript(msg);
                break;

            // AI thinking/reasoning (streamed before response)
            case 'ai_thinking':
                (window as any)._didReceiveMetadataForCurrentTurn = false; // Reset tool call tracking for the new turn
                (window as any)._deliveredReplicaCount = 0; // RESET delivery counter for the new turn!
                setPlaying(true); // Mute mic while AI thinks/generates to prevent self-interruption
                if (msg.data) {
                    const container = getElements().chatContainer;
                    if (container) StreamingDisplay.updateThinking(msg.data, container);
                    SessionLogger.aiThinking(msg.data);
                }
                break;

            // User transcript (partial streaming)
            case 'user_transcript_partial':
                if (msg.data) {
                    const container = getElements().chatContainer;
                    if (container) StreamingDisplay.update('user', msg.data, container);
                }
                break;

            // User transcript (final)
            case 'user_transcript':
                if (msg.data) {
                    StreamingDisplay.finalize('user', msg.data);
                    addToHistory({ role: 'user', parts: [{ text: msg.data }] });
                    setState({ lastUserInput: msg.data });
                    Chat.showAIWaiting();
                    SessionLogger.userMessage(msg.data);
                }
                break;

            // AI transcript (partial streaming)
            case 'ai_transcript_partial':
                setPlaying(true); // Mute mic while AI generates text to prevent self-interruption
                if (msg.data) {
                    // Reset metadata tracker if we see a new REPLICA marker
                    if (msg.data && msg.data.match(/REPLICA\s*\d+\s*:?/i)) {
                        console.log('[WS] 🔄 New REPLICA detected in stream — reset metadata tracking');
                        (window as any)._didReceiveMetadataForCurrentTurn = false;
                        
                        // We DO NOT set _deliveredReplicaCount to absolute numbers here.
                        // We track deliveries PER TURN instead.
                        
                        // Stop accumulating text if we already received the tool call for the PREVIOUS replica 
                        // in this stream block. Wait, this is a new replica, so we allow it.
                        (window as any)._autoContinueRetryCount = 0;
                    }

                    // ⛔ FILTER: After tool_call delivered metadata, STOP ALL streaming updates.
                    // The handleReplicaMetadata already injected the correct original_text.
                    // If we keep calling StreamingDisplay.update(), it re-renders aiAccumulatedText
                    // which contains ALL the pre-metadata streamed text → DUPLICATION.
                    // In fast_text mode this is DISABLED because bot only speaks 1 replica.
                    const deliveryMode = ((window as any).getDeliveryMode?.() || 'interactive');
                    const shouldFilterPostMetadata = deliveryMode !== 'fast_text';
                    if (shouldFilterPostMetadata && (window as any)._didReceiveMetadataForCurrentTurn === true) {
                        // Only allow new REPLICA markers through (already handled above)
                        break; // Drop ALL text — metadata already has the correct content
                    }

                    // Hide waiting indicator when AI starts responding
                    Chat.hideAIWaiting();
                    const container = getElements().chatContainer;
                    if (container) StreamingDisplay.update('ai', msg.data, container);
                    // Feed to Orchestrator for stall detection
                    Orchestrator.onStreamUpdate(msg.data);
                }
                break;

            // AI transcript (final)
            case 'ai_transcript':
                if (msg.data) {
                    // ⛔ CRITICAL: If metadata was already received for this turn, DON'T let finalize
                    // overwrite the content that handleReplicaMetadata injected.
                    // We MUST still call finalize to close the streaming session (otherwise next turn
                    // appends to the same block = duplicate text!), but use a marker so it preserves DOM.
                    if ((window as any)._didReceiveMetadataForCurrentTurn === true) {
                        console.log('[WS] 🛡️ ai_transcript received but metadata already applied — finalizing with DOM preservation');
                        // Finalize with marker to preserve existing DOM content
                        StreamingDisplay.finalize('ai', '__METADATA_APPLIED__');
                        addToHistory({ role: 'model', parts: [{ text: msg.data }] });
                        Orchestrator.onStreamFinished(msg.data);
                        SessionLogger.aiMessage(msg.data);
                        StreamingDisplay.triggerEnrichment(false);
                        break;
                    }
                    StreamingDisplay.finalize('ai', msg.data);
                    addToHistory({ role: 'model', parts: [{ text: msg.data }] });
                    Orchestrator.onStreamFinished(msg.data);
                    SessionLogger.aiMessage(msg.data);
                    StreamingDisplay.triggerEnrichment(false);
                }
                break;

            case 'turn_complete': {
                setPlaying(false); // Let AudioPlayback take over mute control

                // ⚠️ CRITICAL: Save the accumulated text BEFORE finalize() clears it!
                // ai_transcript fires before turn_complete, so finalize() may have already
                // been called and aiAccumulatedText may already be empty.
                const lastAiText = (StreamingDisplay as any).aiAccumulatedText || (StreamingDisplay as any)._lastFinalizedAiText || '';

                // Finalize AI streaming message with accumulated text
                StreamingDisplay.finalize('ai', '');
                // Notify Orchestrator — check completeness
                Orchestrator.onStreamFinished();
                StreamingDisplay.triggerEnrichment(true);

                // === AUTO-CONTINUE: Repair interrupted replica text ===
                // The bot must NEVER create new REPLICA blocks here — only finish the current one
                const isActiveMode = (document.querySelector('input[name="teacher-mode"]:checked') as HTMLInputElement)?.value === 'active';
                const missedMeta = (window as any)._didReceiveMetadataForCurrentTurn === false;
                const currentWs = getState().ws;
                
                // Only trigger if THIS turn was actually a REPLICA (not greeting/Stage1)
                const hasDialogueContent = lastAiText.includes('REPLICA') || 
                                           ((window as any)._autoContinueRetryCount > 0);

                // Retry counter — max 3 retries to repair the current replica
                const retryCount = (window as any)._autoContinueRetryCount || 0;
                const MAX_RETRIES = 3;

                const currentDeliveryMode = ((window as any).getDeliveryMode?.() || 'interactive');
                const delivered = (window as any)._deliveredReplicaCount || 0;
                
                // 🛑 Do NOT trigger auto-continue for illegal extra replicas in single-replica modes!
                // If the AI already delivered the required 1 replica and started a 2nd one by mistake,
                // do NOT ask it to complete the 2nd one. Just let it be.
                const isIllegalExtraReplica = 
                    (currentDeliveryMode === 'interactive' || currentDeliveryMode === 'fast_text') && 
                    delivered >= 1;

                if (!isIllegalExtraReplica && isActiveMode && hasDialogueContent && missedMeta && currentWs && currentWs.readyState === WebSocket.OPEN && retryCount < MAX_RETRIES) {
                    (window as any)._autoContinueRetryCount = retryCount + 1;
                    
                    // Clean text for analysis — strip HTML and REPLICA headers
                    const cleanForContext = lastAiText
                        .replace(/<[^>]+>/g, '')
                        .replace(/REPLICA\s*\d+\s*:?/gi, '')
                        .trim();
                    (window as any)._interruptedAiTextClean = cleanForContext;
                    const words = cleanForContext.split(/\s+/);
                    const lastWords = words.slice(-10).join(' ');
                    
                    // Detect: is the sentence COMPLETE (ends with .?!) or CUT OFF mid-word?
                    const textEndsWithPunctuation = /[.?!»")\]]\s*$/.test(cleanForContext);
                    
                    console.warn(`[AutoContinue] ⚠️ Repair retry ${retryCount + 1}/${MAX_RETRIES}. Text complete: ${textEndsWithPunctuation}. Last words: "${lastWords}"`);
                    addSystemMessage(`⚠️ Реплика прервана. Восстановление ${retryCount + 1}/${MAX_RETRIES}...`);
                    
                    if (textEndsWithPunctuation) {
                        // CASE A: Text IS complete — bot just forgot metadata or generated invalid metadata.
                        // User explicitly requested that Voice AI itself fixes this, NOT Text Bot.
                        // We ask the Voice AI to completely repeat the replica AND invoke the tool call.
                        console.warn(`[AutoContinue] 🤖 Text is complete but Tool Call is missing. Prompting Voice AI to repeat...`);
                        
                        // Prevent duplicate AI message: remove the incomplete one from DOM and memory
                        const chatContainer = document.getElementById('chat-messages');
                        const aiMessages = chatContainer?.querySelectorAll('.message.ai');
                        if (aiMessages && aiMessages.length > 0) {
                            aiMessages[aiMessages.length - 1].remove();
                        }
                        const chatId = (window as any).ChatSessions?.getCurrentChatId?.() || '';
                        if (chatId && typeof (window as any).ChatSessions?.removeLastMessage === 'function') {
                            (window as any).ChatSessions.removeLastMessage(chatId);
                        }
                        
                        currentWs.send(JSON.stringify({
                            type: 'text',
                            data: 'Внимание: вы не вызвали обязательную функцию send_replica_metadata для вашей последней реплики! ' +
                                  'Пожалуйста, ПОВТОРИТЕ вашу последнюю реплику ЕЩЕ РАЗ (вместе с текстом) ' +
                                  'и ОБЯЗАТЕЛЬНО вызовите функцию со ВСЕМИ параметрами (original_text, translation, hint_grammar, answer_options).'
                        }));
                    } else {
                        // CASE B: Text is CUT OFF mid-sentence — continue from where stopped
                        // The bot must NOT start a new REPLICA block, just finish the interrupted sentence
                        currentWs.send(JSON.stringify({
                            type: 'text',
                            data: `Ты прервался на полуслове! Последние слова: "...${lastWords}". ` +
                                  `ПРОДОЛЖИ РОВНО С ЭТОГО МЕСТА. ` +
                                  `ЗАПРЕЩЕНО: создавать новую реплику, писать "REPLICA N:", начинать заново. ` +
                                  `РАЗРЕШЕНО: только чистый текст-продолжение на немецком, закончи мысль точкой. ` +
                                  `Никаких комментариев. После завершения текста — вызови send_replica_metadata.`
                        }));
                    }
                } else if (isActiveMode && hasDialogueContent && missedMeta && retryCount >= MAX_RETRIES) {
                    console.warn(`[AutoContinue] ❌ Max retries (${MAX_RETRIES}) reached. Triggering Text Bot fallback.`);
                    addSystemMessage('⚠️ Голосовой бот не завершил реплику. Текстовый ИИ восстанавливает...');
                    (window as any)._autoContinueRetryCount = 0;
                    // Trigger Text Bot enrichment as fallback to fill missing metadata
                    StreamingDisplay.triggerEnrichment(true);
                }

                // === DELIVERY-MODE SPECIFIC AUTO-CONTINUE ===
                
                if (isActiveMode && currentWs && currentWs.readyState === WebSocket.OPEN) {
                    const expected = Orchestrator.expectedItemCount || 10;

                    
                    if (currentDeliveryMode === 'fast_text') {
                        // MODE: FAST TEXT — After 1st replica, trigger Text Bot for remaining 9
                        if (delivered >= 1 && (window as any)._didReceiveMetadataForCurrentTurn === true) {
                            console.log(`[AutoContinue] ⚡ Fast Text mode: ${delivered} delivered. Text Bot will fill remaining.`);
                            // Text Bot enrichment handles the rest - triggered by triggerEnrichment(true) above
                        }
                    } else if (currentDeliveryMode === 'auto_10') {
                        // MODE: AUTO-10 — Auto-continue to next replica
                        if (delivered > 0 && delivered < expected && (window as any)._didReceiveMetadataForCurrentTurn === true) {
                            console.log(`[AutoContinue] 🔄 Auto-10: Delivered ${delivered}/${expected} — requesting next replica`);
                            setTimeout(() => {
                                if (currentWs.readyState === WebSocket.OPEN) {
                                    currentWs.send(JSON.stringify({
                                        type: 'text',
                                        data: `Ты выдал ${delivered} из ${expected} реплик. ` +
                                              `Продолжай! Выдай REPLICA ${delivered + 1}. ` +
                                              `Помни: для каждой реплики нужен немецкий текст + вызов send_replica_metadata.`
                                    }));
                                }
                            }, 2000);
                        } else if (delivered >= expected) {
                            console.log(`[AutoContinue] 🎉 All ${expected} replicas delivered! Dialogue complete.`);
                            (window as any)._deliveredReplicaCount = 0;
                        }
                    }
                    // MODE: INTERACTIVE — no auto-continue, user drives the dialogue
                }

                break;
            }

            case 'tool_call':
                if (msg.name === 'send_replica_metadata' && msg.args) {
                    
                    // Validate that the AI actually included the mandatory fields
                    const hasTranslation = msg.args.translation && msg.args.translation.trim().length > 3;
                    const hasAnswers = Array.isArray(msg.args.answer_options) && msg.args.answer_options.length >= 3;
                    
                    if (!hasTranslation || !hasAnswers) {
                        console.warn(`[WS] ⚠️ INCOMPLETE Tool Call! AI omitted required fields (translation or answers). Rejecting delivery so AutoContinue can fix it.`);
                        // Do NOT set _didReceiveMetadataForCurrentTurn or increment delivered count.
                        // Just render the placeholder UI and let turn_complete trigger a retry.
                        handleReplicaMetadata(msg.args as any);
                        break;
                    }

                    (window as any)._didReceiveMetadataForCurrentTurn = true; // Mark as received!
                    
                    // ✅ INCREMENT DELIVERED REPLICA COUNTER
                    const deliveredCount = ((window as any)._deliveredReplicaCount || 0) + 1;
                    (window as any)._deliveredReplicaCount = deliveredCount;
                    console.log(`[WS] ✅ Replica ${deliveredCount} metadata delivered`);
                    
                    // Recover missing first half of the text if this was an AutoContinue retry
                    const rc = (window as any)._autoContinueRetryCount || 0;
                    if (rc > 0 && (window as any)._interruptedAiTextClean) {
                        const oldClean = (window as any)._interruptedAiTextClean;
                        if (msg.args.original_text && oldClean.length > 10) {
                            const checkStr = oldClean.substring(0, 10);
                            if (!msg.args.original_text.includes(checkStr)) {
                                msg.args.original_text = oldClean + " " + msg.args.original_text;
                            }
                        }
                        
                        // CLEAR WARNING MESSAGES FROM UI ON SUCCESSFUL RECOVERY
                        const chatOutput = document.getElementById('chat-output');
                        if (chatOutput) {
                             chatOutput.querySelectorAll('.system-message').forEach(el => {
                                 if (el.textContent && el.textContent.includes('Бот прервался') && el.textContent.includes('Попытка')) {
                                     el.remove();
                                 }
                             });
                        }
                    }

                    (window as any)._autoContinueRetryCount = 0; // Reset retry counter — success!
                    (window as any)._interruptedAiTextClean = ''; // Clear state
                    console.log('[WS] 🛠️ Tool Call Received:', msg.name, msg.args);
                    // Handle UI updates with structured metadata
                    handleReplicaMetadata(msg.args as any);
                } else if (msg.name === 'log_learning_item' && msg.args) {
                    console.log('[WS] 📝 Learning item logged:', msg.args);
                    addSystemMessage(`📝 Добавлено в словарь: ${msg.args.term}`);
                }
                break;

            case 'interrupted':
                setPlaying(false);
                AudioPlayback.skipPlayback();
                // ⚠️ CRITICAL: Finalize the current AI text BEFORE resetting
                // This saves the accumulated text to conversation history
                // so Gemini knows what was already covered (prevents topic repetition)
                StreamingDisplay.finalize('ai', '');
                StreamingDisplay.reset();
                StreamingDisplay.triggerEnrichment(true);
                break;

            case 'error':
                setPlaying(false);
                const errorMessage = msg.message || '';
                addSystemMessage('❌ ' + errorMessage);

                // Auto-reconnect on Gemini API errors (but NOT config errors!)
                // Max 3 retries with exponential backoff to prevent infinite loop
                if ((errorMessage.includes('Internal error') ||
                    errorMessage.includes('unavailable') ||
                    errorMessage.includes('Session ended')) &&
                    !errorMessage.includes('invalid argument') &&
                    !errorMessage.includes('INVALID_ARGUMENT') &&
                    reconnectAttempts < MAX_RECONNECT_ATTEMPTS) {

                    reconnectAttempts++;
                    const delay = 2000 * Math.pow(2, reconnectAttempts - 1); // 2s, 4s, 8s
                    console.log(`[WebSocket] Gemini API error, auto-reconnect attempt ${reconnectAttempts}/${MAX_RECONNECT_ATTEMPTS} in ${delay / 1000}s...`);
                    addSystemMessage(`🔄 Переподключение (попытка ${reconnectAttempts}/${MAX_RECONNECT_ATTEMPTS}) через ${delay / 1000} сек...`);

                    setTimeout(() => {
                        const state = getState();
                        if (!state.isConnected) {
                            addSystemMessage('🔄 Переподключаемся...');
                            startConversation('voice');
                        }
                    }, delay);
                } else if (reconnectAttempts >= MAX_RECONNECT_ATTEMPTS) {
                    addSystemMessage('⚠️ Не удалось переподключиться. Нажмите кнопку Voice для ручного подключения.');
                    reconnectAttempts = 0; // Reset for future manual attempts
                }
                break;
        }
    } catch (e) {
        console.error('[WebSocket] Parse error:', e);
    }
}

function handleTextMessage(msg: { data?: string; text?: string }): void {
    const text = msg.data || msg.text;
    if (!text) return;
    const container = getElements().chatContainer;
    if (!container) return;

    // Stream text to display
    StreamingDisplay.update('ai', text, container);
}

function handleTranscript(msg: { role?: string; text?: string; data?: string }): void {
    const text = msg.data || msg.text;
    if (!text) return;

    if (msg.role === 'user') {
        addMessage('user', text);
        addToHistory({ role: 'user', parts: [{ text }] });
    } else if (msg.role === 'model') {
        // Model transcript handled by streaming display
    }
}

// ========== UI HELPERS ==========

function setStatus(text: string, connected: boolean): void {
    const elements = getElements();
    if (elements.statusText) elements.statusText.textContent = text;
    if (elements.statusDot) {
        elements.statusDot.classList.toggle('connected', connected);
    }
}

function addSystemMessage(text: string): void {
    // Will be replaced by chat module
    console.log('[System]', text);
    const event = new CustomEvent('system-message', { detail: { text } });
    window.dispatchEvent(event);
}

function addMessage(role: 'user' | 'ai', text: string): void {
    // Will be replaced by chat module
    const event = new CustomEvent('chat-message', { detail: { role, text } });
    window.dispatchEvent(event);
}

function setupVideoPreview(stream: MediaStream): void {
    const elements = getElements();
    if (elements.videoPreview) {
        elements.videoPreview.srcObject = stream;
        elements.videoPreview.onloadedmetadata = () => {
            elements.videoPreview?.play().catch(() => { });
        };
    }
}

function showVideoSection(): void {
    const elements = getElements();
    elements.videoSection?.classList.remove('hidden', 'video-hidden');
    elements.videoPlaceholder?.classList.add('hidden');
}

function hideVideoSection(): void {
    const elements = getElements();
    elements.videoSection?.classList.add('hidden');
}

// Export for global access
export const WebSocketController = {
    start: startConversation,
    stop: stopConversation,
};
