/**
 * Audio Capture Module (TypeScript)
 * Handles microphone input and PCM16 encoding for Gemini Live
 */

import type { AudioCaptureOptions } from '../types';

class AudioCaptureModule {
    private audioContext: AudioContext | null = null;
    private processor: ScriptProcessorNode | null = null;
    private source: MediaStreamAudioSourceNode | null = null;
    private _micMuted = false;

    /**
     * Set mic mute state (for practice mode - bot won't hear you)
     */
    setMicMute(muted: boolean): void {
        this._micMuted = muted;
        console.log('[AudioCapture] Mic muted:', muted);
    }

    /**
     * Get mic mute state
     */
    isMicMuted(): boolean {
        return this._micMuted;
    }

    /**
     * Start capturing audio from mediaStream
     */
    start(
        mediaStream: MediaStream,
        ws: WebSocket,
        options: AudioCaptureOptions
    ): boolean {
        if (!mediaStream) {
            console.log('[AudioCapture] No mediaStream available');
            return false;
        }

        const audioTracks = mediaStream.getAudioTracks();
        if (audioTracks.length === 0) {
            console.log('[AudioCapture] No audio tracks in mediaStream');
            return false;
        }
        console.log('[AudioCapture] Starting with track:', audioTracks[0].label);

        try {
            this.audioContext = new AudioContext({ sampleRate: 16000 });

            // Resume on mobile (required for iOS/Android)
            if (this.audioContext.state === 'suspended') {
                this.audioContext.resume().catch(e => {
                    console.log('[AudioCapture] Resume failed:', e);
                });
            }

            this.source = this.audioContext.createMediaStreamSource(mediaStream);
            this.processor = this.audioContext.createScriptProcessor(4096, 1, 1);

            let chunkCount = 0;
            this.processor.onaudioprocess = (e: AudioProcessingEvent): void => {
                if (!options.isConnected()) {
                    if (chunkCount === 0) console.log('[AudioCapture] Not connected, skipping');
                    return;
                }
                if (!ws || ws.readyState !== WebSocket.OPEN) {
                    if (chunkCount === 0) console.log('[AudioCapture] WebSocket not open, skipping');
                    return;
                }

                const inputData = e.inputBuffer.getChannelData(0);

                // Update mic level visualization (horizontal bar)
                if (options.micLevelEl) {
                    if (this._micMuted) {
                        options.micLevelEl.style.width = '0%';
                    } else {
                        const level = this.calculateRMS(inputData) * 100;
                        options.micLevelEl.style.width = `${Math.min(level * 3, 100)}%`;
                    }
                }

                // Skip sending when AI is speaking (prevents echo)
                if (options.isPlaying()) {
                    if (chunkCount % 50 === 0) console.log('[AudioCapture] AI speaking, paused');
                    return;
                }

                // Skip sending when mic is muted (practice mode)
                if (this._micMuted) {
                    return;
                }

                // Convert to 16-bit PCM and send
                const pcm16 = this.floatToPCM16(inputData);
                const base64 = this.arrayBufferToBase64(pcm16.buffer as ArrayBuffer);
                ws.send(JSON.stringify({ type: 'audio', data: base64 }));

                chunkCount++;
                if (chunkCount <= 3 || chunkCount % 100 === 0) {
                    console.log(`[AudioCapture] Sent chunk #${chunkCount}`);
                }
            };

            this.source.connect(this.processor);
            this.processor.connect(this.audioContext.destination);
            console.log('[AudioCapture] Started successfully');
            return true;

        } catch (e) {
            console.error('[AudioCapture] Failed to start:', e);
            return false;
        }
    }

    /**
     * Stop audio capture and clean up resources
     */
    stop(): void {
        try {
            this.processor?.disconnect();
            this.source?.disconnect();
            this.audioContext?.close();
        } catch (e) {
            console.log('[AudioCapture] Error stopping:', e);
        }
        this.processor = null;
        this.source = null;
        this.audioContext = null;
        console.log('[AudioCapture] Stopped');
    }

    /**
     * Calculate RMS level (optimized with SIMD-friendly loop)
     */
    private calculateRMS(data: Float32Array): number {
        let sum = 0;
        const len = data.length;
        // Process in chunks of 4 for better CPU cache utilization
        for (let i = 0; i < len; i += 4) {
            sum += data[i] * data[i];
            if (i + 1 < len) sum += data[i + 1] * data[i + 1];
            if (i + 2 < len) sum += data[i + 2] * data[i + 2];
            if (i + 3 < len) sum += data[i + 3] * data[i + 3];
        }
        return Math.sqrt(sum / len);
    }

    /**
     * Convert Float32 to Int16 PCM (optimized)
     */
    private floatToPCM16(input: Float32Array): Int16Array {
        const output = new Int16Array(input.length);
        for (let i = 0; i < input.length; i++) {
            // Clamp and scale in one operation
            output[i] = Math.max(-32768, Math.min(32767, (input[i] * 32767) | 0));
        }
        return output;
    }

    /**
     * Convert ArrayBuffer to Base64 (optimized chunked approach)
     */
    private arrayBufferToBase64(buffer: ArrayBuffer): string {
        const bytes = new Uint8Array(buffer);
        const CHUNK_SIZE = 8192;
        let binary = '';

        for (let i = 0; i < bytes.length; i += CHUNK_SIZE) {
            const chunk = bytes.subarray(i, i + CHUNK_SIZE);
            binary += String.fromCharCode(...chunk);
        }

        return btoa(binary);
    }
}

export const AudioCapture = new AudioCaptureModule();

// Global export for legacy compatibility
if (typeof window !== 'undefined') {
    (window as any).AudioCapture = AudioCapture;
}

console.log('[AudioCapture] Module loaded (TS)');
