/**
 * Streaming Display Module (TypeScript)
 * Handles real-time message rendering for streaming responses
 */

import { saveMessage, getCurrentChatId } from './chat-sessions';
import { resetEnrichment } from './enrichment';

class StreamingDisplayModule {
    private streamingUserMsg: HTMLElement | null = null;
    private streamingAiMsg: HTMLElement | null = null;
    private userAccumulatedText = '';
    public aiAccumulatedText = '';
    private lastTextReceivedTime: number = 0;
    private messageIdCounter = 0;
    private scheduledWordIds = new Set<string>(); // Track which words have karaoke scheduled
    private spokenWordCount = 0; // Track how many words have been spoken (survives innerHTML re-renders)
    private spokenWords = new Set<string>(); // Track spoken word-texts for V3 karaoke (text-based, survives DOM resets)
    private activeDialogueBlock: number | null = null; // Track which dialogue block bot is currently speaking about
    private streamingStallTimer: ReturnType<typeof setTimeout> | null = null; // Detect bot stopping mid-stream
    // Persist across continuations:
    public lastPromisedCount = 0; // e.g. "Вот 10 реплик" → 10, persists across messages
    private totalDeliveredReplicas = 0; // accumulates replica count across continuations
    private autoContinueTimer: ReturnType<typeof setTimeout> | null = null; // Auto-continue countdown

    // Cached DOM template (performance optimization)
    private static readonly MSG_TEMPLATE_USER = '<div class="msg-label">You</div><div class="message-bubble"></div>';
    private static readonly MSG_TEMPLATE_AI = '<div class="msg-label">Gemini</div><div class="message-bubble karaoke-text"></div>';

    // Universal word characters pattern (any script — for karaoke highlighting)
    private static readonly WORD_PATTERN = /[\p{L}\p{M}]+/gu;

    /**
     * Detect the active dialogue block number from the CURRENT STREAMING BUBBLE's DOM.
     * This is ONLY a fallback source when regex matching fails during streaming.
     */
    private detectActiveBlockFromDOM(bubble: HTMLElement): number | null {
        const blocks = bubble.querySelectorAll('.dialogue-block[data-dialogue-id]');
        if (blocks.length === 0) return null;
        // If there are multiple blocks, we can't be sure which one without text parsing.
        // We only use this reliable fallback if the block count is 1 or we're at the end.
        const lastBlock = blocks[blocks.length - 1];
        const dlgId = lastBlock.getAttribute('data-dialogue-id') || '';
        const numMatch = dlgId.match(/(\d+)/);
        return numMatch ? parseInt(numMatch[1], 10) : blocks.length;
    }

    /**
     * Update streaming message with new content + karaoke highlighting
     */
    update(type: 'user' | 'ai', partialText: string, container: HTMLElement): void {
        if (!container) return;

        // Clear welcome screen if present
        if (typeof (window as any).clearWelcome === 'function') {
            (window as any).clearWelcome();
        }

        if (type === 'user') {
            // Extract words from user speech for answer highlighting
            const userChunkWords = partialText.match(StreamingDisplayModule.WORD_PATTERN) || [];

            this.userAccumulatedText += partialText;
            this.lastTextReceivedTime = Date.now(); // Record user activity too just in case

            if (!this.streamingUserMsg) {
                this.streamingUserMsg = this.createMessageElement('user');
                container.appendChild(this.streamingUserMsg);
            }

            const bubble = this.streamingUserMsg.querySelector('.message-bubble') as HTMLElement;
            bubble.textContent = this.userAccumulatedText;

            // Highlight matching words in <answer> blocks when user speaks
            if (userChunkWords.length > 0) {
                this.highlightWordsInAnswers(userChunkWords, container);
            }
        } else {
            // Check if this is a CONTINUATION of a previous broken REPLICA
            // If we don't have a streamingAiMsg, check the last message in the container
            
            if (!this.streamingAiMsg) {
                // Find all AI messages, bypassing any recent "Bot interrupted" system messages
                const aiMessages = container.querySelectorAll('.message.ai');
                const lastMsg = aiMessages.length > 0 ? (aiMessages[aiMessages.length - 1] as HTMLElement) : null;
                
                if (lastMsg) {
                    const lastBubble = lastMsg.querySelector('.message-bubble');
                    // If it has dialogue blocks but NO translation/hint, it might be the broken one
                    // Check if the auto-continue retry counter is active
                    const retryCount = (window as any)._autoContinueRetryCount || 0;
                    if (retryCount > 0 && lastBubble) {
                        this.streamingAiMsg = lastMsg;
                        this.streamingAiMsg.classList.add('streaming'); // Re-activate
                        
                        // Recover previous text state so Vocabulary can format everything together
                        const rawTextSpan = this.streamingAiMsg.dataset.text || '';
                        // Only inherit if it was actually a REPLICA (not a system message or something else)
                        if (rawTextSpan.includes('REPLICA') || this.aiAccumulatedText === '') {
                             this.aiAccumulatedText = rawTextSpan; // Recover history!
                             console.log('[StreamingDisplay] 🔗 Re-attaching to previous AI message (Auto-Continue)');
                        }
                    }
                }
            }

            if (!this.streamingAiMsg) {
                this.streamingAiMsg = this.createMessageElement('ai');
                container.appendChild(this.streamingAiMsg);
                this.scheduledWordIds.clear();
                this.spokenWordCount = 0; // Reset for new message
                this.spokenWords.clear(); // Reset spoken-word set for new message (karaoke V3)
                this.activeDialogueBlock = null; // Reset target block for new message
            }
            // Thinking stays open during streaming
            // It will be collapsed in finalize() when response is complete

            // Extract words from AI speech for highlighting existing content (questions/answers)
            const aiChunkWords = partialText.match(StreamingDisplayModule.WORD_PATTERN) || [];

            // === ROBUST BLOCK DETECTION ===
            // Identify which block the bot is currently focusing on for highlighting.
            // When streaming, the bot might discuss block 1, then block 2, etc.
            const fullText = this.aiAccumulatedText + partialText;

            // Pattern 1: Universal "REPLICA N:" / "Реплика N:" / "Replik N:" / any keyword + number
            const replicaNumMatch = fullText.match(/(?:REPLICA|Реплика|Replik|Replica|вопрос|блок|диалог|block|question|pregunta|domanda|質問|문제)\s*(\d+)/i);
            if (replicaNumMatch) {
                this.activeDialogueBlock = parseInt(replicaNumMatch[1], 10);
            }

            // Pattern 2: Standalone number at start of line followed by punctuation (universal "1." or "[1]")
            if (this.activeDialogueBlock === null) {
                const standaloneNumMatch = fullText.match(/(?:^|\n)\s*\[?(\d{1,2})\]?\s*[.:)]\s/m);
                if (standaloneNumMatch) {
                    const num = parseInt(standaloneNumMatch[1], 10);
                    if (num >= 1 && num <= 20) {
                        this.activeDialogueBlock = num;
                    }
                }
            }

            // Pattern 3: Prefix format "[REPLICA 1]:"
            if (this.activeDialogueBlock === null) {
                const prefixMatch = fullText.match(/\[REPLICA\s+(\d+)\]/i);
                if (prefixMatch) {
                    this.activeDialogueBlock = parseInt(prefixMatch[1], 10);
                }
            }

            // SECONDARY FALLBACK: DOM-based — detect active block from the current streaming bubble.
            // Best used when regex hasn't caught anything yet but a dialogue-block exists.
            if (this.activeDialogueBlock === null) {
                const streamBubble = this.streamingAiMsg.querySelector('.message-bubble') as HTMLElement;
                if (streamBubble) {
                    const domBlock = this.detectActiveBlockFromDOM(streamBubble);
                    if (domBlock !== null) {
                        this.activeDialogueBlock = domBlock;
                    }
                }
            }

            // Pattern 4: German ordinals (kept as legacy)
            if (this.activeDialogueBlock === null) {
                const ordinalMatch = fullText.match(/(ersten|zweiten|dritten|vierten|fünften|sechsten|siebten|achten|neunten|zehnten)\s+(?:Replik|Frage|Dialog)/i);
                if (ordinalMatch) {
                    const ordinalMap: { [key: string]: number } = {
                        'ersten': 1, 'zweiten': 2, 'dritten': 3, 'vierten': 4, 'fünften': 5,
                        'sechsten': 6, 'siebten': 7, 'achten': 8, 'neunten': 9, 'zehnten': 10
                    };
                    this.activeDialogueBlock = ordinalMap[ordinalMatch[1].toLowerCase()] || null;
                }
            }

            // Pattern 5: Russian ordinals (kept as legacy)
            if (this.activeDialogueBlock === null) {
                const ruOrdinalMatch = fullText.match(/(первый|первая|второй|вторая|третий|третья|четвёртый|четвертый|пятый|шестой|седьмой|восьмой|девятый|десятый)\s+(?:вопрос|реплика|блок)/i);
                if (ruOrdinalMatch) {
                    const ruOrdinalMap: { [key: string]: number } = {
                        'первый': 1, 'первая': 1, 'второй': 2, 'вторая': 2, 'третий': 3, 'третья': 3,
                        'четвёртый': 4, 'четвертый': 4, 'пятый': 5, 'шестой': 6, 'седьмой': 7,
                        'восьмой': 8, 'девятый': 9, 'десятый': 10
                    };
                    this.activeDialogueBlock = ruOrdinalMap[ruOrdinalMatch[1].toLowerCase()] || null;
                }
            }

            // Pattern 6: Quoted text content match (any language)
            if (this.activeDialogueBlock === null) {
                const quotedMatch = fullText.match(/(?:Реплика|вопрос|Replik|Frage|replica|question)\s+(?:был[аи]?|was|war)[:\s]*[\"„'«]([^\"„'»]+)/i);
                if (quotedMatch) {
                    const quotedText = quotedMatch[1].trim().substring(0, 30);
                    this.activeDialogueBlock = this.findBlockByContent(quotedText, container);
                }
            }

            // Pattern 7: Answer content match (any language)
            if (this.activeDialogueBlock === null) {
                const answerMatch = fullText.match(/(?:Вы\s+ответили|You\s+answered|Sie\s+antworteten)[:\s]*[\"„'«]([^\"„'»]+)/i);
                if (answerMatch) {
                    const answerText = answerMatch[1].trim().substring(0, 30);
                    this.activeDialogueBlock = this.findBlockByAnswerContent(answerText, container);
                }
            }

            // Highlight matching words in EXISTING content (previous questions + answers)
            // This handles bot repeating questions or speaking answers
            // NOW LIMITED to the active dialogue block if known!
            if (aiChunkWords.length > 0) {
                this.highlightBotSpeechInExistingContent(aiChunkWords, container, this.activeDialogueBlock);
            }

            // Now accumulate
            this.aiAccumulatedText += partialText;
            this.lastTextReceivedTime = Date.now();

            // === LIVE HARVESTING POLLER & HARD KILL ESCALATION ===
            if (this.streamingStallTimer) clearTimeout(this.streamingStallTimer);

            const checkStall = () => {
                if (!this.streamingAiMsg || !this.aiAccumulatedText) return;

                // 1. How long since we received actual text from the WebSocket?
                const timeSinceLastChar = Date.now() - this.lastTextReceivedTime;

                // 2. Are we still physically playing audio? 
                // We MUST not Hard Kill the websocket if audio is still flowing from the buffer,
                // even if the WebSocket has been silent for a long time.
                const isPlaying = (window as any).AudioPlayback?.getIsPlaying?.() || false;

                if (timeSinceLastChar >= 45000 && !isPlaying) {
                    // HARD KILL: 45s WebSocket silence AND the WebAudio buffer is completely drained.
                    // The Voice stream is genuinely dead.
                    console.warn('[StreamingDisplay] 45s Hard Kill! Audio stopped & API Stream dead. Forcing turn completion fallback!');
                    const controller = (window as any).WebSocketController;
                    if (controller?.sendMessage) {
                        try {
                            const handler = controller.messageHandlers?.get('turn_complete');
                            if (handler) handler({ type: 'turn_complete' });
                        } catch (e) {
                            console.error('[StreamingDisplay] Failed to trigger manual turn complete', e);
                        }
                    } else {
                        this.finalize('ai', '');
                        this.triggerEnrichment(true);
                    }
                    return; // Stop polling
                }

                // 3. SOFT HARVEST: The WebSocket is silent (timeSinceLastChar >= 5000 from the timer delay)
                // Audio might STILL be playing (isPlaying === true), but that shouldn't stop us!
                // We can ask the Text Bot to harvest Blocks 1,2,3 while the user is listening to Block 4.
                // We DO NOT send 'turn_complete'.

                // Only harvest if it's been at least 5 seconds since the last text chunk arrived,
                // ensuring we aren't spamming the Text Bot while the Voice API is actively typing.
                if (timeSinceLastChar >= 5000) {
                    this.triggerEnrichment(false);
                }

                // Re-arm the poller so we keep harvesting/escalating if it stalls again
                this.streamingStallTimer = setTimeout(checkStall, 5000);
            };

            // Wait 5 seconds after the last piece of text arrived from WS
            this.streamingStallTimer = setTimeout(checkStall, 5000);


            // Remove continue preloader — bot started responding
            const loader = document.querySelector('.continue-preloader');
            if (loader) loader.remove();

            const bubble = this.streamingAiMsg.querySelector('.message-bubble') as HTMLElement;

            // Use Vocabulary.formatMessage for CONSISTENT formatting with finalized messages
            const Vocabulary = (window as any).Vocabulary;
            const rawText = this.aiAccumulatedText;

            // Format with Vocabulary (handles EVERYTHING: СОБЕСЕДНИК blocks, translations, <hint>/<answer>)
            let formattedHtml = Vocabulary?.formatMessage?.(rawText) ?? this.escapeHtml(rawText);

            // === PRESERVE STATE ACROSS innerHTML RESET ===
            // 1. Save which hint/answer panels are currently revealed
            const revealedHints = new Set<string>();
            const revealedAnswers = new Set<string>();
            bubble.querySelectorAll('.hint-container').forEach(c => {
                const id = (c as HTMLElement).id;
                if (id) {
                    const hint = c.querySelector('[data-type="hint"]');
                    const answer = c.querySelector('[data-type="answer"]');
                    if (hint && !hint.classList.contains('hidden')) revealedHints.add(id);
                    if (answer && !answer.classList.contains('hidden')) revealedAnswers.add(id);
                }
            });

            // 1b. FREEZE: Detach enriched hint-containers so they survive innerHTML wipe.
            //     This prevents scroll jump caused by collapsing and re-expanding hints.
            const savedEnrichedHints = new Map<string, { container: HTMLElement; blockId: string }>();
            const savedTranslations = new Map<string, HTMLElement>();
            bubble.querySelectorAll('.dialogue-block[data-dialogue-id]').forEach(block => {
                const blockId = block.getAttribute('data-dialogue-id') || '';
                const hintContainer = block.querySelector('.hint-container[data-enriched]') as HTMLElement;
                if (hintContainer) {
                    savedEnrichedHints.set(blockId, {
                        container: hintContainer,
                        blockId
                    });
                    hintContainer.remove(); // Detach from DOM (saves the element in memory)
                }
                const transBlock = block.querySelector('.translation-block, .translation') as HTMLElement;
                if (transBlock) {
                    savedTranslations.set(blockId, transBlock);
                    transBlock.remove(); // Detach translation so it survives innerHTML format
                }
                const germanTtsBtn = block.querySelector('.german-tts-btn') as HTMLElement;
                if (germanTtsBtn) {
                    (savedTranslations as any).germanTtsBtns = (savedTranslations as any).germanTtsBtns || new Map();
                    (savedTranslations as any).germanTtsBtns.set(blockId, germanTtsBtn);
                    germanTtsBtn.remove();
                }
            });

            // 2. Detach thinking element before innerHTML wipe (so it survives)
            //    ⚠️ SAVE scroll position BEFORE detach — removeChild() RESETS scrollTop to 0!
            const thinkingRef = this.thinkingElement;
            let savedThinkingScroll = 0;
            let thinkingWasOpen = false;
            if (thinkingRef) {
                const tc = thinkingRef.querySelector('.thought-content') as HTMLElement;
                if (tc) savedThinkingScroll = tc.scrollTop;
                thinkingWasOpen = thinkingRef.hasAttribute('open');
                if (thinkingRef.parentNode) {
                    thinkingRef.parentNode.removeChild(thinkingRef);
                }
            }

            // === SCROLL: Use SINGLE source of truth (isPinnedToBottom from chat.ts) ===
            const chatContainer = document.getElementById('chat-messages');
            const pinned = (window as unknown as { isPinnedToBottom: boolean }).isPinnedToBottom;
            const savedScrollTop = chatContainer ? chatContainer.scrollTop : 0;

            bubble.innerHTML = formattedHtml || '...';

            // === 🐞 Mute Bug Fix: Visual Pulse Indicator ===
            // If Text API is sending a giant batch (no voice chunks), show a "Working..." indicator inside the bubble
            const isAudioActive = (window as any).AudioPlayback?.getIsPlaying?.() || false;

            // Only show if we have accumulated a decent amount of text, and audio has stopped
            if (!isAudioActive && this.aiAccumulatedText.length > 50) {
                const pulse = document.createElement('div');
                pulse.className = 'silence-pulse';
                pulse.innerHTML = '<i>⏳ ИИ формулирует текст (генерация аудио приостановлена)...</i>';
                pulse.style.color = 'var(--text-muted)';
                pulse.style.fontSize = '0.85em';
                pulse.style.marginTop = '12px';
                pulse.style.padding = '8px 12px';
                pulse.style.borderLeft = '3px solid var(--primary)';
                pulse.style.backgroundColor = 'var(--bg-tag)';
                pulse.style.borderRadius = '4px';
                pulse.style.animation = 'pulse 2s infinite opacity';
                bubble.appendChild(pulse);
            }

            // 3. Re-insert thinking element at top of bubble + RESTORE scroll
            if (thinkingRef) {
                bubble.prepend(thinkingRef);
                // Restore open/closed state
                if (thinkingWasOpen) {
                    thinkingRef.setAttribute('open', '');
                } else {
                    thinkingRef.removeAttribute('open');
                }
                // Restore thought-content scroll position (was reset by removeChild!)
                const tc = thinkingRef.querySelector('.thought-content') as HTMLElement;
                if (tc) {
                    tc.scrollTop = savedThinkingScroll;
                }
            }

            // 4. Restore revealed hint/answer panel states
            if (revealedHints.size > 0 || revealedAnswers.size > 0) {
                const revealFn = (window as any).revealHint;
                if (revealFn) {
                    revealedHints.forEach(id => revealFn(id, 'hint'));
                    revealedAnswers.forEach(id => revealFn(id, 'answer'));
                }
            }

            // 4b. THAW: Re-attach saved enriched hint containers into their original blocks.
            //     This replaces the freshly-rendered (collapsed) hints with the saved (open) ones,
            //     preventing the scroll jump caused by collapse→expand reflow.
            if (savedEnrichedHints.size > 0) {
                savedEnrichedHints.forEach(({ container, blockId }) => {
                    const block = bubble.querySelector(`.dialogue-block[data-dialogue-id="${blockId}"]`);
                    if (block) {
                        // Remove the freshly-rendered hint (from formatMessage) if it exists
                        const freshHint = block.querySelector('.hint-container:not([data-enriched])');
                        if (freshHint) freshHint.remove();
                        // Re-attach the saved enriched container
                        block.appendChild(container);
                    }
                });
            }

            // 4c. THAW: Re-attach saved translations
            if (savedTranslations.size > 0) {
                savedTranslations.forEach((transBlock, blockId) => {
                    const block = bubble.querySelector(`.dialogue-block[data-dialogue-id="${blockId}"]`);
                    if (block) {
                        const content = block.querySelector('.dialogue-content');
                        if (content) {
                            // ensure we don't have duplicates
                            content.querySelectorAll('.translation-block, .translation').forEach(el => el.remove());
                            content.insertAdjacentElement('afterbegin', transBlock);
                        }
                    }
                });
            }

            // 4d. THAW: Re-attach saved German TTS buttons
            if ((savedTranslations as any).germanTtsBtns && (savedTranslations as any).germanTtsBtns.size > 0) {
                (savedTranslations as any).germanTtsBtns.forEach((ttsBtn: HTMLElement, blockId: string) => {
                    const block = bubble.querySelector(`.dialogue-block[data-dialogue-id="${blockId}"]`);
                    if (block) {
                        const content = block.querySelector('.dialogue-content');
                        if (content) {
                            content.querySelectorAll('.german-tts-btn').forEach(el => el.remove());
                            content.appendChild(ttsBtn);
                        }
                    }
                });
            }

            // === SCROLL: Restore chat position based on single isPinnedToBottom flag ===
            if (chatContainer) {
                if (pinned) {
                    // User is pinned to bottom → follow the stream
                    chatContainer.scrollTop = chatContainer.scrollHeight;
                } else {
                    // User manually scrolled up → DON'T touch! Keep their position
                    chatContainer.scrollTop = savedScrollTop;
                }
            }

            // ========== KARAOKE SECTION (wrapped in try-catch to NEVER crash update()) ==========
            // If karaoke fails, the text is still rendered above via bubble.innerHTML
            try {
                // KARAOKE: Wrap words ONLY in dialogue-content (text that is actually spoken)
                // Skip: headers, translations, hints, answers, German TTS buttons (not spoken by bot)
                const SKIP_CLASSES = ['translation', 'translation-block', 'translation-icon', 'hint-text', 'answer-text', 'hint-container', 'answer-container', 'dialogue-header', 'dialogue-number', 'dialogue-speaker-label', 'hint-btn', 'tts-play-btn', 'german-tts-btn', 'hint-column', 'hint-panel', 'answer-item', 'answer-list', 'answer-header', 'hint-header', 'hint-list', 'hint-item', 'thought-details', 'ai-thinking-inline', 'thought-title', 'thought-content', 'karaoke-word'];

                const wrapTextNodes = (node: Node): void => {
                    if (node.nodeType === Node.TEXT_NODE) {
                        const text = node.textContent || '';
                        if (text.trim()) {
                            const wrapper = document.createDocumentFragment();
                            let wordIdx = 0;
                            const parts = text.split(/(\s+)/);
                            parts.forEach(part => {
                                if (part.trim()) {
                                    const span = document.createElement('span');
                                    span.className = 'karaoke-word';
                                    span.id = `kw-${Date.now()}-${wordIdx++}`;
                                    span.textContent = part;
                                    wrapper.appendChild(span);
                                } else if (part) {
                                    wrapper.appendChild(document.createTextNode(part));
                                }
                            });
                            node.parentNode?.replaceChild(wrapper, node);
                        }
                    } else if (node.nodeType === Node.ELEMENT_NODE) {
                        const el = node as HTMLElement;
                        if (!SKIP_CLASSES.some(cls => el.classList.contains(cls))) {
                            Array.from(node.childNodes).forEach(child => wrapTextNodes(child));
                        }
                    }
                };

                // Only wrap words in dialogue-content elements (the SPOKEN parts)
                const dialogueContents = bubble.querySelectorAll('.dialogue-content');
                if (dialogueContents.length > 0) {
                    dialogueContents.forEach(dc => {
                        Array.from(dc.childNodes).forEach(child => wrapTextNodes(child));
                    });
                } else {
                    // No dialogue blocks — wrap ALL text in bubble (skip hint/answer containers)
                    Array.from(bubble.childNodes).forEach(child => wrapTextNodes(child));
                }

                // ======== KARAOKE V3: Words-by-text, survives innerHTML resets ========
                const allKaraokeWords = bubble.querySelectorAll('.karaoke-word');
                const totalWrappedWords = allKaraokeWords.length;

                if (totalWrappedWords > 0) {
                    // Re-apply spoken state to words whose text was already spoken
                    allKaraokeWords.forEach(span => {
                        const wordText = (span.textContent || '').toLowerCase().replace(/[.,!?:;'"()]/g, '');
                        if (this.spokenWords.has(wordText)) {
                            span.classList.add('karaoke-spoken');
                        }
                    });

                    // Words in THIS chunk that are NEW (not yet spoken)
                    const chunkWordTexts = aiChunkWords
                        .map((w: string) => w.toLowerCase().replace(/[.,!?:;'"()]/g, ''))
                        .filter((w: string) => w.length > 1);

                    if (chunkWordTexts.length > 0) {
                        // Get REAL audio delay from AudioPlayback
                        const AudioPlayback = (window as any).AudioPlayback;
                        const audioBufferDelayMs = AudioPlayback?.getAudioDelay?.() || 0;
                        const AUDIO_CHUNK_DURATION_MS = 500;
                        const msPerWord = chunkWordTexts.length > 0 ? AUDIO_CHUNK_DURATION_MS / chunkWordTexts.length : 200;
                        const baseDelayMs = Math.max(audioBufferDelayMs, 100);

                        // Schedule highlighting for each word in this chunk by TEXT MATCH
                        chunkWordTexts.forEach((wordText: string, i: number) => {
                            const wordDelay = baseDelayMs + (i * msPerWord);
                            const capturedWordText = wordText;

                            setTimeout(() => {
                                try {
                                    this.spokenWords.add(capturedWordText);
                                    if (!this.streamingAiMsg) return;
                                    const freshBubble = this.streamingAiMsg.querySelector('.message-bubble') as HTMLElement;
                                    if (!freshBubble) return;

                                    const allWords = freshBubble.querySelectorAll('.karaoke-word');
                                    let span: Element | null = null;
                                    for (const w of allWords) {
                                        const wText = (w.textContent || '').toLowerCase().replace(/[.,!?:;'"()]/g, '');
                                        if (wText === capturedWordText && !w.classList.contains('karaoke-active')) {
                                            span = w;
                                            break;
                                        }
                                    }
                                    if (!span) {
                                        for (const w of allWords) {
                                            if (!w.classList.contains('karaoke-spoken') && !w.classList.contains('karaoke-active')) {
                                                span = w;
                                                break;
                                            }
                                        }
                                    }
                                    if (!span) return;

                                    span.classList.add('karaoke-active');
                                    span.classList.add('karaoke-spoken');
                                    this.spokenWordCount = Math.max(this.spokenWordCount, Array.from(allWords).indexOf(span) + 1);

                                    // Smooth scroll
                                    const scrollFollowEnabled = (window as unknown as { scrollFollowMode?: boolean }).scrollFollowMode !== false;
                                    const chatContainer = document.getElementById('chat-messages');
                                    if (scrollFollowEnabled && chatContainer) {
                                        const containerRect = chatContainer.getBoundingClientRect();
                                        const spanRect = (span as HTMLElement).getBoundingClientRect();
                                        const viewportBottom = containerRect.top + containerRect.height * 0.7;
                                        if (spanRect.top > viewportBottom || spanRect.bottom < containerRect.top + 50) {
                                            chatContainer.scrollTo({
                                                top: chatContainer.scrollTop + (spanRect.top - containerRect.top) - (containerRect.height * 0.3),
                                                behavior: 'smooth'
                                            });
                                        }
                                    }

                                    setTimeout(() => { span!.classList.remove('karaoke-active'); }, 300);

                                    const dialogueBlock = span.closest('.dialogue-block');
                                    if (dialogueBlock) {
                                        freshBubble.querySelectorAll('.dialogue-block-active').forEach(el => el.classList.remove('dialogue-block-active'));
                                        dialogueBlock.classList.add('dialogue-block-active');
                                    }
                                } catch (e) {
                                    // Karaoke highlighting error — ignore silently
                                }
                            }, wordDelay);
                        });
                    }
                }
            } catch (karaokeErr) {
                console.warn('[StreamingDisplay] Karaoke wrapping error (non-fatal):', karaokeErr);
            }
        }
    }

    /**
     * Highlight words in existing answer blocks that match what AI is speaking
     */
    private highlightWordsInAnswers(chunkWords: string[], container: HTMLElement): void {
        // Find all answer-german elements in previous messages only (not current streaming)
        const answerElements = container.querySelectorAll('.message:not(.streaming) .answer-german');

        // Normalize words for matching (lowercase, clean punctuation)
        const wordsToHighlight = chunkWords
            .map(w => w.toLowerCase().replace(/[.,!?:;'"()]/g, ''))
            .filter(w => w.length > 1); // Skip single chars

        if (wordsToHighlight.length === 0) return;

        answerElements.forEach(el => {
            const htmlEl = el as HTMLElement;

            // First time: wrap all words with spans for highlighting
            if (!htmlEl.dataset.karaokeWrapped) {
                const text = htmlEl.textContent || '';
                // Wrap each word in a span while preserving whitespace (universal Unicode)
                const wrappedHtml = text.replace(/([\p{L}\p{M}]+)/gu,
                    '<span class="karaoke-answer-word" data-word="$1">$1</span>'
                );
                htmlEl.innerHTML = wrappedHtml;
                htmlEl.dataset.karaokeWrapped = 'true';
            }

            // Activate matching words
            htmlEl.querySelectorAll('.karaoke-answer-word').forEach(span => {
                const wordData = (span as HTMLElement).dataset.word?.toLowerCase() || '';
                if (wordsToHighlight.includes(wordData)) {
                    span.classList.add('active');

                    // Remove active class after delay
                    setTimeout(() => {
                        span.classList.remove('active');
                    }, 600);
                }
            });
        });
    }

    /**
     * Find dialogue block number by matching content text
     * Used when bot says "Реплика была: 'Some text...'" without explicit number
     */
    private findBlockByContent(searchText: string, container: HTMLElement): number | null {
        const dialogueBlocks = container.querySelectorAll('.message:not(.streaming) .dialogue-block');
        const normalizedSearch = searchText.toLowerCase().replace(/[.,!?:;'"()„"]/g, '');

        for (let i = 0; i < dialogueBlocks.length; i++) {
            const block = dialogueBlocks[i];
            const content = block.querySelector('.dialogue-content');
            if (content) {
                const blockText = (content.textContent || '').toLowerCase().replace(/[.,!?:;'"()„"]/g, '');
                if (blockText.includes(normalizedSearch) || normalizedSearch.includes(blockText.substring(0, 20))) {
                    // Found matching block - extract number from .dialogue-number
                    const numberEl = block.querySelector('.dialogue-number');
                    const num = parseInt(numberEl?.textContent?.replace(/\D/g, '') || '0', 10);
                    if (num > 0) return num;
                    // Fallback: use index + 1
                    return i + 1;
                }
            }
        }
        return null;
    }

    /**
     * Find dialogue block number by matching answer content
     * Used when bot says "Вы ответили: 'Some answer...'" and we need to find the block
     */
    private findBlockByAnswerContent(searchText: string, container: HTMLElement): number | null {
        const dialogueBlocks = container.querySelectorAll('.message:not(.streaming) .dialogue-block');
        const normalizedSearch = searchText.toLowerCase().replace(/[.,!?:;'"()„"]/g, '');

        for (let i = 0; i < dialogueBlocks.length; i++) {
            const block = dialogueBlocks[i];
            const answerElements = block.querySelectorAll('.answer-german');
            for (const answerEl of answerElements) {
                const answerText = (answerEl.textContent || '').toLowerCase().replace(/[.,!?:;'"()„"]/g, '');
                if (answerText.includes(normalizedSearch) || normalizedSearch.includes(answerText.substring(0, 20))) {
                    // Found matching block - extract number
                    const numberEl = block.querySelector('.dialogue-number');
                    const num = parseInt(numberEl?.textContent?.replace(/\D/g, '') || '0', 10);
                    if (num > 0) return num;
                    return i + 1;
                }
            }
        }
        return null;
    }

    /**
     * Highlight words in EXISTING content when bot speaks (repeats question or says answer)
     * This handles the "response phase" when bot is not streaming NEW text, but speaking existing content
     * @param targetBlockNumber - If provided, only highlight in this specific dialogue block (1-indexed)
     */
    private highlightBotSpeechInExistingContent(chunkWords: string[], container: HTMLElement, targetBlockNumber: number | null = null): void {
        // Normalize words for matching
        const wordsToHighlight = chunkWords
            .map(w => w.toLowerCase().replace(/[.,!?:;'"()„"]/g, ''))
            .filter(w => w.length > 1);

        if (wordsToHighlight.length === 0) return;

        // 1. Highlight in PREVIOUS messages' dialogue-content (question being repeated by bot)
        const previousDialogueContents = container.querySelectorAll('.message:not(.streaming) .dialogue-content');
        previousDialogueContents.forEach(dc => {
            // If targetBlockNumber is set, filter to only that block
            if (targetBlockNumber !== null) {
                const dialogueBlock = dc.closest('.dialogue-block');
                if (dialogueBlock) {
                    // Extract block number from dialogue-number element  
                    const numberEl = dialogueBlock.querySelector('.dialogue-number');
                    const blockNum = parseInt(numberEl?.textContent?.replace(/\D/g, '') || '0', 10);
                    if (blockNum !== targetBlockNumber) {
                        return; // Skip this block - not the target
                    }
                }
            }

            const karaokeWords = dc.querySelectorAll('.karaoke-word');
            karaokeWords.forEach(span => {
                const wordText = (span.textContent || '').toLowerCase().replace(/[.,!?:;'"()„"]/g, '');
                if (wordsToHighlight.includes(wordText)) {
                    span.classList.add('karaoke-active');
                    span.classList.add('karaoke-spoken');

                    // Remove active class after delay
                    setTimeout(() => {
                        span.classList.remove('karaoke-active');
                    }, 400);

                    // Highlight parent dialogue block
                    const dialogueBlock = span.closest('.dialogue-block');
                    if (dialogueBlock) {
                        dialogueBlock.classList.add('dialogue-block-active');
                        setTimeout(() => {
                            dialogueBlock.classList.remove('dialogue-block-active');
                        }, 600);
                    }
                }
            });
        });

        // 2. Highlight in <answer> blocks (answer being spoken by bot)
        const answerElements = container.querySelectorAll('.message:not(.streaming) .answer-german');
        answerElements.forEach(el => {
            const htmlEl = el as HTMLElement;

            // First time: wrap all words with spans for highlighting
            if (!htmlEl.dataset.karaokeWrapped) {
                const text = htmlEl.textContent || '';
                const wrappedHtml = text.replace(/([\p{L}\p{M}]+)/gu,
                    '<span class="karaoke-answer-word" data-word="$1">$1</span>'
                );
                htmlEl.innerHTML = wrappedHtml;
                htmlEl.dataset.karaokeWrapped = 'true';
            }

            // Activate matching words with karaoke effect
            htmlEl.querySelectorAll('.karaoke-answer-word').forEach(span => {
                const wordData = (span as HTMLElement).dataset.word?.toLowerCase() || '';
                if (wordsToHighlight.includes(wordData)) {
                    span.classList.add('active');
                    span.classList.add('karaoke-bot-speaking'); // Additional class for bot speech

                    // Remove active class after delay
                    setTimeout(() => {
                        span.classList.remove('active');
                        span.classList.remove('karaoke-bot-speaking');
                    }, 400);
                }
            });
        });
    }

    /**
     * Finalize streaming message
     */
    finalize(type: 'user' | 'ai', finalText: string): void {
        const msgId = `msg_${++this.messageIdCounter}`;
        const chatId = getCurrentChatId();

        if (type === 'user' && this.streamingUserMsg) {
            const text = finalText.trim() || this.userAccumulatedText.trim();
            this.finalizeElement(this.streamingUserMsg, msgId, this.escapeHtml(text));
            this.streamingUserMsg = null;
            this.userAccumulatedText = '';

            // Save to localStorage for chat persistence
            if (chatId && text) {
                saveMessage(chatId, 'user', text);
            }
        } else if (type === 'ai' && this.streamingAiMsg) {
            // === DOM PRESERVATION MODE ===
            // When metadata was already applied by handleReplicaMetadata, 
            // we MUST close the streaming session (to prevent duplicates on next turn)
            // but MUST NOT overwrite the bubble innerHTML (to preserve injected translation/hint/answer).
            if (finalText === '__METADATA_APPLIED__') {
                console.log('[StreamingDisplay] 🛡️ Finalizing with DOM preservation — metadata already applied');
                const msgId2 = `msg_${this.messageIdCounter}`; // reuse the already-incremented id
                this.streamingAiMsg.classList.remove('streaming');
                this.streamingAiMsg.id = msgId2;
                // Collapse thinking if present
                this.fadeOutThinking();
                // Close session without touching DOM
                this.streamingAiMsg = null;
                (this as any)._lastFinalizedAiText = this.aiAccumulatedText;
                this.aiAccumulatedText = '';
                return;
            }

            const text = finalText.trim() || this.aiAccumulatedText.trim();

            // === 🐞 Mute Bug Fix: Auto-TTS Fallback ===
            const AudioPlayback = (window as any).AudioPlayback;
            const chunksPlayed = (AudioPlayback as any)?.chunksPlayed || 0;
            // Heuristic: If we received a huge chunk of text (>500 chars) but very little audio (e.g. less than 20 chunks),
            // it means Voice AI muted itself and just generated text. We must fall back to local TTS.
            const isMissingAudio = text.length > 500 && chunksPlayed < 20;

            if (isMissingAudio) {
                console.warn(`[StreamingDisplay] 🔇 Voice AI Mute detected! Text: ${text.length} chars, Audio Chunks: ${chunksPlayed}. Forcing Auto-TTS Fallback...`);
                // Use a short delay to allow DOM to render before speaking
                setTimeout(() => {
                    const Vocabulary = (window as any).Vocabulary;
                    if (Vocabulary?.speakText) {
                        // Extract only spoken German text (strip <hint>, <answer>, etc)
                        const cleanText = Vocabulary.cleanForTTS ? Vocabulary.cleanForTTS(text) : text;
                        if (cleanText.length > 10) Vocabulary.speakText(cleanText);
                    }
                }, 800);
            }

            // Format with Vocabulary (handles EVERYTHING: СОБЕСЕДНИК blocks, translations, <hint>/<answer>)
            // NOTE: DO NOT call formatDialogueBlocks - causes double-processing and broken HTML!
            const Vocabulary = (window as any).Vocabulary;
            const formatted = Vocabulary?.formatMessage?.(text) ?? text;

            // Collapse thinking BEFORE finalize (so it's in collapsed state in the final message)
            this.fadeOutThinking();

            this.finalizeElement(this.streamingAiMsg, msgId, formatted);

            // Save to localStorage for chat persistence (include thinking if present)
            if (chatId) {
                const bubble = this.streamingAiMsg?.querySelector('.message-bubble') as HTMLElement;
                if (bubble) saveMessage(chatId, 'ai', bubble.innerHTML);
            }

            // Extract vocabulary
            Vocabulary?.extractAndLog?.(text);

            // Check scene completion
            if (typeof (window as any).checkSceneCompletion === 'function') {
                (window as any).checkSceneCompletion(text);
            }

            // Check for incomplete replicas
            // Clear stall timer since finalize handles the check
            if (this.streamingStallTimer) {
                clearTimeout(this.streamingStallTimer);
                this.streamingStallTimer = null;
            }
            this.checkIncompleteReplicas(this.streamingAiMsg, text);

            // We rely on turn_complete or ai_transcript to trigger enrichment instead
            // of calling it per-block here.

            this.streamingAiMsg = null;
            // Save for turn_complete handler (ai_transcript fires before turn_complete,
            // so aiAccumulatedText would be empty when turn_complete checks it)
            (this as any)._lastFinalizedAiText = this.aiAccumulatedText;
            this.aiAccumulatedText = '';
        } else if (typeof (window as any).addMessage === 'function') {
            (window as any).addMessage(type, finalText);
        }
    }

    private createMessageElement(type: 'user' | 'ai'): HTMLElement {
        const el = document.createElement('div');
        el.className = `message ${type} streaming`;
        el.innerHTML = type === 'user'
            ? StreamingDisplayModule.MSG_TEMPLATE_USER
            : StreamingDisplayModule.MSG_TEMPLATE_AI;
        return el;
    }

    private finalizeElement(el: HTMLElement, msgId: string, content: string): void {
        el.classList.remove('streaming');
        el.id = msgId;
        el.dataset.text = content;

        const bubble = el.querySelector('.message-bubble') as HTMLElement;
        if (bubble && content) {
            // === PRESERVE EXISTING DOM STATE ACROSS innerHTML RESET ===
            // Detach thinking element
            const thinkingEl = bubble.querySelector('.thought-details') as HTMLElement;
            if (thinkingEl && thinkingEl.parentNode) {
                thinkingEl.parentNode.removeChild(thinkingEl);
            }

            // Rescue dynamically injected hints and loaders from Enrichment API
            // They are attached to .dialogue-block elements, we need their dialogue-id mapping
            const savedEnhancements = new Map<string, HTMLElement[]>();
            bubble.querySelectorAll('.dialogue-block').forEach(block => {
                const id = block.getAttribute('data-dialogue-id');
                if (!id) return;

                const enhancements: HTMLElement[] = [];
                // Save both finished hints, active loaders, translations, AND TTS buttons!
                block.querySelectorAll('.hint-container, .enrichment-loader, .translation-block, .translation, .german-tts-btn').forEach(enhancedNode => {
                    enhancements.push(enhancedNode as HTMLElement);
                    if (enhancedNode.parentNode) enhancedNode.parentNode.removeChild(enhancedNode);
                });

                if (enhancements.length > 0) {
                    savedEnhancements.set(id, enhancements);
                }
            });

            // Use StreamingDisplay.speak() instead of global speakText
            bubble.innerHTML = content + `<div class="message-actions-inline"><button class="tts-btn" onclick="StreamingDisplay.speak('${msgId}')" title="Read aloud">🔈</button></div>`;

            // Restore the rescued hints into their respective blocks in the new DOM
            savedEnhancements.forEach((enhancements, id) => {
                const newBlock = bubble.querySelector(`.dialogue-block[data-dialogue-id="${id}"]`);
                if (newBlock) {
                    enhancements.forEach(node => {
                        if (node.classList.contains('translation-block') || node.classList.contains('translation')) {
                             const contentDiv = newBlock.querySelector('.dialogue-content');
                             if (contentDiv) {
                                  // Avoid duplicates
                                  contentDiv.querySelectorAll('.translation-block, .translation').forEach(el => el.remove());
                                  contentDiv.insertAdjacentElement('afterbegin', node);
                             }
                        } else if (node.classList.contains('german-tts-btn')) {
                             const contentDiv = newBlock.querySelector('.dialogue-content');
                             if (contentDiv) {
                                  contentDiv.querySelectorAll('.german-tts-btn').forEach(el => el.remove());
                                  const transNode = contentDiv.querySelector('.translation-block, .translation');
                                  if (transNode) {
                                      contentDiv.insertBefore(node, transNode);
                                  } else {
                                      contentDiv.appendChild(node);
                                  }
                             }
                        } else {
                            // CRITICAL FIX: To prevent duplicate grammar buttons (Harvester Double Injection),
                            // check if the freshly parsed DOM *already* has a hint container!
                            // If it does, we ONLY restore loaders, we throw away the old hint!
                            if (node.classList.contains('hint-container')) {
                                const alreadyHasHint = newBlock.querySelector('.hint-container') !== null;
                                if (alreadyHasHint) {
                                    console.log(`[StreamingDisplay] 🛡️ Dropped duplicate rescued hint for block ${id} because a new one was just parsed.`);
                                    return; // Skip restoring this old hint!
                                }
                            }
                            newBlock.appendChild(node);
                        }
                    });
                }
            });

            // Re-insert thinking element at top of bubble (collapsed state from fadeOutThinking)
            if (thinkingEl) {
                bubble.prepend(thinkingEl);
            }

            // CRITICAL: Re-wrap words in .karaoke-word spans after innerHTML replacement
            // This is needed so highlightBotSpeechInExistingContent can find words in finalized messages
            this.wrapDialogueWordsForKaraoke(bubble);
        } else if (bubble && !content) {
            el.style.display = 'none';
        }
    }

    /**
     * Wrap words in .dialogue-content elements with .karaoke-word spans
     * Used both during streaming and after finalize to enable karaoke highlighting
     */
    private wrapDialogueWordsForKaraoke(bubble: HTMLElement): void {
        const SKIP_CLASSES = ['translation', 'translation-block', 'translation-icon', 'hint-text', 'answer-text', 'hint-container', 'answer-container', 'dialogue-header', 'dialogue-number', 'dialogue-speaker-label', 'hint-btn', 'tts-play-btn', 'german-tts-btn', 'hint-column', 'hint-panel', 'answer-item', 'answer-list', 'answer-header', 'hint-header', 'hint-list', 'hint-item', 'karaoke-word'];

        const wrapTextNodes = (node: Node): void => {
            if (node.nodeType === Node.TEXT_NODE) {
                const text = node.textContent || '';
                if (text.trim()) {
                    const wrapper = document.createDocumentFragment();
                    let wordIdx = 0;
                    const parts = text.split(/(\s+)/);
                    parts.forEach(part => {
                        if (part.trim()) {
                            const span = document.createElement('span');
                            span.className = 'karaoke-word';
                            span.id = `kw-${Date.now()}-${wordIdx++}`;
                            span.textContent = part;
                            wrapper.appendChild(span);
                        } else if (part) {
                            wrapper.appendChild(document.createTextNode(part));
                        }
                    });
                    node.parentNode?.replaceChild(wrapper, node);
                }
            } else if (node.nodeType === Node.ELEMENT_NODE) {
                const el = node as HTMLElement;
                if (!SKIP_CLASSES.some(cls => el.classList.contains(cls))) {
                    Array.from(node.childNodes).forEach(child => wrapTextNodes(child));
                }
            }
        };

        // Only wrap words in dialogue-content elements (the SPOKEN parts)
        const dialogueContents = bubble.querySelectorAll('.dialogue-content');

        if (dialogueContents.length > 0) {
            dialogueContents.forEach(dc => {
                Array.from(dc.childNodes).forEach(child => wrapTextNodes(child));
            });
        }
        // Note: For finalized messages, we DON'T wrap non-dialogue text to avoid issues
    }

    /**
     * TTS Playback with karaoke word highlighting
     */
    async speak(msgId: string): Promise<void> {
        const el = document.getElementById(msgId);
        if (!el) return;

        // Get raw text (not HTML)
        const rawText = el.dataset.text || el.textContent || '';
        if (!rawText) return;

        const voice = (document.getElementById('voice-select') as HTMLSelectElement)?.value || 'Zephyr';

        const Vocabulary = (window as any).Vocabulary;
        const button = el.querySelector('.tts-btn');

        if (button) button.textContent = '⏳';

        // Find the bubble and ensure karaoke words are wrapped
        const bubble = el.querySelector('.message-bubble') as HTMLElement;
        if (bubble) {
            this.wrapDialogueWordsForKaraoke(bubble);

            // Extract spoken words from dialogue-content only
            const words: string[] = [];
            bubble.querySelectorAll('.dialogue-content .karaoke-word').forEach(span => {
                const w = (span.textContent || '').trim();
                if (w.length > 1) words.push(w);
            });

            if (words.length > 0) {
                // Estimate TTS speed: roughly 2.5 words/second
                const MS_PER_WORD = 380;
                words.forEach((word, i) => {
                    setTimeout(() => {
                        // Re-query fresh spans (bubble innerHTML may have changed)
                        const freshBubble = el.querySelector('.message-bubble') as HTMLElement;
                        if (!freshBubble) return;
                        // Find first unwrapped span matching this word
                        for (const span of freshBubble.querySelectorAll('.dialogue-content .karaoke-word')) {
                            if ((span.textContent || '').trim() === word && !span.classList.contains('karaoke-tts-done')) {
                                span.classList.add('karaoke-active', 'karaoke-tts-done');
                                // Highlight parent dialogue block
                                const dBlock = span.closest('.dialogue-block');
                                if (dBlock) {
                                    freshBubble.querySelectorAll('.dialogue-block-active').forEach(b => b.classList.remove('dialogue-block-active'));
                                    dBlock.classList.add('dialogue-block-active');
                                }
                                setTimeout(() => span.classList.remove('karaoke-active'), 350);
                                break;
                            }
                        }
                    }, i * MS_PER_WORD);
                });

                // Remove dialogue-block-active after all words done
                setTimeout(() => {
                    el.querySelectorAll('.dialogue-block-active').forEach(b => b.classList.remove('dialogue-block-active'));
                    el.querySelectorAll('.karaoke-tts-done').forEach(b => b.classList.remove('karaoke-tts-done'));
                }, words.length * MS_PER_WORD + 500);
            }
        }

        try {
            await Vocabulary?.speakText?.(rawText, voice);
            if (button) button.textContent = '🔈';
        } catch (e) {
            console.error('[StreamingDisplay] TTS failed:', e);
            if (button) button.textContent = '❌';
            setTimeout(() => { if (button) button.textContent = '🔈'; }, 2000);
        }
    }

    // ========== AI THINKING VISUALIZATION ==========
    private thinkingElement: HTMLElement | null = null;
    private thinkingText = '';

    /**
     * Display AI thinking/reasoning process inline inside the current AI message
     * Creates a collapsible <details> block above the response text
     */
    updateThinking(text: string, container: HTMLElement): void {
        if (!container) return;

        // Accumulate thinking text
        this.thinkingText += text;

        // Create the AI streaming message if it doesn't exist yet
        if (!this.streamingAiMsg) {
            // ⚠️ CRITICAL: If there's an old thinking block from a previous (interrupted) response,
            // fade it out NOW so it stays collapsed in the old message
            if (this.thinkingElement) {
                this.fadeOutThinking();
            }

            // === AutoContinue Reattachment Logic (same as update()) ===
            const aiMessages = container.querySelectorAll('.message.ai');
            const lastMsg = aiMessages.length > 0 ? (aiMessages[aiMessages.length - 1] as HTMLElement) : null;
            
            if (lastMsg) {
                const retryCount = (window as any)._autoContinueRetryCount || 0;
                if (retryCount > 0 && lastMsg.querySelector('.message-bubble')) {
                    this.streamingAiMsg = lastMsg;
                    this.streamingAiMsg.classList.add('streaming'); // Re-activate
                    // Inherit previous state
                    const rawTextSpan = this.streamingAiMsg.dataset.text || '';
                    if (rawTextSpan.includes('REPLICA') || this.aiAccumulatedText === '') {
                         this.aiAccumulatedText = rawTextSpan; // Recover history!
                         console.log('[StreamingDisplay] 🔗 Re-attaching to previous AI message via Thoughts (Auto-Continue)');
                    }
                }
            }

            if (!this.streamingAiMsg) {
                this.streamingAiMsg = this.createMessageElement('ai');
                container.appendChild(this.streamingAiMsg);
            }
        }

        const bubble = this.streamingAiMsg.querySelector('.message-bubble') as HTMLElement;
        if (!bubble) return;

        // Create thinking element inside bubble if not exists
        if (!this.thinkingElement) {
            this.thinkingElement = document.createElement('details');
            this.thinkingElement.className = 'thought-details ai-thinking-inline';
            this.thinkingElement.innerHTML = `
                <summary class="thought-title" style="cursor: pointer; font-size: 0.85em; opacity: 0.7; margin-bottom: 8px; user-select: none;">🤔 Gemini думает (развернуть/свернуть)...</summary>
                <div class="thought-content" style="white-space: pre-wrap; font-family: monospace; font-size: 0.8em; opacity: 0.75; padding: 10px; background: rgba(0,0,0,0.2); border-radius: 6px; margin-bottom: 15px; max-height: 200px; overflow-y: auto;"></div>
            `;
            
            // Add listener to handle manual toggles when stream is paused/stopped before finalize
            this.thinkingElement.addEventListener('toggle', () => {
                if (this.thinkingElement?.classList.contains('thinking-complete')) return;
                const summary = this.thinkingElement?.querySelector('.thought-title');
                if (summary) {
                    if (this.thinkingElement?.hasAttribute('open')) {
                        summary.textContent = `🤔 Gemini думает (свернуть)...`;
                    } else {
                        // When closing, try to show the latest thought line
                        const lines = this.thinkingText.split('\n').map(l => l.trim()).filter(l => l.length > 0);
                        let latestLine = lines.length > 0 ? lines[lines.length - 1] : 'Gemini думает...';
                        latestLine = latestLine.replace(/\*\*/g, '');
                        if (latestLine.length > 50) latestLine = latestLine.substring(0, 47) + '...';
                        summary.textContent = `🤔 ${latestLine}`;
                    }
                }
            });

            // Insert at the beginning of bubble (before any response text)
            bubble.prepend(this.thinkingElement);
        }

        // APPEND new text instead of replacing — this preserves scroll position natively
        const content = this.thinkingElement.querySelector('.thought-content') as HTMLElement;
        if (content) {
            // Check if user is pinned to bottom BEFORE appending
            const wasAtBottom = content.scrollHeight - content.scrollTop - content.clientHeight < 30;

            // Append only the NEW chunk (not the entire accumulated text)
            content.appendChild(document.createTextNode(text));

            // Auto-scroll to bottom ONLY if user was already at bottom
            if (wasAtBottom) {
                content.scrollTop = content.scrollHeight;
            }
            // If user scrolled up manually — do NOTHING, their position stays
            
            // Update dynamic title
            const summary = this.thinkingElement.querySelector('.thought-title');
            if (summary && !this.thinkingElement.hasAttribute('open')) {
                const lines = this.thinkingText.split('\n').map(l => l.trim()).filter(l => l.length > 0);
                let latestLine = lines.length > 0 ? lines[lines.length - 1] : 'Gemini думает...';
                latestLine = latestLine.replace(/\*\*/g, '');
                if (latestLine.length > 50) latestLine = latestLine.substring(0, 47) + '...';
                summary.textContent = `🤔 ${latestLine}`;
            } else if (summary && this.thinkingElement.hasAttribute('open') && summary.textContent !== '🤔 Gemini думает (свернуть)...') {
                summary.textContent = `🤔 Gemini думает (свернуть)...`;
            }
        }

        // --- EXTRACT HIDDEN XML TAGS ---
        // Originally we extracted tags from thoughts here.
        // We removed this logic as the LLM no longer sends <hint> blocks in thoughts via Live API.
        // The LLM now uses the `send_replica_metadata` tool call instead.

        // NOTE: No auto-scroll during thinking phase — let user read thoughts freely
        // Auto-scroll resumes when actual AI response text starts streaming
    }

    /**
     * Clear thinking state (reset reference but keep collapsed element in message)
     */
    private clearThinking(): void {
        // Remove if still exists (e.g. on hard reset before finalize)
        if (this.thinkingElement && !this.thinkingElement.closest('.message:not(.streaming)')) {
            this.thinkingElement.remove();
        }
        this.thinkingElement = null;
        this.thinkingText = '';
    }

    // Track fade timer to avoid multiple fades
    private thinkingFadeTimer: ReturnType<typeof setTimeout> | null = null;

    /**
     * Mark thinking as complete — collapse the details and update summary
     */
    private fadeOutThinking(): void {
        if (!this.thinkingElement) return;

        // Already marked as completed? Skip
        if (this.thinkingElement.classList.contains('thinking-complete')) return;

        // Mark as complete
        this.thinkingElement.classList.add('thinking-complete');

        // Collapse the details
        this.thinkingElement.removeAttribute('open');

        // Update summary label
        const summary = this.thinkingElement.querySelector('.thought-title');
        if (summary) summary.textContent = '🧠 Мысли';

        // Reduce opacity
        this.thinkingElement.style.opacity = '0.7';

        // Release reference — the element stays in the message but we won't update it anymore
        this.thinkingElement = null;
        this.thinkingText = '';
    }

    /**
     * Check if bot promised N replicas but delivered fewer.
     * Shows a warning banner if incomplete.
     * Uses HIGHEST replica number found (not accumulation) to avoid double-counting.
     */
    private checkIncompleteReplicas(msgElement: HTMLElement | null, rawText: string): void {
        if (!msgElement) return;

        // === STEP 1: Detect promised count ===
        const wordToNum: { [key: string]: number } = {
            'drei': 3, 'vier': 4, 'fünf': 5, 'sechs': 6, 'sieben': 7,
            'acht': 8, 'neun': 9, 'zehn': 10, 'elf': 11, 'zwölf': 12,
            'три': 3, 'четыре': 4, 'пять': 5, 'шесть': 6, 'семь': 7,
            'восемь': 8, 'девять': 9, 'десять': 10, 'одиннадцать': 11, 'двенадцать': 12,
            'three': 3, 'four': 4, 'five': 5, 'six': 6, 'seven': 7,
            'eight': 8, 'nine': 9, 'ten': 10, 'eleven': 11, 'twelve': 12,
        };
        const wordNumPattern = Object.keys(wordToNum).join('|');
        const keywords = 'реплик|вопрос|Repliken|Replik|Fragen|Frage|questions|replies|replicas|Kontexte|Kontexten|Situationen|ситуаций|ситуации|scenarios|situations';

        let promisedInThisMessage = 0;

        // Pattern 1: digit + (0-3 words) + keyword
        const digitMatch = rawText.match(new RegExp(`(\\d+)\\s+(?:\\S+\\s+){0,3}(?:${keywords})`, 'i'));
        if (digitMatch) {
            promisedInThisMessage = parseInt(digitMatch[1], 10);
        }

        // Pattern 2: word-number + (0-3 words) + keyword
        if (!promisedInThisMessage) {
            const wordMatch = rawText.match(new RegExp(`(${wordNumPattern})\\s+(?:\\S+\\s+){0,3}(?:${keywords})`, 'i'));
            if (wordMatch) {
                promisedInThisMessage = wordToNum[wordMatch[1].toLowerCase()] || 0;
            }
        }

        // Save promise (but don't reset if same number — continuation restatement)
        if (promisedInThisMessage >= 3 && promisedInThisMessage !== this.lastPromisedCount) {
            this.lastPromisedCount = promisedInThisMessage;
            this.totalDeliveredReplicas = 0;
        } else if (promisedInThisMessage >= 3) {
            // Same promise restated in a continuation — just update, don't reset
            this.lastPromisedCount = promisedInThisMessage;
        }

        if (this.lastPromisedCount < 3) return;

        // === STEP 2: Find HIGHEST numbered replica in CURRENT batch only ===
        // Count .dialogue-block elements (created by formatMessage from "N. СОБЕСЕДНИК:")
        // Only scan AI messages AFTER the last user message (not old conversations!)
        const chatContainer = document.getElementById('chat-messages');
        let highestReplicaNum = 0;

        if (chatContainer) {
            // DOM uses class "message user" / "message ai" (NOT "message-row"!)
            const allMsgs = Array.from(chatContainer.querySelectorAll('.message'));
            let lastUserIdx = -1;
            allMsgs.forEach((msg, i) => {
                if (msg.classList.contains('user')) lastUserIdx = i;
            });

            // Only scan AI messages that came AFTER the last user message
            const currentBatchAI = allMsgs
                .slice(lastUserIdx + 1)
                .filter(msg => msg.classList.contains('ai'));

            // Count dialogue-blocks by data-dialogue-id attribute (set by vocabulary.ts formatMessage)
            // Format: data-dialogue-id="dlg-1", "dlg-2", etc.
            let totalBlocks = 0;
            currentBatchAI.forEach(msg => {
                const blocks = msg.querySelectorAll('.dialogue-block[data-dialogue-id]');
                blocks.forEach(block => {
                    totalBlocks++;
                    const dialogueId = block.getAttribute('data-dialogue-id') || '';
                    const numMatch = dialogueId.match(/(\d+)/);
                    if (numMatch) {
                        const num = parseInt(numMatch[1], 10);
                        if (num > highestReplicaNum) highestReplicaNum = num;
                    }
                });
            });

            console.log(`[IncompleteReplicas] DEBUG: totalMsgs=${allMsgs.length}, lastUserIdx=${lastUserIdx}, currentBatchAI=${currentBatchAI.length}, dialogueBlocks=${totalBlocks}, highestId=${highestReplicaNum}`);
        }

        // Use highest number found (don't go backwards)
        this.totalDeliveredReplicas = Math.max(this.totalDeliveredReplicas, highestReplicaNum);

        console.log(`[IncompleteReplicas] Promised=${this.lastPromisedCount}, HighestNum=${highestReplicaNum}, Total=${this.totalDeliveredReplicas}`);

        if (this.totalDeliveredReplicas >= this.lastPromisedCount && this.lastPromisedCount > 0) {
            console.log(`[IncompleteReplicas] All ${this.lastPromisedCount} replicas delivered!`);
        }
    }



    triggerEnrichment(isTurnComplete: boolean = false): void {
        setTimeout(() => {
            if (typeof (window as any).enrichDialogueBlocks === 'function') {
                (window as any).enrichDialogueBlocks(isTurnComplete);
            } else {
                import('./enrichment').then(m => m.enrichDialogueBlocks(isTurnComplete));
            }
        }, 500);
    }

    checkAutoContinue(ws: WebSocket | null, text: string): void {
        if (!ws || ws.readyState !== WebSocket.OPEN) return;
        
        const cleanText = text.trim();
        if (!cleanText) return;

        // Check if text has REPLICA tags (Dialogue mode)
        const isDialogue = cleanText.includes('REPLICA') || cleanText.includes('dialogue-content');
        
        // Define what constitutes a "finished" sentence
        const endsWithPunctuation = /[.!?»"'](\s*<\/div>)*$/.test(cleanText);
        // Sometimes the AI just cuts off after a few words. 
        const isTooShort = cleanText.length < 50 && isDialogue;
        
        // Critical: Check if the AI actually called the send_replica_metadata tool for this turn.
        // We track this via a global flag set by websocket-controller.ts when it receives the tool call.
        const missedMetadata = isDialogue && (window as any)._didReceiveMetadataForCurrentTurn === false;

        if (isDialogue && (!endsWithPunctuation || isTooShort || missedMetadata)) {
            let reason = missedMetadata ? "Missing translation/metadata" : (isTooShort ? "Abnormally short" : "Cut-off text");
            console.warn(`[AutoContinue] ⚠️ Detected incomplete response (${reason})! Requesting continuation...`);
            
            // Add system warning visible to user
            if (typeof (window as any).addSystemMessage === 'function') {
                (window as any).addSystemMessage('⚠️ Ответ прерван или не завершен (нет перевода). Запрашиваю продолжение мыслей...');
            }

            // Send silent instruction to AI asking to continue
            ws.send(JSON.stringify({ 
                type: 'text', 
                data: 'Ты прервался и не закончил свою мысль (ИЛИ ты забыл вызвать функцию send_replica_metadata)! Пожалуйста, продолжи свою мысль, скажи минимум 3-6 предложений, как требуется для уровня C2, и В КОНЦЕ ОБЯЗАТЕЛЬНО сделай вызов функции send_replica_metadata!' 
            }));
        }
    }

    reset(): void {
        // Fade out any active thinking so it stays collapsed in the current message
        if (this.thinkingElement) {
            this.fadeOutThinking();
        }
        // Clear stall detection timer
        if (this.streamingStallTimer) {
            clearTimeout(this.streamingStallTimer);
            this.streamingStallTimer = null;
        }
        // Clear auto-continue timer
        if (this.autoContinueTimer) {
            clearTimeout(this.autoContinueTimer);
            this.autoContinueTimer = null;
        }
        this.streamingUserMsg = null;
        this.streamingAiMsg = null;
        this.userAccumulatedText = '';
        this.aiAccumulatedText = '';
        this.scheduledWordIds.clear();
    }

    /**
     * Full reset including thinking - only call on session stop
     */
    hardReset(): void {
        this.reset();
        // Clear persistent replica tracking (full session ended)
        this.lastPromisedCount = 0;
        this.totalDeliveredReplicas = 0;
        // Reset enrichment state
        resetEnrichment();
        // Clear fade timer if active
        if (this.thinkingFadeTimer) {
            clearTimeout(this.thinkingFadeTimer);
            this.thinkingFadeTimer = null;
        }
        this.clearThinking();
    }

    private escapeHtml(text: string): string {
        const div = document.createElement('div');
        div.textContent = text;
        return div.innerHTML;
    }
}

