function createSelToolbar(): HTMLElement {
    const tb = document.createElement('div');
    tb.id = 'sel-toolbar';
    tb.innerHTML = `
        <button class="sel-btn sel-btn-tts" data-action="tts" title="Озвучить выделенный текст">🔊 Озвучить</button>
        <button class="sel-btn sel-btn-analyze" data-action="analyze" title="Разбор грамматики">📝 Анализ грамматики</button>
        <button class="sel-btn sel-btn-explain" data-action="explain" title="Объяснить как для новичка">💡 Обьяснить подробно</button>
    `;

    tb.addEventListener('click', async (e) => {
        const btn = (e.target as HTMLElement).closest('.sel-btn') as HTMLElement;
        if (!btn || !selectedTextForTTS) return;
        e.preventDefault();
        e.stopPropagation();

        const action = btn.dataset.action;

        if (action === 'tts') {
            btn.textContent = '⏳ ...';
            try {
                const voice = (document.getElementById('voice-select') as HTMLSelectElement)?.value || 'Zephyr';
                const Vocabulary = (window as any).Vocabulary;
                await Vocabulary?.speakText?.(selectedTextForTTS, voice);
                btn.textContent = '✅ Готово';
                setTimeout(() => { btn.textContent = '🔊 Озвучить'; }, 1500);
            } catch {
                btn.textContent = '❌';
                setTimeout(() => { btn.textContent = '🔊 Озвучить'; }, 1500);
            }
        } else if (action === 'analyze') {
            const textToAnalyze = selectedTextForTTS;
            hideSelToolbar();
            showAnalysisPanel('📝 Анализ грамматики', textToAnalyze, 'analyze');
        } else if (action === 'explain') {
            const textToExplain = selectedTextForTTS;
            hideSelToolbar();
            showAnalysisPanel('💡 Объяснение для начинающих', textToExplain, 'explain');
        }
    });

    // Prevent mousedown from clearing the selection before click fires
    tb.addEventListener('mousedown', (e) => {
        if ((e.target as HTMLElement).closest('.sel-btn')) {
            e.preventDefault();
        }
    });

    document.body.appendChild(tb);
    return tb;
}

async function showAnalysisPanel(title: string, text: string, mode: 'analyze' | 'explain'): Promise<void> {
    // Remove old panel
    closeAnalysisPanel();

    // Overlay
    const overlay = document.createElement('div');
    overlay.id = 'sel-analysis-overlay';
    overlay.addEventListener('click', closeAnalysisPanel);
    document.body.appendChild(overlay);

    // Panel
    const panel = document.createElement('div');
    panel.id = 'sel-analysis-panel';
    panel.innerHTML = `
        <div class="sel-panel-header">
            <span>${title}</span>
            <button class="sel-panel-close" title="Закрыть">×</button>
        </div>
        <div class="sel-panel-body">
            <div class="sel-panel-original">"${text}"</div>
            <div class="sel-panel-loading">🤖 Анализирую...<br><small>Несколько секунд</small></div>
        </div>
    `;

    panel.querySelector('.sel-panel-close')?.addEventListener('click', closeAnalysisPanel);
    document.body.appendChild(panel);

    // Send to backend via /api/chat (supports custom messages)
    const level = localStorage.getItem('gemini_level') || 'A1';
    const lang = localStorage.getItem('gemini_target_language') || 'German';
    const nativeLang = localStorage.getItem('gemini_native_language') || 'Russian';
    const apiKey = (document.getElementById('api-key') as HTMLInputElement)?.value
        || localStorage.getItem('gemini_api_key') || '';

    const message = mode === 'analyze'
        ? `Разбери грамматику этого текста на языке ${lang} ОЧЕНЬ ПОДРОБНО на языке ${nativeLang}.
Для КАЖДОГО слова в тексте объясни:
- Какая часть речи (существительное, глагол, предлог и т.д.)
- Падеж и почему именно этот падеж
- Артикль и почему (если есть)
- Время глагола и спряжение
- Порядок слов — почему слова стоят именно так
- Предлоги — что они требуют (Akkusativ/Dativ и т.д.)
Уровень ученика: ${level}.
ОТВЕЧАЙ ТОЛЬКО НА ЯЗЫКЕ: ${nativeLang}!
Анализируемый текст: "${text}"`
        : `Объясни этот текст на языке ${lang} КАК ДЛЯ ПОЛНОГО НОВИЧКА. Отвечай НА ЯЗЫКЕ: ${nativeLang}.
Простым языком, с аналогиями, примерами из жизни. Без сложных лингвистических терминов.
Как будто объясняешь 10-летнему ребёнку который только начал учить язык.
Разложи каждое слово и конструкцию. Приведи похожие примеры.
Уровень ученика: ${level}.
ОТВЕЧАЙ ТОЛЬКО НА ЯЗЫКЕ: ${nativeLang}!
Текст для объяснения: "${text}"`;

    try {
        const response = await fetch('/api/chat', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
                api_key: apiKey,
                message: message,
                custom_instructions: `Ты — учитель языка ${lang}. ВСЕГДА отвечай на языке: ${nativeLang}. Анализируй ТОЛЬКО тот текст, который дан. Не добавляй лишней информации. Будь конкретным и полезным.`,
                context: []
            })
        });

        if (!response.ok) throw new Error('API error');
        const data = await response.json();

        const body = panel.querySelector('.sel-panel-body') as HTMLElement;
        if (!body) return;

        let html = (data.text || 'Нет данных')
            .replace(/### (.*)/g, '<h4>$1</h4>')
            .replace(/## (.*)/g, '<h3>$1</h3>')
            .replace(/\*\*(.*?)\*\*/g, '<strong>$1</strong>')
            .replace(/\*(.*?)\*/g, '<em>$1</em>')
            .replace(/`(.*?)`/g, '<code>$1</code>')
            .replace(/\n- /g, '\n• ')
            .replace(/\n/g, '<br>');

        body.innerHTML = `
            <div class="sel-panel-original">"${text}"</div>
            ${html}
        `;

        // Save to history
        try {
            const historyObj = {
                title,
                text,
                html,
                timestamp: Date.now()
            };
            const rawHist = localStorage.getItem('gemini_analysis_history');
            let historyList = rawHist ? JSON.parse(rawHist) : [];
            historyList.unshift(historyObj); // Add to beginning
            if (historyList.length > 20) historyList = historyList.slice(0, 20); // Keep last 20
            localStorage.setItem('gemini_analysis_history', JSON.stringify(historyList));

            // Auto-open Cheatsheet to history tab
            if (typeof window !== 'undefined' && (window as any).toggleCheatsheet) {
                (window as any).toggleCheatsheet('history');
            }
        } catch (e) {
            console.error('Failed to save analysis history', e);
        }
    } catch {
        const body = panel.querySelector('.sel-panel-body') as HTMLElement;
        if (body) body.innerHTML = '<div style="text-align:center;padding:40px;color:var(--red)">❌ Ошибка. Попробуйте ещё раз.</div>';
    }
}

