// Text selection listener
const handleSelection = (e: Event) => {
    setTimeout(() => {
        const selection = window.getSelection();
        const text = selection?.toString().trim();

        if (text && text.length > 0) {
            selectedTextForTTS = text;
            const range = selection?.getRangeAt(0);
            if (range) {
                const rect = range.getBoundingClientRect();
                // Show toolbar slightly above the selection, centered
                showSelToolbar(rect.left + rect.width / 2 - 130, Math.max(10, rect.top + window.scrollY));
            }
        } else {
            if (selToolbar && !(e.target as HTMLElement)?.closest('#sel-toolbar')) {
                hideSelToolbar();
            }
        }
    }, 10);
};

