document.addEventListener('touchend', handleSelection);
document.addEventListener('keyup', (e) => {
    if (e.key === 'Shift' || e.key.startsWith('Arrow')) handleSelection(e);
});

document.addEventListener('scroll', hideSelToolbar);
document.addEventListener('keydown', (e) => {
    if (e.key === 'Escape') { hideSelToolbar(); closeAnalysisPanel(); }
    else hideSelToolbar();
});

console.log('[StreamingDisplay] Module loaded (TS)');
console.log('[Selection Toolbar] 3-button toolbar enabled');

// ============================================================
//  📱 MOBILE SENTENCE TAP-TO-SELECT
// ============================================================
// On mobile, tapping on text in dialogue blocks selects the whole sentence
// (from the previous sentence-ending punctuation to the next one)

if ('ontouchstart' in window) {
    let lastTapTime = 0;

    document.addEventListener('click', (e: MouseEvent) => {
        const target = e.target as HTMLElement;
        if (!target) return;

        // Only works inside dialogue content or message bubbles
        const bubble = target.closest('.message-bubble');
        if (!bubble) return;

        // Skip clicks on buttons, links, and interactive elements
        if (target.closest('button, a, .hint-btn, .tts-play-btn, .warning-continue-btn')) return;

        // Debounce rapid taps
        const now = Date.now();
        if (now - lastTapTime < 300) return;
        lastTapTime = now;

        // Clear previous sentence selection
        document.querySelectorAll('.sentence-selected').forEach(el => {
            el.classList.remove('sentence-selected');
        });

        // Find the text node at click point
        const range = document.caretRangeFromPoint?.(e.clientX, e.clientY);
        if (!range || !range.startContainer || range.startContainer.nodeType !== Node.TEXT_NODE) return;

        const textNode = range.startContainer;
        const fullText = textNode.textContent || '';
        const pos = range.startOffset;

        // Find sentence boundaries (. ! ? or newline)
        const sentenceEnders = /[.!?。？！\n]/;
        let start = pos;
        let end = pos;

        // Walk backward to find sentence start
        while (start > 0 && !sentenceEnders.test(fullText[start - 1])) {
            start--;
        }

        // Walk forward to find sentence end
        while (end < fullText.length && !sentenceEnders.test(fullText[end])) {
            end++;
        }
        // Include the punctuation mark
        if (end < fullText.length && sentenceEnders.test(fullText[end])) {
            end++;
        }

        const sentence = fullText.substring(start, end).trim();
        if (!sentence || sentence.length < 3) return;

        // Select the sentence using Selection API so it can be copied
        try {
            const selection = window.getSelection();
            if (selection) {
                selection.removeAllRanges();
                const selectRange = document.createRange();
                selectRange.setStart(textNode, start);
                selectRange.setEnd(textNode, end);
                selection.addRange(selectRange);
            }
        } catch (err) {
            // Ignore errors in range selection
        }

        // Visual highlight on the karaoke-word spans within the sentence
        const parentEl = textNode.parentElement;
        if (parentEl) {
            parentEl.classList.add('sentence-selected');
            // Auto-remove after 5 seconds
            setTimeout(() => {
                parentEl.classList.remove('sentence-selected');
            }, 5000);
        }
    });

    console.log('[Mobile] Tap-to-select-sentence enabled');
}
