/**
 * SessionLogger — автоматическое логирование сессии в файлы
 * 
 * Логирует:
 * - 💬 CHAT: все сообщения (user + ai)
 * - 🧠 THINK: мысли бота (ai_thinking)
 * - 📤 SENT: что мы отправляем боту (text commands, continuation)
 * - 🔄 AUTO: действия auto-continue/orchestrator
 * - ⚙️ CONFIG: конфигурация сессии
 * 
 * Данные автоматически отправляются на сервер POST /api/log
 * и сохраняются в logs/sessions/{session_id}.txt
 */

interface LogItem {
    time: string;
    type: string;
    data: string;
}

class SessionLoggerModule {
    private sessionId: string = '';
    private buffer: LogItem[] = [];
    private flushTimer: ReturnType<typeof setInterval> | null = null;
    private isActive = false;

    /**
     * Start a new logging session.
     */
    startSession(mode: string, level: string): void {
        // Generate session ID from timestamp
        const now = new Date();
        const pad = (n: number) => n.toString().padStart(2, '0');
        this.sessionId = `${now.getFullYear()}-${pad(now.getMonth() + 1)}-${pad(now.getDate())}_${pad(now.getHours())}-${pad(now.getMinutes())}-${pad(now.getSeconds())}`;

        this.buffer = [];
        this.isActive = true;

        // Log session start
        this.log('CONFIG', `Session started: mode=${mode}, level=${level}`);

        // Flush every 3 seconds
        if (this.flushTimer) clearInterval(this.flushTimer);
        this.flushTimer = setInterval(() => this.flush(), 3000);

        console.log(`[SessionLogger] Started: ${this.sessionId}`);
    }

    /**
     * Log an entry.
     */
    log(type: string, data: string): void {
        if (!this.isActive) return;

        const now = new Date();
        const time = `${now.getHours().toString().padStart(2, '0')}:${now.getMinutes().toString().padStart(2, '0')}:${now.getSeconds().toString().padStart(2, '0')}.${now.getMilliseconds().toString().padStart(3, '0')}`;

        this.buffer.push({ time, type, data });

        // Auto-flush if buffer is large
        if (this.buffer.length >= 20) {
            this.flush();
        }
    }

    // ========== Convenience methods ==========

    /** User said something */
    userMessage(text: string): void {
        this.log('USER', text);
    }

    /** Bot said something (final transcript) */
    aiMessage(text: string): void {
        this.log('AI_CHAT', text.substring(0, 500));
    }

    /** Bot partial text */
    aiPartial(text: string): void {
        // Don't log every partial — too noisy
        // Only log significant chunks
        if (text.length > 30) {
            this.log('AI_PARTIAL', text.substring(0, 200));
        }
    }

    /** Bot thinking */
    aiThinking(text: string): void {
        this.log('THINK', text.substring(0, 500));
    }

    /** We sent a text command to the bot */
    sentCommand(text: string): void {
        this.log('SENT_CMD', text);
    }

    /** Auto-continue triggered */
    autoContinue(delivered: number, expected: number): void {
        this.log('AUTO_CONTINUE', `triggered: ${delivered}/${expected}`);
    }

    /** Manual continue button pressed */
    manualContinue(delivered: number, expected: number): void {
        this.log('MANUAL_CONTINUE', `pressed: ${delivered}/${expected}`);
    }

    /** WebSocket config sent */
    wsConfig(config: any): void {
        this.log('WS_CONFIG', JSON.stringify(config));
    }

    /** Incomplete replicas detected */
    incompleteDetected(delivered: number, promised: number): void {
        this.log('INCOMPLETE', `${delivered}/${promised} items`);
    }

    // ========== Flush to server ==========

    /**
     * Send buffered entries to server.
     */
    private async flush(): Promise<void> {
        if (this.buffer.length === 0) return;
        if (!this.sessionId) return;

        const entries = [...this.buffer];
        this.buffer = [];

        try {
            await fetch('/api/log', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    session_id: this.sessionId,
                    entries: entries,
                }),
            });
        } catch (e) {
            // Silently fail — don't break the app for logging
            console.warn('[SessionLogger] Flush failed:', e);
            // Put entries back
            this.buffer.unshift(...entries);
        }
    }

    /**
     * Stop logging and flush remaining data.
     */
    stopSession(): void {
        this.log('CONFIG', 'Session ended');
        this.flush(); // Final flush

        if (this.flushTimer) {
            clearInterval(this.flushTimer);
            this.flushTimer = null;
        }
        this.isActive = false;

        console.log(`[SessionLogger] Stopped: ${this.sessionId}`);
    }

    get currentSessionId(): string {
        return this.sessionId;
    }
}

export const SessionLogger = new SessionLoggerModule();

if (typeof window !== 'undefined') {
    (window as any).SessionLogger = SessionLogger;
}

console.log('[SessionLogger] Module loaded');
