/**
 * Orchestrator Module v5 — SIMPLIFIED
 * 
 * Role: BACKUP auto-continue only.
 * Primary auto-continue is handled by streaming-display.ts (showIncompleteWarning + 5s timer).
 * This module only fires if the primary system didn't catch it.
 * 
 * Simple logic:
 * - After content phase starts, if turn_complete fires and items < expected → trigger continueBot()
 * - That's it. No complex audio tracking.
 */

type TeacherMode = 'standard' | 'active' | 'grammar' | 'free_conversation';

class OrchestratorModule {
    private isActive = false;
    private mode: TeacherMode = 'standard';
    private expectedCount = 5;
    private isBatch = true;
    private phase: 'greeting' | 'content' = 'greeting';

    startMonitoring(): void {
        const radio = document.querySelector('input[name="teacher-mode"]:checked') as HTMLInputElement;
        this.mode = (radio?.value as TeacherMode) || 'standard';

        const deliveryMode = ((window as any).getDeliveryMode?.() || 'interactive');
        this.isBatch = deliveryMode === 'fast_text';

        switch (this.mode) {
            case 'active': this.expectedCount = 10; break;
            case 'standard': this.expectedCount = 5; break;
            case 'grammar': this.expectedCount = 5; break;
            default: this.expectedCount = 0;
        }

        this.isActive = true;
        this.phase = 'greeting';

        console.log(`[Orchestrator] Started: mode=${this.mode}, expect=${this.expectedCount}, batch=${this.isBatch}`);
    }

    onStreamUpdate(partialText: string): void {
        if (!this.isActive) return;
        // Detect content phase start
        if (this.phase === 'greeting' && /\d+\.\s*(Граммини|Grammini|СОБЕСЕДНИК)/i.test(partialText)) {
            this.phase = 'content';
            console.log(`[Orchestrator] Phase: content`);
        }
    }

    onAudioReceived(): void {
        // No-op in v5 — primary system handles everything
    }

    onStreamFinished(_fullText?: string): void {
        // No-op in v5 — primary auto-continue in streaming-display handles this
    }

    stopMonitoring(): void {
        this.isActive = false;
        console.log('[Orchestrator] Stopped');
    }

    get isContinuing(): boolean { return false; }
    get expectedItemCount(): number { return this.expectedCount; }
}

export const Orchestrator = new OrchestratorModule();

if (typeof window !== 'undefined') {
    (window as any).Orchestrator = Orchestrator;
}

console.log('[Orchestrator] v5 loaded (simplified backup)');
