/**
 * Theme Effects — Rich animated particles per theme
 * Behind content (z-index: -1) — never overlap text
 * Each theme: emoji particles + glowing orbs + light shafts + fireflies
 */

interface ParticleGroup {
    emoji: string;
    count: number;
    sizeRange: [number, number];
    speedRange: [number, number];
}

interface ThemeConfig {
    particles: ParticleGroup[];
    orbs: { color: string; count: number; maxSize: number }[];
    shafts?: { color: string; count: number; width?: number };
    fireflyCount?: number;
    fireflyColor?: string;
    sunburst?: { color: string; x: string; y: string };
}

