import { saveSession, findSessionByLanguage, loadSession, renderSessionList, setCurrentChatId } from '../chat/chat-sessions';

const STORAGE_KEY = 'gemini_target_language';

let isOpen = false;

/** Position a fixed dropdown below its button by teleporting to .app */
function positionDropdown(btn: HTMLElement, dropdown: HTMLElement): void {
    const appContainer = document.querySelector('.app') || document.body;
    // Teleport to .app to escape any stacking context (transforms, overflow) but keep styles
    if (dropdown.parentElement !== appContainer) {
        (dropdown as any).__originalParent = dropdown.parentElement;
        appContainer.appendChild(dropdown);
    }
    requestAnimationFrame(() => {
        const rect = btn.getBoundingClientRect();
        const dropW = Math.max(220, rect.width);
        let left = rect.left;
        if (left + dropW > window.innerWidth - 8) {
            left = window.innerWidth - dropW - 8;
        }
        if (left < 8) left = 8;

        // Vertical: try below first, if overflows show above
        const dropH = dropdown.scrollHeight || 300;
        let top = rect.bottom + 4;
        if (top + dropH > window.innerHeight - 8) {
            // Open above button
            top = rect.top - dropH - 4;
            if (top < 8) top = 8;
        }

        dropdown.style.position = 'fixed';
        dropdown.style.left = `${left}px`;
        dropdown.style.top = `${top}px`;
        dropdown.style.width = `${dropW}px`;
        dropdown.style.zIndex = '99999';
    });
}

/** Return dropdown to its original parent */
function returnDropdown(dropdown: HTMLElement): void {
    const appContainer = document.querySelector('.app') || document.body;
    const originalParent = (dropdown as any).__originalParent as HTMLElement | null;
    if (originalParent && dropdown.parentElement === appContainer) {
        originalParent.appendChild(dropdown);
    }
}

/**
 * Get currently selected language code
 */
export function getTargetLanguage(): string {
    return localStorage.getItem(STORAGE_KEY) || 'German';
}

/**
 * Find language by code
 */
function findLanguage(code: string): Language | undefined {
    return LANGUAGES.find(l => l.code === code);
}

/**
 * Initialize the searchable language picker
 */
export function setupLanguagePicker(): void {
    const btn = document.getElementById('language-picker-btn');
    const dropdown = document.getElementById('language-picker-dropdown');
    const searchInput = document.getElementById('language-search') as HTMLInputElement;
    const list = document.getElementById('language-list');
    const hiddenInput = document.getElementById('target-language') as HTMLInputElement;

    if (!btn || !dropdown || !searchInput || !list || !hiddenInput) return;

    // Restore saved language
    const saved = getTargetLanguage();
    const savedLang = findLanguage(saved);
    if (savedLang) {
        updateButton(btn, savedLang);
        hiddenInput.value = savedLang.code;
    }

    // Render initial list
    renderLanguageList(list, LANGUAGES, hiddenInput, btn, dropdown);

    // Toggle dropdown
    btn.addEventListener('click', (e) => {
        e.stopPropagation();
        isOpen = !isOpen;
        dropdown.classList.toggle('open', isOpen);
        if (isOpen) {
            positionDropdown(btn, dropdown);
            searchInput.value = '';
            renderLanguageList(list, LANGUAGES, hiddenInput, btn, dropdown);
            setTimeout(() => searchInput.focus(), 50);
        }
    });

    // Search filtering
    searchInput.addEventListener('input', () => {
        const query = searchInput.value.toLowerCase().trim();
        const filtered = query
            ? LANGUAGES.filter(l =>
                l.name.toLowerCase().includes(query) ||
                l.nameEn.toLowerCase().includes(query) ||
                l.code.toLowerCase().includes(query)
            )
            : LANGUAGES;
        renderLanguageList(list, filtered, hiddenInput, btn, dropdown);
    });

    // Prevent search input click from closing dropdown
    searchInput.addEventListener('click', (e) => e.stopPropagation());

    // Close on outside click
    document.addEventListener('click', () => {
        if (isOpen) {
            isOpen = false;
            dropdown.classList.remove('open');
        }
    });

    // Close on Escape
    document.addEventListener('keydown', (e) => {
        if (e.key === 'Escape' && isOpen) {
            isOpen = false;
            dropdown.classList.remove('open');
        }
    });
}

function updateButton(btn: HTMLElement, lang: Language): void {
    const flag = btn.querySelector('.lang-flag');
    const name = btn.querySelector('.lang-name');
    if (flag) flag.textContent = lang.flag;
    if (name) name.textContent = lang.name;
}

function renderLanguageList(
    list: HTMLElement,
    languages: Language[],
    hiddenInput: HTMLInputElement,
    btn: HTMLElement,
    dropdown: HTMLElement
): void {
    const current = getTargetLanguage();

    // Sort: available languages first, then coming soon
    const sorted = [...languages].sort((a, b) => {
        if (a.available && !b.available) return -1;
        if (!a.available && b.available) return 1;
        return 0;
    });

    list.innerHTML = sorted.map(lang => `
        <div class="language-item ${lang.code === current ? 'selected' : ''} ${!lang.available ? 'disabled' : ''}" data-code="${lang.code}" ${!lang.available ? 'title="Coming soon — curriculum in development"' : ''}>
            <span class="lang-item-flag">${lang.flag}</span>
            <span class="lang-item-name">${lang.name}</span>
            <span class="lang-item-en">${lang.nameEn}</span>
            ${!lang.available ? '<span class="lang-coming-soon">Coming soon</span>' : ''}
        </div>
    `).join('');

    // Attach click handlers (only to available languages)
    list.querySelectorAll('.language-item:not(.disabled)').forEach(item => {
        item.addEventListener('click', async (e) => {
            e.stopPropagation();
            const code = (item as HTMLElement).dataset.code!;
            const lang = findLanguage(code);
            if (!lang) return;

            // Update UI
            updateButton(btn, lang);
            hiddenInput.value = lang.code;

            // Save to localStorage
            localStorage.setItem(STORAGE_KEY, lang.code);

            // Close dropdown
            isOpen = false;
            dropdown.classList.remove('open');

            // Sync to backend DB
            try {
                await fetch('/api/profile?user_id=default', {
                    method: 'PUT',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify({ target_language: lang.code })
                });
                console.log('[Language] Updated DB target_language to:', lang.code);
            } catch (err) {
                console.error('[Language] Failed to update profile:', err);
            }

            // === PER-LANGUAGE CHAT SESSION SWITCHING ===
            // Find existing chat for this language, or create one
            const existingChat = findSessionByLanguage(lang.code);
            if (existingChat) {
                // Switch to existing chat for this language
                console.log(`[Language] Found existing chat for ${lang.code}:`, existingChat.id);
                loadSession(existingChat.id);
            } else {
                // Create a new chat session for this language with mode/level info
                const chatId = `${lang.code.toLowerCase()}_${Date.now()}`;
                const modeSelect = document.getElementById('teacher-mode') as HTMLSelectElement;
                const levelSelect = document.getElementById('level') as HTMLSelectElement;
                const currentMode = modeSelect?.value || 'standard';
                const currentLevel = levelSelect?.value || 'A1';
                saveSession(chatId, `${lang.flag} ${lang.name}`, lang.code, currentMode, currentLevel);
                setCurrentChatId(chatId);
                console.log(`[Language] Created new chat for ${lang.code}: ${chatId} (${currentMode}/${currentLevel})`);

                // Clear the chat display for the new session
                const chatMessages = document.getElementById('chat-messages');
                if (chatMessages) chatMessages.innerHTML = '';
            }

            renderSessionList();

            // 🌍 ALWAYS force reconnect on language change
            // Backend reads target_language from DB, so we need a full reconnect
            // to rebuild system instructions with the new language

            // Clear old session memory
            try {
                await fetch('/api/clear-session', { method: 'POST' });
                console.log('[Language] Cleared backend session');
            } catch (_) { /* ignore */ }

            StreamingDisplay.hardReset();

            // Show notification
            const chatMessages = document.getElementById('chat-messages');
            if (chatMessages) {
                const notif = document.createElement('div');
                notif.className = 'system-message mode-change-notice';
                notif.innerHTML = `🌍 Switching to <strong>${lang.flag} ${lang.name}</strong>...`;
                notif.style.cssText = 'background: rgba(59, 130, 246, 0.2); border: 1px solid #3b82f6; padding: 10px; margin: 10px 0; border-radius: 8px; text-align: center;';
                chatMessages.appendChild(notif);
            }

            // Stop any active connection
            const state = getState();
            if (state.isConnected || (state.ws && state.ws.readyState !== WebSocket.CLOSED)) {
                stopConversation();
            }

            // Auto-reconnect with new language (backend reads from DB)
            console.log('[Language] Reconnecting in 1.2s with', lang.code);
            setTimeout(() => startConversation('voice'), 1200);
        });
    });
}

const NATIVE_STORAGE_KEY = 'gemini_native_language';
let isNativeOpen = false;

/**
 * Get currently selected native language code
 */
export function getNativeLanguage(): string {
    return localStorage.getItem(NATIVE_STORAGE_KEY) || 'Russian';
}

/**
 * Initialize the searchable native language picker
 */
export function setupNativeLanguagePicker(): void {
    const btn = document.getElementById('native-language-picker-btn');
    const dropdown = document.getElementById('native-language-picker-dropdown');
    const searchInput = document.getElementById('native-language-search') as HTMLInputElement;
    const list = document.getElementById('native-language-list');
    const hiddenInput = document.getElementById('native-language') as HTMLInputElement;

    if (!btn || !dropdown || !searchInput || !list || !hiddenInput) return;

    // Restore saved language
    const saved = getNativeLanguage();
    const savedLang = findLanguage(saved);
    if (savedLang) {
        updateButton(btn, savedLang);
        hiddenInput.value = savedLang.code;
    }

    // For native language ALL languages are selectable
    const renderNativeList = (langs: Language[]) => {
        const current = getNativeLanguage();
        list.innerHTML = langs.map(lang => `
            <div class="language-item ${lang.code === current ? 'selected' : ''}" data-code="${lang.code}">
                <span class="lang-item-flag">${lang.flag}</span>
                <span class="lang-item-name">${lang.name}</span>
                <span class="lang-item-en">${lang.nameEn}</span>
            </div>
        `).join('');

        list.querySelectorAll('.language-item').forEach(item => {
            item.addEventListener('click', async (e) => {
                e.stopPropagation();
                const code = (item as HTMLElement).dataset.code!;
                const lang = findLanguage(code);
                if (!lang) return;

                updateButton(btn, lang);
                hiddenInput.value = lang.code;
                localStorage.setItem(NATIVE_STORAGE_KEY, lang.code);

                isNativeOpen = false;
                dropdown.classList.remove('open');
                console.log('[NativeLang] Set to:', lang.code);

                // 🔄 Update backend DB so {NATIVE_LANG} placeholder changes
                try {
                    await fetch('/api/profile?user_id=default', {
                        method: 'PUT',
                        headers: { 'Content-Type': 'application/json' },
                        body: JSON.stringify({ native_language: lang.code })
                    });
                    console.log('[NativeLang] Updated DB native_language to:', lang.code);
                } catch (err) {
                    console.error('[NativeLang] Failed to update profile:', err);
                }

                // 🔄 Force reconnect ONLY if already connected, to rebuild instructions with new native language
                const state = getState();
                if (state.isConnected || (state.ws && state.ws.readyState !== WebSocket.CLOSED)) {
                    const reconnectMode = 'voice';
                    stopConversation();
                    StreamingDisplay.hardReset();
                    console.log('[NativeLang] Reconnecting with new native language:', lang.code);
                    setTimeout(() => startConversation(reconnectMode), 1200);
                } else {
                    console.log('[NativeLang] Not connected, skipping reconnect');
                }
            });
        });
    };

    // Render initial list
    renderNativeList(LANGUAGES);

    // Toggle dropdown
    btn.addEventListener('click', (e) => {
        e.stopPropagation();
        isNativeOpen = !isNativeOpen;
        dropdown.classList.toggle('open', isNativeOpen);
        if (isNativeOpen) {
            positionDropdown(btn, dropdown);
            searchInput.value = '';
            renderNativeList(LANGUAGES);
            setTimeout(() => searchInput.focus(), 50);
        }
    });

    // Search filtering
    searchInput.addEventListener('input', () => {
        const query = searchInput.value.toLowerCase().trim();
        const filtered = query
            ? LANGUAGES.filter(l =>
                l.name.toLowerCase().includes(query) ||
                l.nameEn.toLowerCase().includes(query) ||
                l.code.toLowerCase().includes(query)
            )
            : LANGUAGES;
        renderNativeList(filtered);
    });

    // Prevent search input click from closing dropdown
    searchInput.addEventListener('click', (e) => e.stopPropagation());

    // Close on outside click
    document.addEventListener('click', () => {
        if (isNativeOpen) {
            isNativeOpen = false;
            dropdown.classList.remove('open');
        }
    });

    // Close on Escape
    document.addEventListener('keydown', (e) => {
        if (e.key === 'Escape' && isNativeOpen) {
            isNativeOpen = false;
            dropdown.classList.remove('open');
        }
    });
}

export const LanguagePicker = {
    setup: setupLanguagePicker,
    setupNative: setupNativeLanguagePicker,
    getTargetLanguage,
    getNativeLanguage,
    LANGUAGES,
};
