// ========== APP INITIALIZATION ==========

function initApp(): void {
    console.log('[App] Initializing TypeScript application...');

    // Initialize elements
    initElements();
    const elements = getElements();

    // Load settings
    Settings.load();

    // Sync localStorage level + target language to backend DB on startup
    const savedLevel = localStorage.getItem('gemini_level');
    const savedLang = LanguagePicker.getTargetLanguage();
    const syncPayload: Record<string, string> = {};
    if (savedLevel) syncPayload.level = savedLevel;
    if (savedLang) syncPayload.target_language = savedLang;
    if (Object.keys(syncPayload).length > 0) {
        fetch('/api/profile?user_id=default', {
            method: 'PUT',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(syncPayload)
        }).then(() => {
            console.log('[Startup] DB sync: level=', savedLevel, 'lang=', savedLang);
        }).catch(err => console.error('[Startup] DB sync failed:', err));
    }

    // Setup chat event listeners
    Chat.initListeners();
    Chat.initScrollListener();

    // Setup event handlers
    setupEventHandlers(elements);

    // Load progress
    Vocabulary.refreshProgress();
    Vocabulary.loadLearnedWords();

    // Load chat sessions from localStorage
    initChatSessions();

    // Initialize grammar cheatsheet button
    initCheatsheet();

    // Initialize language picker (searchable dropdown)
    LanguagePicker.setup();
    LanguagePicker.setupNative();

    // Initialize i18n (translations) — BEFORE tooltips so labels are already translated
    initI18n();

    // Initialize tooltip hints ("?" buttons)
    initTooltips();

    // Initialize tutorial / onboarding
    initTutorial();

    // Initialize mobile periodic hints
    initMobileHints();

    // Initialize delivery mode radios (replaces old batch toggle)
    const deliveryHint = document.getElementById('delivery-mode-hint');
    
    function getDeliveryMode(): string {
        return (document.querySelector('input[name="delivery-mode"]:checked') as HTMLInputElement)?.value || 'interactive';
    }
    // Expose globally for other modules
    (window as any).getDeliveryMode = getDeliveryMode;
    
    function updateDeliveryHint() {
        if (!deliveryHint) return;
        const mode = getDeliveryMode();
        switch (mode) {
            case 'interactive': deliveryHint.textContent = 'Интерактивный диалог'; break;
            case 'fast_text': deliveryHint.textContent = '1 голосом + 9 текстом'; break;
            case 'auto_10': deliveryHint.textContent = 'Все 10 голосом подряд'; break;
        }
    }
    
    // Load saved preference
    const savedDelivery = localStorage.getItem('delivery_mode');
    if (savedDelivery) {
        const radio = document.querySelector(`input[name="delivery-mode"][value="${savedDelivery}"]`) as HTMLInputElement;
        if (radio) radio.checked = true;
    }
    updateDeliveryHint();
    
    // Save on change
    document.querySelectorAll('input[name="delivery-mode"]').forEach(radio => {
        radio.addEventListener('change', () => {
            localStorage.setItem('delivery_mode', getDeliveryMode());
            updateDeliveryHint();
        });
    });


    console.log('[App] TypeScript modules initialized');

    // Make enrichDialogueBlocks globally available for streaming-display
    import('./modules/chat/enrichment').then(m => {
        (window as any).enrichDialogueBlocks = m.enrichDialogueBlocks;
        console.log('[App] Enrichment observer attached to window');
    });

    // Register global quiz answer reveal function
    (window as any).revealQuizAnswer = (element: HTMLElement) => {
        if (element.classList.contains('answered')) return;

        // Get the question text (remove the reveal hint)
        const questionText = element.textContent?.replace('👆 нажми', '').trim() || '';

        // Mark as answered
        element.classList.add('answered');

        // Remove the reveal hint
        const hint = element.querySelector('.quiz-reveal-hint');
        if (hint) hint.remove();

        // Send as user message to get the answer
        const textInput = document.getElementById('text-input') as HTMLTextAreaElement;
        if (textInput) {
            textInput.value = questionText;
            Chat.sendTextMessage();
        }
    };

    // Register mobile sidebar togglers
    (window as any).openMobileSidebar = (side: 'left' | 'right') => {
        const sidebar = document.getElementById(`sidebar-${side}`);
        const overlay = document.getElementById('mobile-overlay');

        if (sidebar) {
            if (sidebar.classList.contains('mobile-open')) {
                sidebar.classList.remove('mobile-open');
                if (overlay) overlay.classList.remove('active');
            } else {
                sidebar.classList.add('mobile-open');
                if (overlay) overlay.classList.add('active');
            }
        }
    };

    (window as any).closeMobileSidebars = () => {
        const sidebarLeft = document.getElementById('sidebar-left');
        const sidebarRight = document.getElementById('sidebar-right');
        const overlay = document.getElementById('mobile-overlay');
        if (sidebarLeft) sidebarLeft.classList.remove('mobile-open');
        if (sidebarRight) sidebarRight.classList.remove('mobile-open');
        if (overlay) overlay.classList.remove('active');
    };
}

// ========== EVENT HANDLERS ==========

function setupEventHandlers(elements: ReturnType<typeof getElements>): void {
    // Mode buttons
    document.getElementById('btn-voice')?.addEventListener('click', () => startConversation('voice'));
    document.getElementById('btn-screen')?.addEventListener('click', () => startConversation('screen'));
    document.getElementById('btn-camera')?.addEventListener('click', () => startConversation('camera'));

    // Stop button
    document.getElementById('stop-btn')?.addEventListener('click', () => stopConversation(true));

    // Skip button - interrupt bot speech to start talking
    const skipBtn = document.getElementById('skip-speech-btn');
    skipBtn?.addEventListener('click', () => {
        // Use skipPlayback (soft stop) — cancels scheduled audio BUT keeps AudioContext alive
        // This is critical: stop() destroys AudioContext, which kills ALL future audio!
        if ((window as any).AudioPlayback) {
            (window as any).AudioPlayback.skipPlayback();
        }
        // Reset isPlaying state so AudioCapture stops suppressing mic input
        setState({ isPlaying: false });
        // ⚠️ CRITICAL: Finalize BEFORE reset to save accumulated text to conversation history
        // Without this, Gemini doesn't know what topics were covered and REPEATS them
        StreamingDisplay.finalize('ai', '');
        // Reset streaming display (clear any partial AI text)
        StreamingDisplay.reset();
        // Trigger observer bot text enrichment since the turn is officially over (passing true for isTurnComplete)
        StreamingDisplay.triggerEnrichment(true);
        // Visual feedback
        skipBtn.classList.remove('speaking');
        console.log('[Skip] Bot speech interrupted — text saved to history, mic re-enabled');
    });

    // === GLOBAL CONTINUE BOT FUNCTION ===
    // Continuation Logic is now handled seamlessly by Observer Bot in enrichment.ts
    // Mute microphone button (for practice mode)
    const muteBtn = document.getElementById('mute-mic-btn');
    muteBtn?.addEventListener('click', () => {
        const isMuted = muteBtn.classList.toggle('muted');
        // Show crossed microphone when muted, normal mic when unmuted
        muteBtn.textContent = isMuted ? '🚫🎙️' : '🎙️';
        muteBtn.title = isMuted ? 'Включить микрофон' : 'Заглушить микрофон (режим практики)';
        // Direct call to AudioCapture
        if ((window as any).AudioCapture) {
            (window as any).AudioCapture.setMicMute(isMuted);
        }
    });

    // Mute voice button (mute AI voice output)
    const muteVoiceBtn = document.getElementById('mute-voice-btn');
    const volumeSlider = document.getElementById('volume-slider') as HTMLInputElement;

    // Load saved volume from localStorage, default to 100
    let savedVolume = parseInt(localStorage.getItem('app_volume') || '100', 10);
    if (volumeSlider) {
        volumeSlider.value = String(savedVolume);
    }

    muteVoiceBtn?.addEventListener('click', () => {
        const isMuted = muteVoiceBtn.classList.toggle('muted');
        if (isMuted) {
            savedVolume = parseInt(volumeSlider?.value || '100', 10);
            if (volumeSlider) volumeSlider.value = '0';
            muteVoiceBtn.textContent = '🔇';
            muteVoiceBtn.title = 'Включить голос бота';
        } else {
            if (volumeSlider) volumeSlider.value = String(savedVolume);
            muteVoiceBtn.textContent = '🔊';
            muteVoiceBtn.title = 'Заглушить голос бота';
        }
        const volume = parseInt(volumeSlider?.value || '100', 10);
        if ((window as any).AudioPlayback) {
            (window as any).AudioPlayback.setVolume(volume / 100);
        }
    });

    // Volume slider
    volumeSlider?.addEventListener('input', () => {
        const volume = parseInt(volumeSlider.value, 10);
        // Save to localStorage
        localStorage.setItem('app_volume', String(volume));

        // Update speaker icon based on volume
        if (muteVoiceBtn) {
            muteVoiceBtn.textContent = volume === 0 ? '🔇' : volume < 50 ? '🔉' : '🔊';
            if (volume === 0) {
                muteVoiceBtn.classList.add('muted');
            } else {
                muteVoiceBtn.classList.remove('muted');
            }
        }
        // Direct call to AudioPlayback
        if ((window as any).AudioPlayback) {
            (window as any).AudioPlayback.setVolume(volume / 100);
        }
    });

    // German-only mode toggle (don't speak Russian translations)
    const germanOnlyBtn = document.getElementById('german-only-btn');
    // Load saved state
    const savedGermanOnly = localStorage.getItem('germanOnlyMode') === 'true';
    if (savedGermanOnly && germanOnlyBtn) {
        germanOnlyBtn.classList.add('active');
        germanOnlyBtn.textContent = '🇩🇪✓';
        (window as any).germanOnlyMode = true;
    }
    germanOnlyBtn?.addEventListener('click', () => {
        const isActive = germanOnlyBtn.classList.toggle('active');
        germanOnlyBtn.textContent = isActive ? '🇩🇪✓' : '🇩🇪';
        germanOnlyBtn.title = isActive
            ? 'Режим: только немецкий ВКЛ (нажми чтоб выключить)'
            : 'Режим: только немецкий (не озвучивать русский)';

        // Save state
        localStorage.setItem('germanOnlyMode', String(isActive));
        (window as any).germanOnlyMode = isActive;

        // Send instruction to Gemini if connected
        const WsController = (window as any).WsController;
        if (WsController?.isConnected?.()) {
            const message = isActive
                ? '[SYSTEM] ВАЖНО: С этого момента говори ТОЛЬКО по-немецки! Русские переводы ПИШИ в скобках, но НЕ ОЗВУЧИВАЙ. Говори только немецкий текст!'
                : '[SYSTEM] Можешь снова озвучивать русские переводы вместе с немецким.';
            WsController.sendText(message);
            console.log('[GermanOnly]', isActive ? 'Enabled' : 'Disabled');
        }
    });

    // Save settings
    elements.saveBtn?.addEventListener('click', Settings.save);

    // Theme change
    Settings.setupThemeListener();
    Settings.setupBgToggle();

    // Teacher mode (standard/active/grammar) toggle
    Settings.setupTeacherModeListener();

    // Speech rate slider
    Settings.setupSpeechRateListener();
    // API keys
    Settings.setupApiKeyListeners();

    // Send text
    elements.sendBtn?.addEventListener('click', Chat.sendTextMessage);
    elements.textInput?.addEventListener('keypress', (e) => {
        if (e.key === 'Enter' && !e.shiftKey) {
            e.preventDefault();
            Chat.sendTextMessage();
        }
    });

    // File attachments
    elements.attachBtn?.addEventListener('click', () => elements.fileInput?.click());
    elements.fileInput?.addEventListener('change', handleFileSelect);

    // New chat
    elements.newChatBtn?.addEventListener('click', newChat);

    // Sidebar collapse
    setupSidebarCollapse();

    // Video controls
    setupVideoControls();

    // Progress widget
    setupProgressWidget();

    // Draggable floating widget
    setupDraggableWidget();

    // Close context menu on click
    document.addEventListener('click', () => {
        elements.contextMenu?.classList.add('hidden');
    });
}

// ========== DRAGGABLE WIDGET ==========

function setupDraggableWidget(): void {
    const widget = document.getElementById('floating-widget');
    const handle = document.getElementById('widget-drag-handle');
    if (!widget || !handle) return;

    // Ensure widget is visible
    widget.classList.remove('hidden');
    widget.style.display = 'flex';

    // Restore saved position (with bounds check)
    const savedPos = localStorage.getItem('widget-position');
    if (savedPos) {
        try {
            const { x, y } = JSON.parse(savedPos);
            // Check if saved position is within current viewport
            const maxX = window.innerWidth - 100;
            const maxY = window.innerHeight - 50;
            if (x >= 0 && x <= maxX && y >= 0 && y <= maxY) {
                widget.style.left = `${x}px`;
                widget.style.top = `${y}px`;
                widget.style.right = 'auto';
                widget.style.bottom = 'auto';
            } else {
                // Reset to default position if out of bounds
                console.log('[Widget] Saved position out of bounds, resetting');
                localStorage.removeItem('widget-position');
            }
        } catch (e) {
            console.log('[Widget] Failed to restore position');
            localStorage.removeItem('widget-position');
        }
    }

    let isDragging = false;
    let startX = 0, startY = 0;
    let initialX = 0, initialY = 0;

    const startDrag = (clientX: number, clientY: number) => {
        isDragging = true;
        const rect = widget.getBoundingClientRect();
        startX = clientX;
        startY = clientY;
        initialX = rect.left;
        initialY = rect.top;
        handle.style.cursor = 'grabbing';
    };

    const doDrag = (clientX: number, clientY: number) => {
        if (!isDragging) return;

        const dx = clientX - startX;
        const dy = clientY - startY;

        let newX = initialX + dx;
        let newY = initialY + dy;

        // Keep in bounds
        newX = Math.max(0, Math.min(window.innerWidth - widget.offsetWidth, newX));
        newY = Math.max(0, Math.min(window.innerHeight - widget.offsetHeight, newY));

        widget.style.left = `${newX}px`;
        widget.style.top = `${newY}px`;
        widget.style.right = 'auto';
        widget.style.bottom = 'auto';
    };

    const endDrag = () => {
        if (!isDragging) return;
        isDragging = false;
        handle.style.cursor = 'grab';

        // Save position
        const rect = widget.getBoundingClientRect();
        localStorage.setItem('widget-position', JSON.stringify({ x: rect.left, y: rect.top }));
    };

    // Mouse events
    handle.addEventListener('mousedown', (e) => {
        e.preventDefault();
        startDrag(e.clientX, e.clientY);
    });
    document.addEventListener('mousemove', (e) => doDrag(e.clientX, e.clientY));
    document.addEventListener('mouseup', endDrag);

    // Touch events
    handle.addEventListener('touchstart', (e) => {
        const touch = e.touches[0];
        startDrag(touch.clientX, touch.clientY);
    }, { passive: true });
    document.addEventListener('touchmove', (e) => {
        const touch = e.touches[0];
        doDrag(touch.clientX, touch.clientY);
    }, { passive: true });
    document.addEventListener('touchend', endDrag);
}

// ========== FILE HANDLING ==========

function handleFileSelect(e: Event): void {
    const input = e.target as HTMLInputElement;
    const files = Array.from(input.files || []);
    const state = getState();

    files.forEach(file => {
        const reader = new FileReader();
        reader.onload = (ev) => {
            const result = ev.target?.result as string;
            const base64 = result.split(',')[1];
            state.pendingAttachments.push({
                name: file.name,
                type: file.type,
                data: base64,
                preview: file.type.startsWith('image/') ? result : null
            });
            updateAttachmentsPreview();
        };
        reader.readAsDataURL(file);
    });

    input.value = '';
}

function updateAttachmentsPreview(): void {
    const container = document.getElementById('attachments-preview');
    const state = getState();

    if (!container) return;

    if (state.pendingAttachments.length === 0) {
        container.innerHTML = '';
        container.classList.add('hidden');
        return;
    }

    container.classList.remove('hidden');
    container.innerHTML = state.pendingAttachments.map((att, i) => `
        <div class="attachment-chip">
            ${att.preview ? `<img src="${att.preview}" class="attachment-thumb">` : ''}
            <span>${att.name}</span>
            <button onclick="removeAttachment(${i})" class="remove-attachment">×</button>
        </div>
    `).join('');
}

// Make removeAttachment global
(window as any).removeAttachment = function (index: number): void {
    const state = getState();
    state.pendingAttachments.splice(index, 1);
    updateAttachmentsPreview();
};

// ========== CHAT MANAGEMENT ==========

function newChat(): void {
    Chat.clearMessages();
    const newChatId = crypto.randomUUID();
    setState({
        conversationHistory: [],
        currentChatId: newChatId
    });
    // Also update localStorage
    localStorage.setItem('gemini_current_chat_id', newChatId);
    clearAttachments();
    updateAttachmentsPreview();
    Notifications.showToast('Новый чат создан', 2000);
}

// ========== SIDEBAR ==========

function setupSidebarCollapse(): void {
    const SIDEBAR_STATE_KEY = 'sidebar_state';
    const SIDEBAR_WIDTH_KEY = 'sidebar_widths';

    // Restore saved state
    const savedState = JSON.parse(localStorage.getItem(SIDEBAR_STATE_KEY) || '{}');
    const savedWidths = JSON.parse(localStorage.getItem(SIDEBAR_WIDTH_KEY) || '{}');

    const MIN_SIDEBAR = 150;

    // Apply saved widths via CSS custom properties (enforce minimum)
    const app = document.querySelector('.app') as HTMLElement;
    if (savedWidths.left && app) {
        const w = Math.max(MIN_SIDEBAR, savedWidths.left);
        app.style.setProperty('--sidebar-left-width', w + 'px');
    }
    if (savedWidths.right && app) {
        const w = Math.max(MIN_SIDEBAR, savedWidths.right);
        app.style.setProperty('--sidebar-right-width', w + 'px');
    }

    // Restore collapsed state
    if (savedState.leftCollapsed) {
        document.querySelector('.app')?.classList.add('left-collapsed');
        createShowButton('left');
    }
    if (savedState.rightCollapsed) {
        document.querySelector('.app')?.classList.add('right-collapsed');
        createShowButton('right');
    }

    // Save state helper
    const saveSidebarState = () => {
        const appEl = document.querySelector('.app');
        localStorage.setItem(SIDEBAR_STATE_KEY, JSON.stringify({
            leftCollapsed: appEl?.classList.contains('left-collapsed') || false,
            rightCollapsed: appEl?.classList.contains('right-collapsed') || false,
        }));
    };

    // Hide buttons with persistence (handle mobile vs desktop)
    document.getElementById('hide-left-btn')?.addEventListener('click', () => {
        if (window.innerWidth <= 900) {
            (window as any).closeMobileSidebars?.();
        } else {
            document.querySelector('.app')?.classList.add('left-collapsed');
            createShowButton('left');
            saveSidebarState();
        }
    });

    document.getElementById('hide-right-btn')?.addEventListener('click', () => {
        if (window.innerWidth <= 900) {
            (window as any).closeMobileSidebars?.();
        } else {
            document.querySelector('.app')?.classList.add('right-collapsed');
            createShowButton('right');
            saveSidebarState();
        }
    });

    // Expose saveSidebarState for createShowButton
    (window as any)._saveSidebarState = saveSidebarState;

    // === Drag-to-Resize Handles ===
    const leftSidebar = document.getElementById('sidebar-left');
    const rightSidebar = document.getElementById('sidebar-right');

    function createDragHandle(sidebar: HTMLElement, side: 'left' | 'right'): void {
        const handle = document.createElement('div');
        handle.className = `sidebar-drag-handle sidebar-drag-${side}`;
        handle.title = 'Потяните для изменения ширины';
        sidebar.appendChild(handle);

        let startX = 0;
        let startWidth = 0;
        let isDragging = false;

        handle.addEventListener('mousedown', (e: MouseEvent) => {
            e.preventDefault();
            isDragging = true;
            startX = e.clientX;
            startWidth = sidebar.offsetWidth;
            document.body.style.cursor = 'col-resize';
            document.body.style.userSelect = 'none';
            handle.classList.add('active');
        });

        document.addEventListener('mousemove', (e: MouseEvent) => {
            if (!isDragging) return;
            const MIN_W = 150, MAX_W = 500;
            let newWidth: number;
            if (side === 'left') {
                newWidth = startWidth + (e.clientX - startX);
            } else {
                newWidth = startWidth - (e.clientX - startX);
            }
            newWidth = Math.max(MIN_W, Math.min(MAX_W, newWidth));
            const cssVar = side === 'left' ? '--sidebar-left-width' : '--sidebar-right-width';
            app?.style.setProperty(cssVar, newWidth + 'px');
        });

        document.addEventListener('mouseup', () => {
            if (!isDragging) return;
            isDragging = false;
            document.body.style.cursor = '';
            document.body.style.userSelect = '';
            handle.classList.remove('active');

            // Save widths
            const widths: Record<string, number> = JSON.parse(localStorage.getItem(SIDEBAR_WIDTH_KEY) || '{}');
            if (side === 'left' && leftSidebar) widths.left = leftSidebar.offsetWidth;
            if (side === 'right' && rightSidebar) widths.right = rightSidebar.offsetWidth;
            localStorage.setItem(SIDEBAR_WIDTH_KEY, JSON.stringify(widths));
        });
    }

    if (leftSidebar) createDragHandle(leftSidebar, 'left');
    if (rightSidebar) createDragHandle(rightSidebar, 'right');
}

function createShowButton(side: 'left' | 'right'): void {
    const existing = document.getElementById(`show-${side}-btn`);
    if (existing) return;

    const btn = document.createElement('button');
    btn.id = `show-${side}-btn`;
    btn.className = `show-sidebar-btn ${side}`;
    btn.textContent = side === 'left' ? '→' : '←';
    btn.addEventListener('click', () => {
        document.querySelector('.app')?.classList.remove(`${side}-collapsed`);
        btn.remove();
        // Save state after restoring sidebar
        if ((window as any)._saveSidebarState) {
            (window as any)._saveSidebarState();
        }
    });
    document.body.appendChild(btn);
}

// ========== VIDEO CONTROLS ==========

function setupVideoControls(): void {
    const elements = getElements();
    const videoSection = elements.videoSection;
    if (!videoSection) return;

    const toggleBtn = document.getElementById('toggle-video');
    const fullscreenBtn = document.getElementById('video-fullscreen');
    const hideBtn = document.getElementById('hide-video');
    const showBtn = document.getElementById('show-video-btn');
    const videoBody = document.getElementById('video-body');
    const dragHandle = videoSection.querySelector('.drag-handle');

    // Toggle minimize
    toggleBtn?.addEventListener('click', () => {
        videoBody?.classList.toggle('minimized');
        if (toggleBtn) toggleBtn.textContent = videoBody?.classList.contains('minimized') ? '+' : '−';
    });

    // Hide video
    hideBtn?.addEventListener('click', () => {
        videoSection.classList.add('video-hidden');
        showBtn?.classList.remove('hidden');
    });

    // Show video
    showBtn?.addEventListener('click', () => {
        videoSection.classList.remove('video-hidden');
        showBtn?.classList.add('hidden');
    });

    // Fullscreen
    fullscreenBtn?.addEventListener('click', () => {
        videoSection.classList.toggle('video-fullscreen');
    });

    // Drag functionality
    setupDrag(videoSection, dragHandle as HTMLElement | null);
}

function setupDrag(videoSection: HTMLElement, dragHandle: HTMLElement | null): void {
    if (!dragHandle) return;

    let isDragging = false;
    let offsetX = 0, offsetY = 0;

    const startDrag = (clientX: number, clientY: number) => {
        if (videoSection.classList.contains('video-fullscreen')) return;
        isDragging = true;
        videoSection.classList.add('dragging');
        const rect = videoSection.getBoundingClientRect();
        offsetX = clientX - rect.left;
        offsetY = clientY - rect.top;
        videoSection.style.position = 'fixed';
        videoSection.style.left = `${rect.left}px`;
        videoSection.style.top = `${rect.top}px`;
        videoSection.style.right = 'auto';
        videoSection.style.bottom = 'auto';
    };

    const moveDrag = (clientX: number, clientY: number) => {
        if (!isDragging) return;
        const maxX = window.innerWidth - videoSection.offsetWidth;
        const maxY = window.innerHeight - videoSection.offsetHeight;
        videoSection.style.left = `${Math.max(0, Math.min(clientX - offsetX, maxX))}px`;
        videoSection.style.top = `${Math.max(0, Math.min(clientY - offsetY, maxY))}px`;
    };

    const endDrag = () => {
        isDragging = false;
        videoSection.classList.remove('dragging');
    };

    // Mouse events
    dragHandle.addEventListener('mousedown', (e) => { e.preventDefault(); startDrag(e.clientX, e.clientY); });
    document.addEventListener('mousemove', (e) => moveDrag(e.clientX, e.clientY));
    document.addEventListener('mouseup', endDrag);

    // Touch events
    dragHandle.addEventListener('touchstart', (e) => { e.preventDefault(); startDrag(e.touches[0].clientX, e.touches[0].clientY); }, { passive: false });
    document.addEventListener('touchmove', (e) => { if (isDragging) { e.preventDefault(); moveDrag(e.touches[0].clientX, e.touches[0].clientY); } }, { passive: false });
    document.addEventListener('touchend', endDrag);
}

// ========== PROGRESS WIDGET ==========

let progressAutoCloseTimer: ReturnType<typeof setTimeout> | null = null;

function setupProgressWidget(): void {
    // Progress section collapse/expand
    const progressSection = document.querySelector('.progress-section') as HTMLElement;
    if (progressSection) {
        const progressLabel = progressSection.querySelector('label') as HTMLElement;
        const progressWidget = progressSection.querySelector('#progress-widget') as HTMLElement;
        const progressActions = progressSection.querySelector('.progress-actions-row') as HTMLElement;

        // Add collapse arrow indicator
        let arrowSpan: HTMLSpanElement | null = null;
        if (progressLabel) {
            arrowSpan = document.createElement('span');
            arrowSpan.className = 'progress-collapse-arrow';
            arrowSpan.textContent = ' ▸';
            arrowSpan.style.cssText = 'font-size: 10px; opacity: 0.7; transition: transform 0.2s; display: inline-block;';
            progressLabel.appendChild(arrowSpan);
        }

        // Start collapsed
        if (progressWidget) progressWidget.style.display = 'none';
        if (progressActions) progressActions.style.display = 'none';
        if (progressLabel) {
            progressLabel.style.cursor = 'pointer';
            progressLabel.title = 'Click to expand';
            progressLabel.addEventListener('click', (e) => {
                // Ignore clicks on tooltip ? button inside the label
                if ((e.target as HTMLElement).classList.contains('tooltip-hint-btn')) return;

                const isHidden = progressWidget?.style.display === 'none';
                if (progressWidget) progressWidget.style.display = isHidden ? '' : 'none';
                if (progressActions) progressActions.style.display = isHidden ? '' : 'none';

                // Update arrow
                if (arrowSpan) arrowSpan.textContent = isHidden ? ' ▾' : ' ▸';

                // Auto-close after 10 seconds if opened
                if (isHidden) {
                    if (progressAutoCloseTimer) clearTimeout(progressAutoCloseTimer);
                    progressAutoCloseTimer = setTimeout(() => {
                        if (progressWidget) progressWidget.style.display = 'none';
                        if (progressActions) progressActions.style.display = 'none';
                        if (arrowSpan) arrowSpan.textContent = ' ▸';
                    }, 10000);
                } else {
                    if (progressAutoCloseTimer) clearTimeout(progressAutoCloseTimer);
                }
            });
        }
    }

    document.getElementById('export-words-btn')?.addEventListener('click', () => {
        window.open('/api/export-words?format=csv', '_blank');
    });

    document.getElementById('language-level')?.addEventListener('change', async () => {
        const newLevel = (document.getElementById('language-level') as HTMLSelectElement)?.value;
        if (newLevel) {
            // Save to localStorage
            localStorage.setItem('gemini_level', newLevel);

            // Sync level to backend DB so next session uses the correct prompt file
            try {
                await fetch('/api/profile?user_id=default', {
                    method: 'PUT',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify({ level: newLevel })
                });
                console.log('[Level] Updated DB profile level to:', newLevel);
            } catch (err) {
                console.error('[Level] Failed to update profile:', err);
            }

            // Auto-reconnect if currently connected to load new level's prompts
            const state = getState();
            if (state.isConnected) {
                // Clear session memory to prevent old level context bleeding
                try {
                    await fetch('/api/clear-session', { method: 'POST' });
                } catch (_) { /* ignore */ }

                // Reset streaming display to clean up orphaned CSS
                StreamingDisplay.hardReset();

                // 🔧 FIX: Clear ALL chat messages to prevent duplication of
                // "Microphone active", "Connected to Gemini", and old level content
                const chatMessages = document.getElementById('chat-messages');
                if (chatMessages) {
                    chatMessages.innerHTML = '';
                    // Show brief notification in the now-clean chat
                    const notif = document.createElement('div');
                    notif.className = 'system-message mode-change-notice';
                    notif.innerHTML = `🔄 Переключение на <strong>${newLevel}</strong>...`;
                    notif.style.cssText = 'background: rgba(59, 130, 246, 0.2); border: 1px solid #3b82f6; padding: 10px; margin: 10px 0; border-radius: 8px; text-align: center;';
                    chatMessages.appendChild(notif);
                }

                stopConversation();
                setTimeout(() => startConversation('voice'), 500);
            }
        }
        Vocabulary.refreshProgress();
    });

    // Setup save slots
    setupSaveSlots();
}

// ========== SAVE SLOTS ==========

interface SaveSlot {
    id: number;
    slot_name: string;
    word_count: number;
    created_at: string;
}

async function setupSaveSlots(): Promise<void> {
    // === Save Management Modal ===
    const savesModal = document.getElementById('saves-modal');
    const openBtn = document.getElementById('open-saves-modal-btn');
    const closeBtn = document.getElementById('close-saves-modal');

    openBtn?.addEventListener('click', () => {
        savesModal?.classList.remove('hidden');
        // Show current save name
        const currentSaveName = localStorage.getItem('current_save_name');
        const nameEl = document.getElementById('current-save-name');
        if (nameEl) {
            nameEl.textContent = currentSaveName || 'Не загружено (новая сессия)';
            nameEl.style.color = currentSaveName ? 'var(--green)' : 'var(--text3)';
        }
        loadSaveSlotsList(); // refresh list when opening
    });
    closeBtn?.addEventListener('click', () => {
        savesModal?.classList.add('hidden');
    });
    savesModal?.querySelector('.modal-overlay')?.addEventListener('click', () => {
        savesModal?.classList.add('hidden');
    });

    // Create save button
    document.getElementById('create-save-btn')?.addEventListener('click', async () => {
        const name = prompt('Название сохранения:', `Сохранение ${new Date().toLocaleDateString('ru')}`);
        if (!name) return;

        try {
            const res = await fetch('/api/saves', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ slot_name: name })
            });
            if (res.ok) {
                const data = await res.json();
                localStorage.setItem('current_save_name', name);
                Notifications.showToast(`💾 Сохранено: ${data.word_count} слов`, 3000);
                loadSaveSlotsList();
            }
        } catch (e) {
            console.error('Save failed:', e);
        }
    });

    // Reset progress button
    document.getElementById('reset-progress-btn')?.addEventListener('click', async () => {
        if (!confirm('⚠️ Вы уверены, что хотите начать заново?\n\nВесь прогресс будет удалён!\n\nСначала сохраните текущий прогресс!')) return;

        try {
            const res = await fetch('/api/progress/reset-all', { method: 'POST' });
            if (res.ok) {
                Notifications.showToast('🗑️ Прогресс сброшен', 3000);
                Vocabulary.refreshProgress();
            }
        } catch (e) {
            console.error('Reset failed:', e);
        }
    });

    // Load initial list
    loadSaveSlotsList();
}

async function loadSaveSlotsList(): Promise<void> {
    const container = document.getElementById('save-slots-list');
    if (!container) return;

    try {
        const res = await fetch('/api/saves');
        if (!res.ok) throw new Error('Failed to load saves');

        const slots: SaveSlot[] = await res.json();

        if (slots.length === 0) {
            container.innerHTML = '<p class="saves-empty">Нет сохранений</p>';
            return;
        }

        container.innerHTML = slots.map(slot => `
            <div class="save-slot-item" data-id="${slot.id}">
                <div class="save-slot-info">
                    <span class="save-slot-name">${escapeHtml(slot.slot_name)}</span>
                    <span class="save-slot-meta">${slot.word_count} слов • ${formatDate(slot.created_at)}</span>
                </div>
                <div class="save-slot-btns">
                    <button class="btn btn-sm btn-load load-save-btn">📂 Загрузить</button>
                    <button class="btn btn-sm btn-del delete-save-btn">🗑️ Удалить</button>
                </div>
            </div>
        `).join('');

        // Add event listeners
        container.querySelectorAll('.load-save-btn').forEach(btn => {
            btn.addEventListener('click', async (e) => {
                const item = (e.target as HTMLElement).closest('.save-slot-item');
                const id = item?.getAttribute('data-id');
                if (!id || !confirm('Загрузить это сохранение?\n\nТекущий прогресс будет заменён!')) return;

                try {
                    const res = await fetch(`/api/saves/${id}`);
                    if (res.ok) {
                        const data = await res.json();
                        const slotName = item?.querySelector('.save-slot-name')?.textContent || '';
                        localStorage.setItem('current_save_name', slotName);
                        Notifications.showToast(`📂 Загружено: ${data.word_count} слов`, 3000);
                        Vocabulary.refreshProgress();
                    }
                } catch (e) {
                    console.error('Load failed:', e);
                }
            });
        });

        container.querySelectorAll('.delete-save-btn').forEach(btn => {
            btn.addEventListener('click', async (e) => {
                const item = (e.target as HTMLElement).closest('.save-slot-item');
                const id = item?.getAttribute('data-id');
                if (!id || !confirm('Удалить это сохранение?')) return;

                try {
                    const res = await fetch(`/api/saves/${id}`, { method: 'DELETE' });
                    if (res.ok) {
                        Notifications.showToast('🗑️ Сохранение удалено', 2000);
                        loadSaveSlotsList();
                    }
                } catch (e) {
                    console.error('Delete failed:', e);
                }
            });
        });
    } catch (e) {
        console.error('Failed to load saves:', e);
        container.innerHTML = '<p class="saves-empty">Ошибка загрузки</p>';
    }
}

function escapeHtml(text: string): string {
    const div = document.createElement('div');
    div.textContent = text;
    return div.innerHTML;
}

function formatDate(isoDate: string): string {
    try {
        const date = new Date(isoDate);
        return date.toLocaleDateString('ru', { day: 'numeric', month: 'short' });
    } catch {
        return isoDate;
    }
}

