let currentLang: AppLang = 'ru';

export function t(key: string): string {
    return T[currentLang]?.[key] || T['en']?.[key] || key;
}

export function getCurrentLang(): AppLang {
    return currentLang;
}

/**
 * Apply all translations to the DOM
 */
function applyTranslations(): void {
    // data-i18n labels
    document.querySelectorAll('[data-i18n]').forEach(el => {
        const key = el.getAttribute('data-i18n')!;
        const text = t(key);
        // Preserve child elements (buttons inside labels, tooltip btns)
        const children = Array.from(el.children);
        if (children.length > 0) {
            // Replace only text nodes
            el.childNodes.forEach(node => {
                if (node.nodeType === Node.TEXT_NODE && node.textContent?.trim()) {
                    node.textContent = text + ' ';
                }
            });
        } else {
            el.textContent = text;
        }
    });

    // Radio labels
    const radioMap: Record<string, string> = {
        standard: t('standard'), active: t('active'),
        grammar: t('grammar'), free_conversation: t('conversation'),
    };
    document.querySelectorAll('.teacher-mode-radios .radio-label').forEach(label => {
        const input = label.querySelector('input[type="radio"]') as HTMLInputElement;
        const span = label.querySelector('span:last-child');
        if (input && span && radioMap[input.value]) span.textContent = radioMap[input.value];
    });

    // Progress buttons
    const mgmt = document.getElementById('open-saves-modal-btn');
    if (mgmt) mgmt.textContent = t('management');
    const exp = document.getElementById('export-words-btn');
    if (exp) exp.textContent = t('export');

    // Loading text
    const ld = document.querySelector('.progress-loading');
    if (ld) ld.textContent = t('loading');

    // Voice/Screen/Camera buttons (have <span class="icon"> + <span>TEXT</span>)
    const modeBtns: [string, string][] = [
        ['btn-voice', 'voiceBtn'], ['btn-screen', 'screenBtn'], ['btn-camera', 'cameraBtn'],
    ];
    for (const [id, key] of modeBtns) {
        const btn = document.getElementById(id);
        if (btn) {
            const textSpan = btn.querySelector('span:last-child');
            if (textSpan) {
                // Extract just the text part (after emoji)
                const text = t(key);
                const parts = text.split(' ');
                textSpan.textContent = parts.length > 1 ? parts.slice(1).join(' ') : text;
            }
        }
    }

    // Skip / Stop / Continue buttons
    const skipBtn = document.getElementById('skip-speech-btn');
    if (skipBtn) skipBtn.textContent = t('skipBtn');
    const stopBtn = document.getElementById('stop-btn');
    if (stopBtn) stopBtn.textContent = t('stopBtn');
    const continueBtn = document.getElementById('continue-btn');
    if (continueBtn) continueBtn.textContent = t('continueBtn');

    // Send button — may have an icon
    // Type placeholder
    const msgInput = document.getElementById('message-input') as HTMLInputElement;
    if (msgInput) msgInput.placeholder = t('typePlaceholder');

    // Get Key link
    const getKeyLink = document.querySelector('.settings-group .link') as HTMLElement;
    if (getKeyLink) getKeyLink.textContent = t('getKey');

    // Chats header
    const chatsHeader = document.querySelector('.sidebar-header span');
    if (chatsHeader) {
        // Preserve logo img if present
        const img = chatsHeader.querySelector('img');
        if (img) {
            chatsHeader.textContent = '';
            chatsHeader.appendChild(img);
            chatsHeader.appendChild(document.createTextNode(' ' + t('chats')));
        } else {
            chatsHeader.textContent = t('chats');
        }
    }

    // Thoughts label
    const thoughtsBtns = document.querySelectorAll('.thinking-toggle-text');
    thoughtsBtns.forEach(el => { el.textContent = t('thoughts'); });

    // Settings link in mobile
    const settingsLinks = document.querySelectorAll('[data-i18n="settings"]');
    settingsLinks.forEach(el => { el.textContent = t('settings'); });

    // Update picker button text
    updatePickerButton();
}

let pickerBtn: HTMLElement | null = null;
let pickerDropdown: HTMLElement | null = null;

function updatePickerButton(): void {
    if (!pickerBtn) return;
    const meta = LANGS[currentLang];
    pickerBtn.innerHTML = `
        <span class="lang-flag">${meta.flag}</span>
        <span class="lang-name">${meta.native}</span>
        <span class="lang-arrow">▾</span>
    `;
}

function buildPicker(container: HTMLElement): void {
    container.innerHTML = `
        <label data-i18n="appLang">${t('appLang')}</label>
        <div class="language-picker app-lang-picker" id="app-lang-picker">
            <button class="language-picker-btn" id="app-lang-picker-btn" type="button">
                <span class="lang-flag">${LANGS[currentLang].flag}</span>
                <span class="lang-name">${LANGS[currentLang].native}</span>
                <span class="lang-arrow">▾</span>
            </button>
            <div class="language-picker-dropdown" id="app-lang-dropdown">
                <input type="text" class="language-search" id="app-lang-search"
                    placeholder="🔍 Search..." autocomplete="off">
                <div class="language-list" id="app-lang-list"></div>
            </div>
        </div>
    `;

    pickerBtn = container.querySelector('#app-lang-picker-btn');
    pickerDropdown = container.querySelector('#app-lang-dropdown');
    const searchInput = container.querySelector('#app-lang-search') as HTMLInputElement;
    const listEl = container.querySelector('#app-lang-list')!;

    function renderList(filter = ''): void {
        listEl.innerHTML = '';
        const q = filter.toLowerCase();
        for (const [code, meta] of Object.entries(LANGS)) {
            const match = !q ||
                meta.name.toLowerCase().includes(q) ||
                meta.native.toLowerCase().includes(q) ||
                code.includes(q);
            if (!match) continue;

            const item = document.createElement('div');
            item.className = 'language-item' + (code === currentLang ? ' selected' : '');
            item.innerHTML = `
                <span class="lang-item-flag">${meta.flag}</span>
                <span class="lang-item-name">${meta.native}</span>
                <span class="lang-item-en">${meta.name}</span>
            `;
            item.addEventListener('click', () => {
                currentLang = code as AppLang;
                localStorage.setItem('app_language', currentLang);
                pickerDropdown?.classList.remove('open');
                applyTranslations();
            });
            listEl.appendChild(item);
        }
    }

    // Toggle dropdown
    pickerBtn?.addEventListener('click', (e) => {
        e.stopPropagation();
        const isOpen = pickerDropdown?.classList.contains('open');
        // Close any other open pickers
        document.querySelectorAll('.language-picker-dropdown.open').forEach(d => d.classList.remove('open'));
        if (!isOpen && pickerBtn && pickerDropdown) {
            const btnEl = pickerBtn;
            const dropEl = pickerDropdown;
            const app = document.querySelector('.app') || document.body;
            if (dropEl.parentElement !== app) {
                app.appendChild(dropEl);
            }
            requestAnimationFrame(() => {
                const rect = btnEl.getBoundingClientRect();
                const dropW = 240;
                let left = rect.left;
                if (left + dropW > window.innerWidth - 10) left = window.innerWidth - dropW - 10;
                if (left < 10) left = 10;
                const dropH = dropEl.offsetHeight || 300; // estimated height
                let top = rect.bottom + 4;

                // If it goes off the bottom of the screen, show it above the button
                if (top + dropH > window.innerHeight - 10) {
                    top = rect.top - dropH - 4;
                    if (top < 10) top = 10; // Failsafe if screen is very small
                }

                dropEl.style.position = 'fixed';
                dropEl.style.left = `${left}px`;
                dropEl.style.top = `${top}px`;
                dropEl.style.width = `${Math.max(dropW, rect.width)}px`;
                dropEl.style.zIndex = '99999';
                dropEl.classList.add('open');
                searchInput.value = '';
                renderList();
                searchInput.focus();
            });
        }
    });

    // Search filter
    searchInput?.addEventListener('input', () => {
        renderList(searchInput.value);
    });

    // Close on outside click
    document.addEventListener('click', (e) => {
        if (!container.contains(e.target as Node)) {
            pickerDropdown?.classList.remove('open');
        }
    });

    renderList();
}

export function initI18n(): void {
    const saved = localStorage.getItem('app_language') as AppLang | null;
    if (saved && T[saved]) currentLang = saved;

    // Create app language picker BELOW the theme section
    const sidebar = document.querySelector('.sidebar-right');
    const themeGroup = sidebar?.querySelector('.theme-group');
    if (sidebar && themeGroup) {
        const group = document.createElement('div');
        group.className = 'settings-group app-lang-group';
        themeGroup.insertAdjacentElement('afterend', group);
        buildPicker(group);
    }

    applyTranslations();
}
