/**
 * Audio Playback Module (TypeScript)
 * Handles buffered audio output from Gemini Live with optimized scheduling
 */

class AudioPlaybackModule {
    private context: AudioContext | null = null;
    private gainNode: GainNode | null = null;
    private scheduledEndTime = 0;
    private readonly MIN_BUFFER_TIME = 0.1;
    // Load from localStorage if available, otherwise default to 1.0 (100%)
    private _volume = (localStorage.getItem('app_volume') ? parseInt(localStorage.getItem('app_volume') as string, 10) / 100 : 1.0);
    private _muted = false;
    private _playbackRate = 1.0;

    // Reusable typed arrays for performance
    private floatBuffer: Float32Array | null = null;

    // Tracking for karaoke sync
    private chunksPlayed = 0;
    private totalAudioDurationMs = 0;

    /**
     * Set volume (0.0 - 1.0)
     */
    setVolume(volume: number): void {
        this._volume = Math.max(0, Math.min(1, volume));
        if (this.gainNode) {
            this.gainNode.gain.value = this._muted ? 0 : this._volume;
        }
    }

    /**
     * Set mute state
     */
    setMute(muted: boolean): void {
        this._muted = muted;
        if (this.gainNode) {
            this.gainNode.gain.value = this._muted ? 0 : this._volume;
        }
    }

    // Track active audio sources (kept for potential future use)
    private activeSources: AudioBufferSourceNode[] = [];

    /**
     * Set playback rate (0.5 - 2.0)
     * Rate applies to NEW audio chunks only (changing mid-playback causes audio glitches)
     */
    setPlaybackRate(rate: number): void {
        const newRate = Math.max(0.5, Math.min(2.0, rate));
        console.log('[AudioPlayback] setPlaybackRate:', rate, '-> clamped to:', newRate);
        this._playbackRate = newRate;
        // NOTE: Not applying to active sources - causes timing glitches
        // New chunks will use the updated rate
    }

    /**
     * Get current playback rate
     */
    getPlaybackRate(): number {
        return this._playbackRate;
    }

    /**
     * Play audio chunk from base64 PCM16 data
     */
    playChunk(base64Audio: string): void {
        try {
            const bytes = this.base64ToUint8Array(base64Audio);
            const samples = this.pcm16ToFloat32(bytes);

            const ctx = this.getContext();
            if (!ctx) return;

            // Create and fill buffer
            const buffer = ctx.createBuffer(1, samples.length, 24000);
            buffer.getChannelData(0).set(samples);

            // Schedule playback with precise timing
            const currentTime = ctx.currentTime;
            const startTime = Math.max(currentTime + this.MIN_BUFFER_TIME, this.scheduledEndTime);

            const source = ctx.createBufferSource();
            source.buffer = buffer;

            // Apply playback rate (affects pitch too, but works!)
            source.playbackRate.value = this._playbackRate;

            // Connect through gain node for volume control
            if (this.gainNode) {
                source.connect(this.gainNode);
            } else {
                source.connect(ctx.destination);
            }

            // Adjust duration based on playback rate
            const adjustedDuration = buffer.duration / this._playbackRate;
            this.scheduledEndTime = startTime + adjustedDuration;
            source.start(startTime);

            // Track this source for instant rate changes
            this.activeSources.push(source);

            // Track for karaoke sync
            this.chunksPlayed++;
            this.totalAudioDurationMs += adjustedDuration * 1000;

            source.onended = (): void => {
                // Remove from active sources
                const idx = this.activeSources.indexOf(source);
                if (idx > -1) {
                    this.activeSources.splice(idx, 1);
                }
            };

        } catch (e) {
            console.error('[AudioPlayback] Error:', e);
        }
    }

    /**
     * Get or create audio context
     */
    private getContext(): AudioContext | null {
        if (!this.context || this.context.state === 'closed') {
            try {
                this.context = new AudioContext({ sampleRate: 24000 });
                // Create gain node for volume control
                this.gainNode = this.context.createGain();
                this.gainNode.gain.value = this._muted ? 0 : this._volume;
                this.gainNode.connect(this.context.destination);
                this.scheduledEndTime = 0;
            } catch (e) {
                console.error('[AudioPlayback] Failed to create AudioContext:', e);
                return null;
            }
        }

        if (this.context.state === 'suspended') {
            this.context.resume().catch(() => { });
        }

        return this.context;
    }

    /**
     * Optimized Base64 decode using atob + typed array
     */
    private base64ToUint8Array(base64: string): Uint8Array {
        const binaryString = atob(base64);
        const len = binaryString.length;
        const bytes = new Uint8Array(len);

        // Unrolled loop for performance
        for (let i = 0; i < len; i += 4) {
            bytes[i] = binaryString.charCodeAt(i);
            if (i + 1 < len) bytes[i + 1] = binaryString.charCodeAt(i + 1);
            if (i + 2 < len) bytes[i + 2] = binaryString.charCodeAt(i + 2);
            if (i + 3 < len) bytes[i + 3] = binaryString.charCodeAt(i + 3);
        }

        return bytes;
    }

    /**
     * Optimized PCM16 to Float32 conversion
     */
    private pcm16ToFloat32(bytes: Uint8Array): Float32Array {
        const numSamples = bytes.length >> 1; // Faster division by 2

        // Reuse buffer if same size (reduces GC pressure)
        if (!this.floatBuffer || this.floatBuffer.length !== numSamples) {
            this.floatBuffer = new Float32Array(numSamples);
        }

        const view = new DataView(bytes.buffer);
        const scale = 1 / 32768;

        for (let i = 0; i < numSamples; i++) {
            this.floatBuffer[i] = view.getInt16(i << 1, true) * scale;
        }

        return this.floatBuffer;
    }

    reset(): void {
        this.scheduledEndTime = 0;
        this.chunksPlayed = 0;
        this.totalAudioDurationMs = 0;
    }

    /**
     * Skip/interrupt current playback without destroying AudioContext.
     * Cancels all scheduled audio sources so mic can work immediately.
     * AudioContext stays alive for future audio from Gemini.
     */
    skipPlayback(): void {
        console.log('[AudioPlayback] Skipping current playback, canceling', this.activeSources.length, 'sources');
        // Stop all active audio sources immediately
        for (const source of this.activeSources) {
            try {
                source.stop();
            } catch (e) {
                // Source may have already ended
            }
        }
        this.activeSources = [];
        this.scheduledEndTime = 0;
        this.chunksPlayed = 0;
        this.totalAudioDurationMs = 0;
        console.log('[AudioPlayback] Playback skipped — mic should work now');
    }

    stop(): void {
        // First cancel all active sources
        this.skipPlayback();
        // Then destroy the AudioContext entirely
        try {
            if (this.context && this.context.state !== 'closed') {
                this.context.close();
            }
        } catch (e) {
            console.log('[AudioPlayback] Error stopping:', e);
        }
        this.context = null;
        this.gainNode = null;
        this.floatBuffer = null;
    }

    /**
     * Get current audio buffer delay in milliseconds
     * (how far ahead audio is scheduled)
     */
    getAudioDelay(): number {
        if (!this.context) return 0;
        const delay = Math.max(0, this.scheduledEndTime - this.context.currentTime);
        return delay * 1000; // Convert to ms
    }

    getIsPlaying(): boolean {
        if (!this.context) return false;
        // The definitive truth: is current time before the end time we scheduled?
        // Add a tight 0.05s buffer to prevent premature cuts
        return this.context.currentTime < this.scheduledEndTime + 0.05;
    }
}

export const AudioPlayback = new AudioPlaybackModule();

// Resume on user interaction (mobile policy)
const resumeHandler = (): void => {
    const ctx = (AudioPlayback as any).context;
    if (ctx && ctx.state === 'suspended') {
        ctx.resume().catch(() => { });
    }
};

['touchstart', 'touchend', 'click', 'keydown'].forEach(type => {
    document.addEventListener(type, resumeHandler, { once: false, passive: true });
});

// Global export
if (typeof window !== 'undefined') {
    (window as any).AudioPlayback = AudioPlayback;
}

console.log('[AudioPlayback] Module loaded (TS)');
