/**
 * Vocabulary Module (TypeScript)
 * Handles German vocabulary extraction, formatting, and progress tracking
 * 
 * Performance optimizations:
 * - Compiled regex patterns (created once)
 * - Set-based word lookup (O(1))
 * - DocumentFragment for batch DOM updates
 */

import type { VocabularyWord, ProgressData } from '../types';
import { LANGUAGES, getNativeLanguage } from '../ui/language-picker';

/** Get the native language flag emoji dynamically from "Переклад" picker */
function getNativeLangFlag(): string {
    const code = getNativeLanguage();
    const lang = LANGUAGES.find(l => l.code === code);
    return lang?.flag || '🇷🇺';
}

class VocabularyModule {
    // Track words seen in current session
    private seenWords = new Set<string>();
    // Track words already logged (avoid duplicates)  
    private loggedWords = new Set<string>();

    // Pre-compiled regex patterns (performance optimization)
    // More flexible lookahead - stop only at next 🇩🇪 flag or end of text
    private static readonly FLAG_WITH_TRANSLATION = /🇩🇪\s*(\*{0,2}[A-ZÄÖÜ][A-ZÄÖÜa-zäöüß\s?!'\.…]+?\*{0,2})\s*(\([^)]+\))?\s*([-–—:]\s*[А-Яа-яЁё][А-Яа-яЁё\s,\.!?…]+?)(?=\s*🇩🇪|\s*$|\n\n|\n[А-ЯA-Z])/gi;
    private static readonly FLAG_WITH_NUMBER = /🇩🇪\s*([A-ZÄÖÜ][A-ZÄÖÜa-zäöüß\s?!']{1,40}?)\s*(\([^)]+\))?\s*([-–—:]\s*\d+)(?=\s*🇩🇪|\s*$|\s*\n|\s+[А-Яа-яA-Z])/gi;
    private static readonly FLAG_WITH_PRON = /🇩🇪\s*([A-ZÄÖÜ][A-ZÄÖÜa-zäöüß\s?!'\.…]{2,50}?)\s*(\([^)]+\))(?!\s*[-–—:])/gi;
    private static readonly FLAG_SIMPLE = /🇩🇪\s*([A-ZÄÖÜ][A-ZÄÖÜa-zäöüß\s?!']{2,40}?)(?=\s*🇩🇪|\s*$|\s*[.!?,;:](?:\s|$)|\s*\n)/gi;
    // NEW: Pattern for german-only mode format: 🇩🇪 WORD (pron) - [TRANSLATION:...]
    private static readonly FLAG_WITH_TRANSLATION_TAG = /🇩🇪\s*([A-ZÄÖÜ][A-ZÄÖÜa-zäöüß\s?!'\.…]{1,50}?)\s*(\([^)]+\))?\s*[-–—:]\s*\[TRANSLATION:([^\]]+)\]/gi;
    private static readonly BOLD_PATTERN = /\*\*([A-ZÄÖÜ][A-ZÄÖÜa-zäöüß\s]+)\*\*/g;
    // Supports both old (LOG: ...) and new [log_learning_item:...] formats
    private static readonly LOG_PATTERN = /(?:\[\s*(?:log_learning_item|LOG)(?:[:\s]\s*|)([^\]]*)\])|(?:log_learning_item\s*\([^)]*\)\s*)|(?:\[LOG:[^\]]*\])/gi;

    // Extraction patterns - more flexible for various formats
    // Pattern for: 🇩🇪 WORD (pron) - Translation (most complete)
    // Include … and multiple dots in translation
    private static readonly EXTRACT_FLAG = /🇩🇪\s*([A-ZÄÖÜ][A-ZÄÖÜa-zäöüß\s'?!\.…]{1,50}?)\s*\(([^)]+)\)\s*[-–—:]\s*([А-Яа-яЁё][А-Яа-яЁё\s,\.!?…]+?)(?=\s*🇩🇪|\s*$|\n\n|\n[А-ЯA-Z])/g;
    // Pattern for: 🇩🇪 WORD - Translation (no pronunciation)  
    private static readonly EXTRACT_SIMPLE = /🇩🇪\s*([A-ZÄÖÜ][A-ZÄÖÜa-zäöüß\s'?!\.…]{1,50}?)\s*[-–—:]\s*([А-Яа-яЁё][А-Яа-яЁё\s,\.!?…]+?)(?=\s*🇩🇪|\s*$|\n\n|\n[А-ЯA-Z])/g;
    // Pattern for: 🇩🇪 WORD (pron) without translation - use pronunciation as definition
    private static readonly EXTRACT_PRON_ONLY = /🇩🇪\s*([A-ZÄÖÜ][A-ZÄÖÜa-zäöüß\s'?!\.…]{1,50}?)\s*\(([^)]+)\)(?!\s*[-–—:])/g;
    // Pattern for: Word = Translation
    private static readonly EXTRACT_EQUALS = /([A-ZÄÖÜa-zäöüß'][A-ZÄÖÜa-zäöüß'\s]{1,30})\s*=\s*([А-Яа-яЁё][А-Яа-яЁё\s]{2,30})/gi;

    // Pattern for extraction from [log_learning_item:TERM:DEFINITION]
    private static readonly EXTRACT_LOG_TAG = /\[\s*(?:log_learning_item|LOG)(?:[:\s]\s*)([^:\]]+):([^\]]+)\]/gi;

    // Pattern for grammar topic logging: [LOG: GRAMMAR: topic_name]
    private static readonly GRAMMAR_LOG_PATTERN = /\[LOG:\s*GRAMMAR:\s*([^\]]+)\]/gi;

    /**
     * Format AI message with vocabulary highlighting
     */
    // Sequential counter for stable hint IDs (reset per formatMessage call)
    private hintCounter = 0;

    /**
     * Build hint/answer HTML from extracted hint and answer text content.
     * Used by both XML tag parser and plain-text fallback parser.
     */
    public buildHintAnswerHtml(hint: string, answer: string): string {
        const hintId = 'hint_' + (++this.hintCounter);

        // Parse hint content
        let hintContentHtml = '';
        let hintParts = hint.split('▸');
        if (hintParts.length <= 1) {
            if (hint.includes('•')) {
                hintParts = hint.split('•');
            } else {
                // Pre-process: merge trailing translations that ended up on a new line
                // e.g., "- German text\n(Russian text)" -> "- German text (Russian text)"
                const cleanHint = hint.replace(/\n\s*(\([А-Яа-яЁё][^)]*?\))/g, ' $1');

                if (cleanHint.includes('\n')) {
                    hintParts = cleanHint.split(/\n/);
                }
            }
        }

        hintParts = hintParts.map(p => p.trim()).filter(p => p.length > 0);

        if (hintParts.length > 1) {
            const title = hintParts[0];
            const items = hintParts.slice(1)
                .filter(item => {
                    const p = item.toLowerCase();
                    return !p.startsWith('ответ:') && !p.startsWith('answer:') && !p.startsWith('antwort:');
                })
                .map(item =>
                    `<div class="hint-item">${this.escapeHtml(item)}</div>`
                ).join('');

            hintContentHtml = `
                <div class="hint-header">${this.escapeHtml(title)}</div>
                <div class="hint-list">${items}</div>
            `;
        } else {
            // Use cleanHint if it was processed, otherwise original hint
            const finalHintText = hintParts.length > 0 ? hintParts[0] : hint;
            hintContentHtml = this.escapeHtml(finalHintText.trim());
        }

        // Pre-process: merge trailing translations that ended up on a new line
        // e.g., "+ German text\n(Russian text)" -> "+ German text (Russian text)"
        const cleanAnswer = answer.replace(/\n\s*(\([А-Яа-яЁё][^)]*?\))/g, ' $1');

        // Parse answer content for variants
        const answerLines = cleanAnswer.split(/\n/)
            .map((l: string) => l.trim())
            .filter((l: string) => l.length > 0)
            .filter((l: string) => !/^(ОТВЕТ\s*\/?\s*ANSWER|ОТВЕТ|ANSWER)$/i.test(l));
        const answerItems = answerLines.map(line => {
            line = line.trim();
            let className = 'answer-item-neutral';
            if (line.startsWith('+')) {
                className = 'answer-item-positive';
                line = line.substring(1).trim();
            } else if (line.startsWith('-')) {
                className = 'answer-item-negative';
                line = line.substring(1).trim();
            } else if (line.startsWith('~')) {
                className = 'answer-item-variant';
                line = line.substring(1).trim();
            }

            const match = line.match(/^(.*?)(\s*\([^)]*[А-Яа-яЁё][^)]*\))\s*$/);
            let germanPart = line;
            let translationPart = '';
            if (match) {
                germanPart = match[1];
                translationPart = match[2];
            }

            return `
                <div class="answer-item ${className}">
                    <div class="answer-content">
                        <span class="answer-german">${this.escapeHtml(germanPart.trim())}</span><button class="tts-inline-btn" onclick="speakThisText(this)" title="Прослушать">🔊</button>
                        ${translationPart ? `<br><span class="answer-translation">${this.escapeHtml(translationPart.trim())}&nbsp;<button class="tts-inline-btn" onclick="speakThisText(this)" title="Прослушать">🔊</button></span>` : ''}
                    </div>
                </div>
            `;
        }).join('');

        const answerContentHtml = `
            <div class="answer-list">${answerItems}</div>
        `;

        const answerContainerHtml = answer.trim() ? `
                <div class="hint-column">
                    <button class="hint-btn hint-btn-answer hidden" onclick="revealHint('${hintId}', 'answer', event)" title="Показать ответ">ОТВЕТ</button>
                    <div class="hint-panel hint-text hidden" data-type="answer">${answerContentHtml}</div>
                </div>
        ` : '';

        return `
            <div class="hint-container expanded" id="${hintId}">
                <div class="hint-column">
                    <button class="hint-btn hint-btn-hint" onclick="revealHint('${hintId}', 'hint', event)" title="Показать подсказку">ГРАММАТИКА</button>
                    <div class="hint-panel hint-text hidden" data-type="hint">${hintContentHtml}</div>
                </div>
                ${answerContainerHtml}
            </div>
        `.replace(/\s+/g, ' ').trim();
    }

    formatMessage(text: string): string {
        if (!text) return '';

        // Strip explicit 🔊 emojis from raw model output to prevent double buttons
        text = text.replace(/🔊/g, '');

        // Reset hint counter so same content always produces same IDs
        this.hintCounter = 0;

        const teacherModeRadio = document.querySelector('input[name="teacher-mode"]:checked') as HTMLInputElement;
        const isActiveMode = teacherModeRadio?.value === 'active';
        const vocabClassNew = isActiveMode ? 'vocab-word-active' : 'vocab-word';
        const vocabClassLearned = 'vocab-word-learned';

        let formatted = text.replace(VocabularyModule.LOG_PATTERN, '');
        formatted = this.fixMalformedTags(formatted);

        // Add aggressive stripping of Voice TTS markers so they NEVER appear in UI
        formatted = formatted.replace(/(?:Ende\s+der\s+Replik|End\s+der\s+Replik|Nächste\s+bitte)[\s.,!?]*/gi, '');
        formatted = formatted.replace(/(?:конец\s+реплики|следующая\s+пожалуйста)[\s.,!?]*/gi, '');

        // Deduplicate repeated REPLICA N: markers that sometimes happen due to Voice AI stuttering
        // or getting injected multiple times by Text Bot text recoveries
        // Matches both [REPLICA N]: (with brackets) and REPLICA N: (without brackets)
        formatted = formatted.replace(/(?:\[?REPLICA\s+(\d+)\]?:?\s*)+/gi, 'REPLICA $1:\n');

        // CRITICAL: Extract <hint>/<answer> blocks BEFORE speakerPattern to prevent
        // the regex from inserting <div class="dialogue-block"> inside answers/hints.
        const hintAnswerPlaceholders: Map<string, string> = new Map();
        let placeholderIdx = 0;
        formatted = formatted.replace(/<hint>([\s\S]*?)<\/hint>\s*<answer>([\s\S]*?)<\/answer>/gi, (match) => {
            const key = `__HA_PH_${placeholderIdx++}__`;
            hintAnswerPlaceholders.set(key, match);
            return key;
        });
        formatted = formatted.replace(/<hint>([\s\S]*?)<\/hint>/gi, (match) => {
            const key = `__HA_PH_${placeholderIdx++}__`;
            hintAnswerPlaceholders.set(key, match);
            return key;
        });

        // Matches: "REPLICA 1:", "[REPLICA 1]:", "1. Граммини:", "2. СОБЕСЕДНИК:", "Grammini:"
        let blockCount = 0;
        // CRITICAL FIX: Match REPLICA N: both with and without brackets, but enforce that it appears at the START of a line or after a break
        // to prevent matching inline mentions like "Я, Граммини, считаю..."
        const speakerPattern = /(^|\n|<br>)\s*(?:\[?REPLICA\s+(\d+)\]?:?\s*|(\d+)?(?:\]|\.)?\s*(?:Граммини|Grammini|Гrammini|Gраммини|Грамmini|Грамм[а-яА-Яa-zA-Z]*mini|СОБЕСЕДНИК|COБЕСЕДНИК|СОБЕСНИК|COGESPRECHER|COSESPRECHER|SPRECHER|INTERLOCUTOR|Собеседник|ПОЛЬЗОВАТЕЛЬ|УЧЕНИК|УЧИТЕЛЬ|USER|STUDENT|TEACHER|PARTICIPANT|BOT|БОТ|AI|ИИ|ASSISTANT|АССИСТЕНТ)\s*:?\s*)/gi;

        formatted = formatted.replace(
            speakerPattern,
            (_match, p1, p2, p3) => {
                blockCount++;
                const num = p2 || p3;
                const blockNum = num ? num : blockCount.toString();
                const prefix = (p1 && p1.trim()) ? p1 : ''; // Restore preceding punctuation/letter, discard pure whitespace
                return prefix + '</div></div>' +  // Close previous block
                    `<div class="dialogue-block" data-dialogue-id="dlg-${blockNum}">` +
                    '<div class="dialogue-header">' +
                    `<span class="dialogue-number">${blockNum}</span>` +
                    '<span class="dialogue-speaker-label">ГРАММИНИ</span>' +
                    '</div>' +
                    '<div class="dialogue-content"><span class="translation-icon translation" style="margin-right: 8px;">🇩🇪</span> ';
            }
        );
        // Clean orphaned closing tags at start
        formatted = formatted.replace(/^<\/div><\/div>/, '');
        // Close last dialogue-content if there are dialogue blocks
        if (formatted.includes('dialogue-block')) {
            formatted += '</div></div>';
        }

        // NOTE: Translation formatting moved to END of function (after <hint>/<answer> processing)
        // to prevent escapeHtml from converting span tags to visible text

        // NOTE: Translation formatting moved to END of function (after <hint>/<answer> processing)
        // to prevent escapeHtml from converting span tags to visible text

        // Pattern 0: NEW FORMAT with [TRANSLATION:...] tag (german-only mode)
        // Format: 🇩🇪 WORD (pron) - [TRANSLATION:перевод]
        formatted = formatted.replace(VocabularyModule.FLAG_WITH_TRANSLATION_TAG,
            (_m, word: string, pron: string, trans: string) => {
                const clean = word.replace(/[\\*?!]+/g, '').trim().toUpperCase();
                const css = this.seenWords.has(clean) ? vocabClassLearned : vocabClassNew;
                this.seenWords.add(clean);
                // Display: 🇩🇪 WORD (pron)<br><translation>перевод</translation>
                const pronPart = pron ? ` ${pron}` : '';
                return `<br><span class="${css}">🇩🇪 <strong>${word.trim()}</strong>${pronPart}</span> <span class="translation translation-block">${trans.trim()}</span>`;
            }
        );

        // Pattern 1: With translation (Russian text directly after dash)
        formatted = formatted.replace(VocabularyModule.FLAG_WITH_TRANSLATION,
            (_m, word: string, pron: string, trans: string) => {
                const clean = word.replace(/[\*?!]+/g, '').trim().toUpperCase();
                const css = this.seenWords.has(clean) ? vocabClassLearned : vocabClassNew;
                this.seenWords.add(clean);
                return `<br><span class="${css}">🇩🇪 <strong>${word.replace(/\*/g, '')}</strong> ${pron ?? ''} ${trans}</span>`;
            }
        );

        // Pattern 1b: With number translation (for digits like 🇩🇪 FÜNF - 5)
        formatted = formatted.replace(VocabularyModule.FLAG_WITH_NUMBER,
            (_m, word: string, pron: string, num: string) => {
                const clean = word.replace(/[\*?!]+/g, '').trim().toUpperCase();
                const css = this.seenWords.has(clean) ? vocabClassLearned : vocabClassNew;
                this.seenWords.add(clean);
                return `<br><span class="${css}">🇩🇪 <strong>${word.trim()}</strong> ${pron ?? ''} ${num}</span>`;
            }
        );

        // Pattern 2: With pronunciation only
        formatted = formatted.replace(VocabularyModule.FLAG_WITH_PRON,
            (_m, word: string, pron: string) => {
                const clean = word.replace(/[?!]+$/, '').trim().toUpperCase();
                const css = this.seenWords.has(clean) ? vocabClassLearned : vocabClassNew;
                this.seenWords.add(clean);
                return `<br><span class="${css}">🇩🇪 <strong>${word.trim()}</strong> ${pron}</span>`;
            }
        );

        // Pattern 3: Simple word
        formatted = formatted.replace(VocabularyModule.FLAG_SIMPLE,
            (match, word: string) => {
                if (match.includes('<span')) return match;
                const clean = word.replace(/[?!]+$/, '').trim().toUpperCase();
                const css = this.seenWords.has(clean) ? vocabClassLearned : vocabClassNew;
                this.seenWords.add(clean);
                return `<br><span class="${css}">🇩🇪 <strong>${word.trim()}</strong></span>`;
            }
        );

        // Bold pattern
        formatted = formatted.replace(VocabularyModule.BOLD_PATTERN, '<strong class="german-word">$1</strong>');


        // Cleanup: Remove stray closing brackets that might appear dynamically
        formatted = formatted.replace(/\]\s*<div class="hint-container"/g, '<div class="hint-container"');

        // Cleanup: Remove orphaned ] brackets (but NOT inside HTML attributes)
        // Remove standalone ] at start of line
        formatted = formatted.replace(/^\s*\]\s*/gm, '');
        // Remove ] not part of HTML (before text or at end)
        formatted = formatted.replace(/\](?=\s*[А-Яа-яA-Za-z])/g, '');
        // Remove ] followed by newline/br
        formatted = formatted.replace(/\]\s*(<br>|$)/gi, '$1');

        // The hint/answer restoring logic has been moved to the very end of this function
        // to prevent Pattern 2 from accidentally matching and double-wrapping Russian translations
        // that are already enclosed in HTML generated by buildHintAnswerHtml.
        // FINAL STEP: Format Russian translations - put on new line below German
        // This MUST be AFTER all <hint>/<answer> processing to avoid escapeHtml breaking our tags

        // Helper function to build the modern translation block
        const buildTranslationBlock = (trans: string) => {
            let formattedTrans = trans.replace(/([.!?])\s{1,3}([A-ZÄÖÜА-ЯЁ])/g, '$1<br>$2');
            return `<button class="tts-inline-btn german-tts-btn" onclick="playDialogueText(this)" title="Прослушать немецкий (Gemini)">🔊</button>` +
                   `<div class="translation-block translation selected-theme">` +
                   `<div class="translation-text-section" style="display: flex; flex-direction: row; align-items: flex-start; gap: 6px; margin-top: 4px; padding-top: 4px; border-top: 1px dashed rgba(255,255,255,0.1);">` +
                   `<span class="translation-icon" style="flex-shrink: 0;">${getNativeLangFlag()}</span>` +
                   `<span class="translation-text" style="flex-grow: 1;">${formattedTrans}</span>` +
                   `<button class="tts-inline-btn translation-tts-btn" style="flex-shrink: 0;" onclick="playTranslationText(this)" title="Прослушать перевод">🔊</button>` +
                   `</div></div>`;
        };

        // Pattern 0a: [TRANSLATION:...] - properly closed tag
        formatted = formatted.replace(
            /\[TRANSLATION:([^\]]+)\]/gi,
            (_m, trans) => buildTranslationBlock(trans)
        );
        // Pattern 0b: [TRANSLATION:... (unclosed, until end of line or next tag)
        formatted = formatted.replace(
            /\[TRANSLATION:([^\[\n]+?)(?=\[|$|\n)/gi,
            (_m, trans) => buildTranslationBlock(trans)
        );

        // Pattern 1: [ПЕРЕВОД:Русский текст] - alternative format
        formatted = formatted.replace(
            /\[ПЕРЕВОД:([^\]]+)\]/gi,
            (_m, trans) => buildTranslationBlock(trans)
        );

        // Pattern 1c: [RU: Русский текст] format (German-only mode marker)
        formatted = formatted.replace(
            /\[RU:\s*([А-Яа-яёЁ][А-Яа-яёЁ\s,\.\/\-\?!\:\;\"\'«»\d]*)\]/g,
            (_m, trans) => buildTranslationBlock(trans)
        );

        // Pattern 2: (Русский текст) format - traditional parenthetical translations
        // Capture text inside parentheses starting with Cyrillic. 
        formatted = formatted.replace(
            /(?:<\/p>)?\s*(?:<p>|<br>)?\s*\(([А-Яа-яёЁ][А-Яа-яёЁ\s,\.\/\-\—\–\?\!\:\;\"\'\«\»\d\wÄÖÜäöüß]*)\)/g,
            (_m, trans) => buildTranslationBlock(trans)
        );

        // Pattern 2b: STREAMING FIX — Unclosed parenthesis at end of text / before next REPLICA.
        // During streaming the closing ) may not have arrived yet.
        // Match (Cyrillic... at end of text or before next block header — auto-close.
        formatted = formatted.replace(
            /(?:<\/p>)?\s*(?:<p>|<br>)?\s*\(([А-Яа-яёЁ][А-Яа-яёЁ\s,\.\/\-\—\–\?\!\:\;\"\'\«\»\d\wÄÖÜäöüß]{10,})(?=\s*(?:<\/div>|$))/g,
            ' <button class="tts-inline-btn" onclick="speakDialogueGerman(this)" title="Прослушать немецкий">🔊</button>' +
            ' <span class="translation translation-block">($1)&nbsp;<button class="tts-inline-btn" onclick="speakDialogueTranslation(this)" title="Прослушать перевод">🔊</button></span>'
        );



        // FALLBACK: Native audio model often outputs plain-text format instead of XML tags:




        // ============================================================================
        // 🛡️ CRITICAL STEP: RESTORE <hint> AND <answer> BLOCKS AFTER ALL OTHER REGEXES
        // ============================================================================
        // Now that the main translation block regexes have run on the core text, we can safely expand
        // the hint/answer placeholders back into their full HTML structure.
        // Moving this to the VERY END prevents Pattern 2 from double-wrapping the Russian text
        // inside the generated hint/answer HTML!
        hintAnswerPlaceholders.forEach((originalMatch, placeholderKey) => {
            // Check if it's the combined hint+answer version (no global flag inside loop!)
            const combinedMatch = originalMatch.match(/<hint>([\s\S]*?)<\/hint>\s*<answer>([\s\S]*?)<\/answer>/i);
            if (combinedMatch && combinedMatch.length >= 3) {
                const hintContent = combinedMatch[1];
                const answerContent = combinedMatch[2];
                formatted = formatted.replace(placeholderKey, this.buildHintAnswerHtml(hintContent, answerContent));
                return;
            }

            // Check if it's the hint-only version (no global flag inside loop!)
            const hintMatch = originalMatch.match(/<hint>([\s\S]*?)<\/hint>/i);
            if (hintMatch && hintMatch.length >= 2) {
                const hintContent = hintMatch[1];
                formatted = formatted.replace(placeholderKey, this.buildHintAnswerHtml(hintContent, ''));
                return;
            }
        });

        // FALLBACK: Native audio model often outputs plain-text format instead of XML tags:
        // 📜 ГРАММАТИКА\nКОНСТРУКЦИЯ: ...\nСТИЛИСТИКА: ...\nОТВЕТ / ANSWER\n+ ...\n- ...\n~ ...
        if (!formatted.includes('hint-container')) {
            const plainTextPattern = /📜\s*(?:ГРАММ(?:АТИКА|АР|УАР)|GRAMMAR)[\s/]*(?:GRAMMAR)?\s*\n([\s\S]*?)(?:(?:ОТВЕТ\s*\/?\s*ANSWER|ANSWER\s*\/?\s*ОТВЕТ)\s*\n([\s\S]*?))?(?=(?:\n\n(?:\[?REPLICA\s+)?\d+(?:\]?|\.)\s*(?::|Грам[а-яА-Яa-zA-Z]*|Gram[a-zA-Z]*|СОБЕСЕДНИК|COБЕСЕДНИК|СОБЕСНИК|COGESPRECHER|COSESPRECHER|SPRECHER|INTERLOCUTOR|[A-Z]{8,}))|\n\n📜|$)/gi;
            formatted = formatted.replace(plainTextPattern, (_match, hint: string, answer: string | undefined) => {
                return this.buildHintAnswerHtml(hint, answer || '');
            });
        }

        // ============================================================================
        // 🎨 BEAUTIFUL TEXT FORMATTING 
        // ============================================================================
        // New paragraph after sentence-ending punctuation followed by a capital letter
        // This makes long streamed text readable with proper line breaks
        // Only apply OUTSIDE of HTML tags and hint-containers
        if (!formatted.includes('hint-container')) {
            // Line break after . ! ? followed by space + capital letter (both Latin and Cyrillic)
            formatted = formatted.replace(/([.!?])\s{1,3}([A-ZÄÖÜА-ЯЁ])/g, '$1<br>$2');
        } else {
            // With hint-containers present, only format inside .dialogue-content spans
            // Apply line breaks after periods only to dialogue German text (before hint-container)
            formatted = formatted.replace(
                /(<div class="dialogue-content">)(.*?)(<div class="hint-container)/gs,
                (_m, pre, content, post) => {
                    const beautified = content.replace(/([.!?])\s{1,3}([A-ZÄÖÜА-ЯЁ])/g, '$1<br>$2');
                    return pre + beautified + post;
                }
            );
        }

        // Clean up line breaks — max 2 consecutive <br>
        return formatted.replace(/(\s*<br>\s*){3,}/gi, '<br><br>').replace(/^(\s*<br>)+/, '');
    }

    /**
     * Clean text for TTS (remove hints, logs, etc)
     */
    cleanForTTS(text: string): string {
        if (!text) return '';
        // Remove <hint>/<answer> blocks completely (including newlines)
        let clean = text.replace(/<hint>[\s\S]*?<\/hint>(\s*<answer>[\s\S]*?<\/answer>)?/gi, '');
        // Remove standalone <hint> blocks (including newlines)
        clean = clean.replace(/<hint>[\s\S]*?<\/hint>/gi, '');
        // Remove log commands
        clean = clean.replace(VocabularyModule.LOG_PATTERN, '');
        // Remove markdown bold/italic
        clean = clean.replace(/\*\*|__/g, '');
        return clean.trim();
    }

    /**
     * Pre-populate seen words from history
     */
    populateFromHistory(messages: Array<{ role: string; parts?: Array<{ text?: string }>; text?: string }>): void {
        this.seenWords.clear();
        const pattern = /🇩🇪\s*([A-ZÄÖÜ][A-ZÄÖÜa-zäöüß\s']+)/g;

        for (const msg of messages) {
            if (msg.role !== 'model') continue;
            const text = msg.parts?.[0]?.text ?? msg.text ?? '';
            let match: RegExpExecArray | null;
            while ((match = pattern.exec(text)) !== null) {
                this.seenWords.add(match[1].trim().toUpperCase());
            }
        }
        console.log('[Vocabulary] Loaded', this.seenWords.size, 'words from history');
    }

    /**
     * Load learned words from server
     */
    async loadLearnedWords(): Promise<void> {
        try {
            console.log('[Vocabulary] Loading learned words...');
            const res = await fetch('/api/export-words');
            if (res.ok) {
                const words: VocabularyWord[] = await res.json();
                words.forEach(w => {
                    if (w.term) {
                        const clean = w.term.trim().toUpperCase();
                        this.seenWords.add(clean);
                        this.loggedWords.add(clean);
                    }
                });
                console.log(`[Vocabulary] Loaded ${words.length} learned words from server`);
            }
        } catch (e) {
            console.error('[Vocabulary] Failed to load learned words:', e);
        }
    }

    /**
     * Extract and log vocabulary to backend
     */
    async extractAndLog(text: string): Promise<void> {
        if (!text) return;
        console.log('[Vocabulary] extractAndLog called, text length:', text.length);

        // Clean instruction patterns
        let clean = text.replace(VocabularyModule.LOG_PATTERN, '');
        clean = clean.replace(/(?:повтори|скажи|запомни)[^:]*:\s*[A-ZÄÖÜ](?:[A-ZÄÖÜa-zäöüß,\s]+)(?=\.|$|\n)/gi, '');

        const found: VocabularyWord[] = [];

        // Extract with all patterns
        this.extractWithPattern(clean, VocabularyModule.EXTRACT_FLAG, found, true);
        this.extractWithPattern(clean, VocabularyModule.EXTRACT_SIMPLE, found, false);
        this.extractWithPattern(clean, VocabularyModule.EXTRACT_PRON_ONLY, found, false); // pronunciation as definition
        this.extractWithPattern(clean, VocabularyModule.EXTRACT_EQUALS, found, false);
        // Extract from explicit log tags (use raw text as clean has logs stripped)
        this.extractWithPattern(text, VocabularyModule.EXTRACT_LOG_TAG, found, false);

        console.log('[Vocabulary] Found words:', found.length, found.map(w => w.term));
        if (found.length === 0) return;

        // Log to backend
        let successCount = 0;
        const baseLevel = (document.getElementById('language-level') as HTMLSelectElement)?.value ?? 'A1';
        const teacherModeRadio = document.querySelector('input[name="teacher-mode"]:checked') as HTMLInputElement;
        const isActive = teacherModeRadio?.value === 'active';
        const category = isActive ? `${baseLevel} -S` : baseLevel;

        for (const word of found) {
            try {
                console.log('[Vocabulary] Saving:', word.term, '->', word.definition);
                const res = await fetch('/api/notebook', {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify({
                        category,
                        term: word.term,
                        definition: word.definition,
                        context: 'Auto-extracted from conversation'
                    })
                });

                console.log('[Vocabulary] API response:', res.status);
                if (res.ok) {
                    const result = await res.json();
                    console.log('[Vocabulary] Saved ID:', result.id);
                    if (result.id) successCount++;
                }
            } catch (e) {
                console.error('[Vocabulary] Failed to log:', word.term, e);
            }
        }

        if (successCount > 0) {
            this.showProgressAnimation(successCount);
            this.refreshProgress();
        }

        // Extract grammar topics [LOG: GRAMMAR: topic_name]
        await this.extractGrammarTopics(text);
    }

    /**
     * Extract and save grammar topics to backend
     */
    private async extractGrammarTopics(text: string): Promise<void> {
        const baseLevel = (document.getElementById('language-level') as HTMLSelectElement)?.value ?? 'A1';
        const grammarCategory = `GRAMMAR-${baseLevel}`;

        let match: RegExpExecArray | null;
        VocabularyModule.GRAMMAR_LOG_PATTERN.lastIndex = 0;

        while ((match = VocabularyModule.GRAMMAR_LOG_PATTERN.exec(text)) !== null) {
            const topic = match[1].trim();
            if (!topic || this.loggedWords.has(`GRAMMAR:${topic}`)) continue;

            try {
                console.log('[Vocabulary] Saving grammar topic:', topic);
                const res = await fetch('/api/notebook', {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify({
                        category: grammarCategory,
                        term: topic,
                        definition: `Грамматическая тема ${baseLevel}`,
                        context: 'Grammar topic completed in grammar mode'
                    })
                });

                if (res.ok) {
                    const result = await res.json();
                    if (result.id) {
                        this.loggedWords.add(`GRAMMAR:${topic}`);
                        console.log('[Vocabulary] Grammar topic saved:', topic, 'ID:', result.id);

                        const Notifications = (window as any).Notifications;
                        Notifications?.showToast?.(`📚 Тема усвоена: ${topic}`);
                    }
                }
            } catch (e) {
                console.error('[Vocabulary] Failed to save grammar topic:', topic, e);
            }
        }
    }

    private extractWithPattern(text: string, pattern: RegExp, found: VocabularyWord[], hasPron: boolean): void {
        let match: RegExpExecArray | null;
        pattern.lastIndex = 0; // Reset regex state

        while ((match = pattern.exec(text)) !== null) {
            const term = match[1].trim().replace(/[?!]+$/, '').toUpperCase();
            const definition = (hasPron ? match[3] : match[2])?.trim().replace(/[.!?,;]+$/, '').trim();

            if (term && definition && term.length > 1 && definition.length > 1 && !this.loggedWords.has(term)) {
                found.push({ term, definition });
                this.loggedWords.add(term);
            }
        }
    }

    private showProgressAnimation(count: number): void {
        const widget = document.getElementById('progress-widget');
        if (!widget) return;

        const anim = document.createElement('div');
        anim.className = 'progress-anim';
        anim.textContent = `+ ${count} 📚`;
        anim.style.cssText = `
            position: absolute; top: 50 %; left: 50 %;
            transform: translate(-50 %, -50 %) scale(1);
            font - size: 32px; font - weight: bold; color: #22c55e;
            text - shadow: 0 0 20px rgba(34, 197, 94, 0.8);
            animation: progressPop 2s ease - out forwards;
            pointer - events: none; z - index: 100;
            `;

        widget.style.position = 'relative';
        widget.appendChild(anim);
        widget.style.boxShadow = '0 0 20px rgba(34, 197, 94, 0.6)';

        const Notifications = (window as any).Notifications;
        Notifications?.showToast?.(`+ ${count} слов добавлено! 📚`);

        setTimeout(() => {
            anim.remove();
            widget.style.boxShadow = '';
        }, 2000);
    }

    async refreshProgress(): Promise<void> {
        const widget = document.getElementById('progress-widget');
        if (!widget) return;

        const teacherMode = localStorage.getItem('teacherMode') || 'standard';

        // Progress levels only for standard mode
        if (teacherMode !== 'standard') {
            try {
                const res = await fetch('/api/progress');
                const data: ProgressData = await res.json();
                widget.innerHTML = `
                    <div class="progress-mode-info">
                        <div class="mode-info-desc">Прогресс доступен в режиме 📖 Стандарт</div>
                        <div class="total-words">Всего слов: <strong>${data.total_words || 0}</strong></div>
                    </div>
                `;
            } catch {
                widget.innerHTML = '<div class="progress-mode-info"><div class="mode-info-desc">Прогресс доступен в режиме 📖 Стандарт</div></div>';
            }
            return;
        }

        try {
            const res = await fetch('/api/progress');
            const data: ProgressData = await res.json();

            if (data.levels) {
                const currentLevel = (document.getElementById('language-level') as HTMLSelectElement)?.value ?? 'A2';

                let html = '';
                for (const level of data.levels) {
                    const isSpeaker = level.level.endsWith('-S');
                    const baseLevel = isSpeaker ? level.level.slice(0, -2) : level.level;
                    const isCurrent = baseLevel === currentLevel;

                    let badgeClass = '';
                    if (isSpeaker) badgeClass = 'speaker';
                    else if (level.is_certified) badgeClass = 'certified';
                    else if (isCurrent) badgeClass = 'current';

                    html += `
                        <div class="progress-level" title="${level.completed_modules} слов">
                            <span class="level-badge ${badgeClass}">${level.level}</span>
                            <div class="progress-bar-container">
                                <div class="progress-bar-fill${isSpeaker ? ' speaker' : ''}" style="width: ${level.percent}%"></div>
                            </div>
                            <span class="progress-percent">${level.completed_modules}</span>
                            <button class="btn-reset-level" onclick="Vocabulary.resetLevel('${level.level}')" title="Сбросить ${level.level}">🗑️</button>
                        </div>
                    `;
                }
                html += `<div class="total-words">Всего слов: <strong>${data.total_words}</strong></div>`;
                widget.innerHTML = html;
            }
        } catch (e) {
            console.error('[Vocabulary] Failed to refresh:', e);
        }
    }

    async resetLevel(level: string): Promise<void> {
        const Notifications = (window as any).Notifications;

        Notifications?.confirmAction?.(`Сбросить прогресс уровня ${level}?<br><br>Все слова этого уровня будут удалены!`, async () => {
            try {
                const res = await fetch(`/api/progress/reset?level=${level}`, { method: 'DELETE' });
                if (res.ok) {
                    this.loggedWords.clear();
                    this.refreshProgress();
                    Notifications?.showToast?.(`✅ Прогресс ${level} сброшен!`);
                }
            } catch (e) {
                console.error('[Vocabulary] Reset failed:', e);
            }
        });
    }

    clearLogged(): void {
        this.loggedWords.clear();
    }

    private escapeHtml(text: string): string {
        const div = document.createElement('div');
        div.textContent = text;
        return div.innerHTML;
    }

    /**
     * Fix malformed tags (unclosed XML hint/answer tags)
     */
    private fixMalformedTags(text: string): string {
        if (!text) return '';

        // Ensure <hint> is closed (auto-close at next <answer>, <hint>, or end of string)
        let fixed = text.replace(/<hint>([\s\S]*?)(?=<answer>|<hint>|$)/gi, (match, content) => {
            if (!match.includes('</hint>')) return `<hint>${content}</hint>`;
            return match;
        });

        // Ensure <answer> is closed
        fixed = fixed.replace(/<answer>([\s\S]*?)(?=<hint>|$)/gi, (match, content) => {
            if (!match.includes('</answer>')) return `<answer>${content}</answer>`;
            return match;
        });

        return fixed;
    }
    /**
     * Speak text using Gemini TTS ONLY.
     * No fallback to Web Speech API.
     */
    async speakText(text: string, voice: string = 'Puck'): Promise<void> {
        if (!text) return;

        // Clean text for TTS
        const cleanText = this.cleanForTTS(text);
        if (!cleanText) return;

        console.log('[Vocabulary] Speaking (Gemini Only):', cleanText);

        // 1. Check Cache
        const ttsCache = (window as any).__ttsCache as Map<string, string>;
        if (ttsCache && ttsCache.has(cleanText)) {
            console.log('[TTS] Serving from cache');
            const audioData = ttsCache.get(cleanText);
            const AudioPlayback = (window as any).AudioPlayback;
            if (AudioPlayback?.playChunk && audioData) {
                AudioPlayback.playChunk(audioData);
                return;
            }
        }

        try {
            // Get API key
            // Get API key from input field or localStorage
            const apiKeyInput = document.getElementById('api-key') as HTMLInputElement;
            let apiKey = apiKeyInput?.value?.trim() || localStorage.getItem('gemini_api_key') || '';

            // Sync UI if needed
            if (document.getElementById('api-key')) {
                (document.getElementById('api-key') as HTMLInputElement).value = apiKey;
            }

            if (!apiKey) {
                console.warn('[TTS] No API key provided');
                return;
            }

            // 2. Call Gemini API
            const response = await fetch('/api/tts', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    api_key: apiKey,
                    text: cleanText,
                    voice: voice
                })
            });

            // 3. Handle Errors
            if (!response.ok) {
                const errorText = await response.text();
                // Check specifically for 500 which wraps the 429 from backend
                // or just log it.
                if (response.status === 429 || errorText.includes('429') || errorText.includes('RESOURCE_EXHAUSTED')) {
                    console.warn('[TTS] Rate limit exceeded (429). Silence (Fallback disabled).');
                    const Notifications = (window as any).Notifications;
                    Notifications?.showToast?.('⚠️ Rate Limit (Wait 1m).');
                } else {
                    console.error(`[TTS] API Error: ${response.status} - ${errorText}`);
                }
                return; // fail silently
            }

            const data = await response.json();
            if (data.audio) {
                // Cache result
                if (ttsCache) ttsCache.set(cleanText, data.audio);

                const AudioPlayback = (window as any).AudioPlayback;
                AudioPlayback?.playChunk?.(data.audio);
            }

        } catch (e) {
            console.error('[TTS] Failed to generate speech:', e);
            // NO FALLBACK
        }
    }
}

export const Vocabulary = new VocabularyModule();

// Global exports
if (typeof window !== 'undefined') {
    (window as any).Vocabulary = Vocabulary;
    (window as any).formatVocabularyMessage = (t: string) => Vocabulary.formatMessage(t);
    (window as any).populateSeenWordsFromHistory = (m: any[]) => Vocabulary.populateFromHistory(m);
    (window as any).extractAndLogVocabulary = (t: string) => Vocabulary.extractAndLog(t);
    (window as any).refreshProgress = () => Vocabulary.refreshProgress();
    (window as any).resetLevelProgress = (l: string) => Vocabulary.resetLevel(l);
    (window as any).loadLearnedWords = () => Vocabulary.loadLearnedWords();
    (window as any).speakText = (text: string, voice?: string) => Vocabulary.speakText(text, voice);

    // Hint/Answer reveal function — works during streaming, finalized, and TTS playback
    // Supports TOGGLE: click again to collapse panel
    (window as any).revealHint = (containerId: string, type: 'hint' | 'answer', event?: Event) => {
        // Find container: prefer event.target.closest() (works with duplicate IDs), fallback to getElementById
        let container: HTMLElement | null = null;
        if (event && event.target) {
            container = (event.target as HTMLElement).closest('.hint-container') as HTMLElement;
        }
        if (!container) {
            container = document.getElementById(containerId);
        }
        if (!container) return;

        const hintBtn = container.querySelector('.hint-btn-hint') as HTMLElement;
        const answerBtn = container.querySelector('.hint-btn-answer') as HTMLElement;
        const hintText = container.querySelector('[data-type="hint"]') as HTMLElement;
        const answerText = container.querySelector('[data-type="answer"]') as HTMLElement;

        if (type === 'hint') {
            if (hintText) {
                // Toggle: if already visible, collapse it
                if (!hintText.classList.contains('hidden')) {
                    hintText.classList.add('hidden');
                    if (hintBtn) { hintBtn.classList.remove('used', 'hidden'); }
                    if (answerBtn) { answerBtn.classList.add('hidden'); }
                } else {
                    // Reveal hint, show answer button
                    hintText.classList.remove('hidden');
                    if (hintBtn) hintBtn.classList.add('used', 'hidden');
                    if (answerBtn) answerBtn.classList.remove('hidden');
                }
            }
        } else if (type === 'answer') {
            if (answerText) {
                // Toggle: if already visible, collapse it
                if (!answerText.classList.contains('hidden')) {
                    answerText.classList.add('hidden');
                    if (answerBtn) { answerBtn.classList.remove('used', 'hidden'); }
                } else {
                    // Reveal answer
                    answerText.classList.remove('hidden');
                    if (answerBtn) answerBtn.classList.add('used', 'hidden');
                }
            }
        }

        // Smooth scroll to keep content in view after reveal/collapse
        const chatContainer = document.getElementById('chat-messages');
        if (chatContainer) {
            requestAnimationFrame(() => {
                const blockEl = container!.closest('.dialogue-block');
                if (blockEl) {
                    blockEl.scrollIntoView({ behavior: 'smooth', block: 'nearest' });
                }
            });
        }
    };

    // TTS audio cache - stores audio data by text to avoid repeated API calls
    const ttsCache: Map<string, string> = (window as any).__ttsCache || new Map();
    (window as any).__ttsCache = ttsCache;

    // Inline TTS: speak the text from the previous sibling span (answer-german, answer-translation, etc.)
    (window as any).speakThisText = async (button: HTMLElement) => {
        const btn = button as HTMLButtonElement;
        // Find the previous sibling element (the text span)
        const prevEl = btn.previousElementSibling as HTMLElement;
        if (!prevEl) return;
        const text = prevEl.textContent?.trim() || '';
        if (!text) return;

        // Visual feedback
        const original = btn.textContent;
        btn.textContent = '⏳';
        btn.disabled = true;

        try {
            await Vocabulary.speakText(text);
            btn.textContent = '✅';
            setTimeout(() => { btn.textContent = original || '🔊'; btn.disabled = false; }, 1500);
        } catch (e) {
            btn.textContent = '❌';
            setTimeout(() => { btn.textContent = original || '🔊'; btn.disabled = false; }, 2000);
        }
    };

    // Speak German text from dialogue-content (excluding translation and TTS buttons)
    (window as any).speakDialogueGerman = async (button: HTMLElement) => {
        const btn = button as HTMLButtonElement;
        const dialogueContent = btn.closest('.dialogue-content') || btn.closest('.dialogue-block')?.querySelector('.dialogue-content');
        if (!dialogueContent) return;

        // Clone and remove non-German elements (translations in parentheses, TTS bar, hints)
        const clone = dialogueContent.cloneNode(true) as HTMLElement;
        clone.querySelectorAll('.translation, .translation-block, .tts-inline-btn, .tts-bar, .hint-container, .enrichment-loader').forEach(el => el.remove());
        // Also remove parenthesized text (translations are in (...) with Cyrillic)
        let germanText = clone.textContent?.trim() || '';
        germanText = germanText.replace(/\([^)]*[А-Яа-яЁё][^)]*\)/g, '').trim();
        if (!germanText) return;

        const original = btn.innerHTML;
        btn.textContent = '⏳';
        btn.disabled = true;

        try {
            await Vocabulary.speakText(germanText);
            btn.textContent = '✅';
            setTimeout(() => { btn.innerHTML = original; btn.disabled = false; }, 1500);
        } catch (e) {
            btn.textContent = '❌';
            setTimeout(() => { btn.innerHTML = original; btn.disabled = false; }, 2000);
        }
    };

    // Speak the translation (Russian text in parentheses) from dialogue-content
    (window as any).speakDialogueTranslation = async (button: HTMLElement) => {
        const btn = button as HTMLButtonElement;
        const dialogueContent = btn.closest('.dialogue-content') || btn.closest('.dialogue-block')?.querySelector('.dialogue-content');
        if (!dialogueContent) return;

        // Extract text in parentheses containing Cyrillic characters (= Russian translation)
        const fullText = dialogueContent.textContent || '';
        const matches = fullText.match(/\(([^)]*[А-Яа-яЁё][^)]*)\)/g);
        if (!matches || matches.length === 0) return;
        // Join all translation parentheses, strip outer brackets
        const translationText = matches.map(m => m.replace(/^\(|\)$/g, '')).join('. ').trim();
        if (!translationText) return;

        const original = btn.innerHTML;
        btn.textContent = '⏳';
        btn.disabled = true;

        try {
            await Vocabulary.speakText(translationText);
            btn.textContent = '✅';
            setTimeout(() => { btn.innerHTML = original; btn.disabled = false; }, 1500);
        } catch (e) {
            btn.textContent = '❌';
            setTimeout(() => { btn.innerHTML = original; btn.disabled = false; }, 2000);
        }
    };

    // TTS playback for dialogue blocks using Gemini TTS API
    (window as any).playDialogueText = async (button: HTMLElement) => {
        // Find the dialogue block
        const dialogueBlock = button.closest('.dialogue-block');
        if (!dialogueBlock) return;

        // Get German text from dialogue-content (not translation)
        const dialogueContent = dialogueBlock.querySelector('.dialogue-content');
        if (!dialogueContent) return;

        // Clone and remove translation spans to get only German text
        const clone = dialogueContent.cloneNode(true) as HTMLElement;
        clone.querySelectorAll('.translation').forEach(el => el.remove());
        const germanText = clone.textContent?.trim() || '';

        if (!germanText) return;

        // Visual feedback - loading
        const originalContent = button.textContent;
        button.textContent = '⏳';
        button.setAttribute('disabled', 'true');

        try {
            let audioData: string;

            // Check cache first
            if (ttsCache.has(germanText)) {
                console.log('[TTS] Using cached audio');
                audioData = ttsCache.get(germanText)!;
            } else {
                // Get API key from settings (stored as 'gemini_api_key')
                const apiKey = localStorage.getItem('gemini_api_key') || '';
                if (!apiKey) {
                    throw new Error('API key not found in gemini_api_key');
                }

                // Call Gemini TTS API
                const selectedVoice = (document.getElementById('voice-select') as HTMLSelectElement)?.value || 'Zephyr';
                const response = await fetch('/api/tts', {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify({
                        api_key: apiKey,
                        text: germanText,
                        voice: selectedVoice // Use user-selected voice (not hardcoded)
                    })
                });

                if (!response.ok) {
                    throw new Error(`TTS API error: ${response.status}`);
                }

                const data = await response.json();
                audioData = data.audio;

                // Cache the audio for future use
                ttsCache.set(germanText, audioData);
                console.log('[TTS] Audio cached, cache size:', ttsCache.size);
            }

            // Gemini TTS returns raw PCM (24kHz, 16-bit, mono)
            // Need to use AudioContext to play it
            const pcmBytes = Uint8Array.from(atob(audioData), c => c.charCodeAt(0));

            // Convert PCM16 to Float32 for AudioContext
            const audioContext = new AudioContext({ sampleRate: 24000 });
            const numSamples = pcmBytes.length / 2; // 16-bit = 2 bytes per sample
            const audioBuffer = audioContext.createBuffer(1, numSamples, 24000);
            const channelData = audioBuffer.getChannelData(0);

            const dataView = new DataView(pcmBytes.buffer);
            for (let i = 0; i < numSamples; i++) {
                // PCM16 little-endian to float [-1, 1]
                const sample = dataView.getInt16(i * 2, true);
                channelData[i] = sample / 32768.0;
            }

            // Play using AudioBufferSourceNode with playback rate control
            const source = audioContext.createBufferSource();
            source.buffer = audioBuffer;

            // Apply playback rate (speed control)
            // 0.8 = slower, 1.0 = normal, 1.2 = faster
            // Get from global setting or default to 1.0
            const playbackRate = (window as any).ttsPlaybackRate || 1.0;
            source.playbackRate.value = playbackRate;

            // Apply volume from app settings (0.0 to 1.0)
            const volumeStr = localStorage.getItem('app_volume');
            const volumeFloat = volumeStr ? parseInt(volumeStr, 10) / 100 : 1.0;
            
            const gainNode = audioContext.createGain();
            gainNode.gain.value = volumeFloat;

            source.connect(gainNode);
            gainNode.connect(audioContext.destination);

            // ====== KARAOKE HIGHLIGHTING DURING TTS PLAYBACK ======
            try {
                // Find karaoke words inside the dialogue content
                const karaokeWords = Array.from(
                    (dialogueContent as HTMLElement).querySelectorAll('.karaoke-word')
                );
                if (karaokeWords.length > 0) {
                    // Estimate total playback duration
                    const durationMs = (numSamples / 24000 / playbackRate) * 1000;
                    
                    // Improved intonation: calculate timing based on word length
                    let totalChars = 0;
                    karaokeWords.forEach(w => {
                        const text = w.textContent || '';
                        totalChars += text.length;
                        // Add extra weight for punctuation to simulate pauses
                        if (/[.,!?:;]/.test(text)) totalChars += 3;
                    });
                    
                    // Distribute time per "character weight" + a small gap per word
                    const weightPerChar = durationMs / Math.max(1, totalChars + karaokeWords.length * 1.5);

                    // Highlight parent dialogue block
                    const parentBlock = (dialogueContent as HTMLElement).closest('.dialogue-block');
                    if (parentBlock) {
                        parentBlock.classList.add('dialogue-block-active');
                    }

                    let accumulatedDelayMs = 0;
                    karaokeWords.forEach((word) => {
                        const wordDelay = accumulatedDelayMs;
                        
                        // Calculate next delay
                        const text = word.textContent || '';
                        let charsWeight = text.length;
                        if (/[.,!?:;]/.test(text)) charsWeight += 3;
                        accumulatedDelayMs += (charsWeight + 1.5) * weightPerChar;

                        setTimeout(() => {
                            try {
                                (word as HTMLElement).classList.add('karaoke-active');
                                (word as HTMLElement).classList.add('karaoke-spoken');
                                setTimeout(() => {
                                    (word as HTMLElement).classList.remove('karaoke-active');
                                }, 300);
                                // Auto-scroll to follow the word
                                const chatContainer = document.getElementById('chat-messages');
                                const scrollFollowEnabled = (window as unknown as { scrollFollowMode?: boolean }).scrollFollowMode !== false;
                                if (scrollFollowEnabled && chatContainer) {
                                    const containerRect = chatContainer.getBoundingClientRect();
                                    const wordRect = (word as HTMLElement).getBoundingClientRect();
                                    const viewportBottom = containerRect.top + containerRect.height * 0.7;
                                    if (wordRect.top > viewportBottom || wordRect.bottom < containerRect.top + 50) {
                                        chatContainer.scrollTo({
                                            top: chatContainer.scrollTop + (wordRect.top - containerRect.top) - (containerRect.height * 0.3),
                                            behavior: 'smooth'
                                        });
                                    }
                                }
                            } catch (_e) { /* karaoke error is non-fatal */ }
                        }, wordDelay);
                    });
                }
            } catch (_e) {
                console.warn('[TTS] Karaoke highlighting error (non-fatal):', _e);
            }

            // Update button when playing/done
            button.textContent = '🔊';
            source.onended = () => {
                button.textContent = originalContent || '🔊';
                button.removeAttribute('disabled');
                audioContext.close();
                // Remove active states when playback ends
                const parentBlock = (dialogueContent as HTMLElement).closest('.dialogue-block');
                if (parentBlock) parentBlock.classList.remove('dialogue-block-active');
            };

            source.start();
        } catch (error) {
            console.error('[TTS] Gemini TTS error:', error);
            button.textContent = '❌';
            button.removeAttribute('disabled');

            // Fallback to Web Speech API
            if ('speechSynthesis' in window) {
                console.log('[TTS] Falling back to Web Speech API');
                window.speechSynthesis.cancel();
                const utterance = new SpeechSynthesisUtterance(germanText);
                utterance.lang = 'de-DE';
                utterance.rate = 0.9;
                button.textContent = '🔊';
                utterance.onend = () => { button.textContent = originalContent || '🔊'; };
                window.speechSynthesis.speak(utterance);
            } else {
                setTimeout(() => { button.textContent = originalContent || '🔊'; }, 2000);
            }
        }
    };
    // TTS playback for translation blocks using Web Speech API
    (window as any).playTranslationText = (button: HTMLElement) => {
        const transBlock = button.closest('.translation-block');
        if (!transBlock) return;

        const transTextNode = transBlock.querySelector('.translation-text');
        const text = transTextNode?.textContent?.trim() || '';
        if (!text) return;

        // Visual feedback
        const originalContent = button.textContent;
        button.textContent = '⏳';
        button.setAttribute('disabled', 'true');

        if ('speechSynthesis' in window) {
            window.speechSynthesis.cancel();
            const utterance = new SpeechSynthesisUtterance(text);
            
            // Try to detect translation language from settings or use Russian as default fallback
            // (Since the app translates to the user's native language)
            const getNativeLangCode = (window as any).LanguagePicker?.getNativeLanguageCode;
            utterance.lang = getNativeLangCode ? getNativeLangCode() : 'ru-RU';
            
            const playbackRate = (window as any).ttsPlaybackRate || 1.0;
            utterance.rate = playbackRate;

            button.textContent = '🔊';
            
            utterance.onend = () => { 
                button.textContent = originalContent || '🔊'; 
                button.removeAttribute('disabled');
            };
            
            utterance.onerror = (e) => {
                console.error('[TTS] Translation playback error:', e);
                button.textContent = '❌';
                setTimeout(() => { 
                    button.textContent = originalContent || '🔊'; 
                    button.removeAttribute('disabled');
                }, 2000);
            };

            window.speechSynthesis.speak(utterance);
        } else {
            console.error('[TTS] Web Speech API not supported');
            button.textContent = '❌';
            setTimeout(() => { 
                button.textContent = originalContent || '🔊'; 
                button.removeAttribute('disabled');
            }, 2000);
        }
    };
}

