/**
 * Application state management
 */

export interface Attachment {
    name: string;
    type: string;
    data: string;
    preview: string | null;
}

export interface ConversationMessage {
    role: 'user' | 'model';
    parts?: { text: string }[];
    text?: string;
}

export interface AppState {
    // Connection
    ws: WebSocket | null;
    isConnected: boolean;
    isPlaying: boolean;
    mediaStream: MediaStream | null;

    // Session
    currentChatId: string;
    conversationHistory: ConversationMessage[];
    pendingAttachments: Attachment[];
    lastUserInput: string; // Last user voice/text input for Continue resend

    // Camera
    currentFacingMode: 'user' | 'environment';

    // Intervals
    keepaliveInterval: number | null;
}

// Global state instance
let state: AppState = {
    ws: null,
    isConnected: false,
    isPlaying: false,
    mediaStream: null,
    currentChatId: '',
    conversationHistory: [],
    pendingAttachments: [],
    lastUserInput: '',
    currentFacingMode: 'user',
    keepaliveInterval: null,
};

export function getState(): AppState {
    return state;
}

export function setState(updates: Partial<AppState>): void {
    state = { ...state, ...updates };
}

// Convenience setters
export function setConnected(connected: boolean): void {
    state.isConnected = connected;
}

export function setPlaying(playing: boolean): void {
    state.isPlaying = playing;
}

export function setWebSocket(ws: WebSocket | null): void {
    state.ws = ws;
}

export function addToHistory(message: ConversationMessage): void {
    state.conversationHistory.push(message);
}

export function appendToLastModelHistory(text: string): void {
    for (let i = state.conversationHistory.length - 1; i >= 0; i--) {
        if (state.conversationHistory[i].role === 'model') {
            const msg = state.conversationHistory[i];
            if (msg.parts && msg.parts.length > 0) {
                msg.parts[0].text += '\n\n' + text;
            } else if (msg.text !== undefined) {
                msg.text += '\n\n' + text;
            } else {
                msg.text = text;
            }
            break;
        }
    }
}

export function updateLastModelHistoryText(text: string): void {
    for (let i = state.conversationHistory.length - 1; i >= 0; i--) {
        if (state.conversationHistory[i].role === 'model') {
            const msg = state.conversationHistory[i];
            if (msg.parts && msg.parts.length > 0) {
                msg.parts[0].text = text;
            } else {
                msg.text = text;
            }
            break;
        }
    }
}

export function clearHistory(): void {
    state.conversationHistory = [];
}

export function addAttachment(attachment: Attachment): void {
    state.pendingAttachments.push(attachment);
}

export function clearAttachments(): void {
    state.pendingAttachments = [];
}
