/**
 * Chat Sessions Module - Manages chat list and messages persistence in localStorage
 */

export interface ChatMessage {
    role: 'user' | 'ai' | 'system';
    text: string;
    timestamp: number;
}

export interface ChatSession {
    id: string;
    title: string;
    createdAt: number;
    lastMessageAt: number;
    preview: string;  // First few words of last message
    messages: ChatMessage[];
    language?: string; // Target language for this session
    mode?: string;     // Teacher mode: standard, active, grammar
    level?: string;    // CEFR level: A1-C2
}

const STORAGE_KEY = 'gemini_chat_sessions';
const CURRENT_CHAT_KEY = 'gemini_current_chat_id';
const MAX_SESSIONS = 50;

/**
 * Get all saved chat sessions
 */
export function getSessions(): ChatSession[] {
    try {
        const data = localStorage.getItem(STORAGE_KEY);
        return data ? JSON.parse(data) : [];
    } catch {
        return [];
    }
}

/**
 * Save sessions to localStorage
 */
function saveSessions(sessions: ChatSession[]): void {
    try {
        // Keep only last MAX_SESSIONS
        const trimmed = sessions.slice(0, MAX_SESSIONS);
        localStorage.setItem(STORAGE_KEY, JSON.stringify(trimmed));
    } catch (e) {
        console.error('[ChatSessions] Failed to save:', e);
    }
}

/**
 * Get current active chat ID
 */
export function getCurrentChatId(): string {
    return localStorage.getItem(CURRENT_CHAT_KEY) || '';
}

/**
 * Set current active chat ID
 */
export function setCurrentChatId(id: string): void {
    localStorage.setItem(CURRENT_CHAT_KEY, id);
}

/**
 * Get a specific session by ID
 */
export function getSession(id: string): ChatSession | undefined {
    return getSessions().find(s => s.id === id);
}

/**
 * Create or update a chat session
 */
export function saveSession(id: string, preview: string, language?: string, mode?: string, level?: string): void {
    const sessions = getSessions();
    const now = Date.now();

    const existing = sessions.find(s => s.id === id);

    if (existing) {
        existing.lastMessageAt = now;
        existing.preview = preview.substring(0, 60);
        // Move to top
        const index = sessions.indexOf(existing);
        sessions.splice(index, 1);
        sessions.unshift(existing);
    } else {
        // New session
        const title = new Date(now).toLocaleString('ru-RU', {
            day: 'numeric',
            month: 'short',
            hour: '2-digit',
            minute: '2-digit'
        });
        sessions.unshift({
            id,
            title,
            createdAt: now,
            lastMessageAt: now,
            preview: preview.substring(0, 60),
            messages: [],
            language: language || undefined,
            mode: mode || undefined,
            level: level || undefined,
        });
    }

    saveSessions(sessions);
    setCurrentChatId(id);
    renderSessionList();
}

/**
 * Save a message to a chat session
 */
export function saveMessage(chatId: string, role: 'user' | 'ai' | 'system', text: string): void {
    const sessions = getSessions();
    let session = sessions.find(s => s.id === chatId);

    if (!session) {
        // Create new session if doesn't exist
        const now = Date.now();
        session = {
            id: chatId,
            title: new Date(now).toLocaleString('ru-RU', {
                day: 'numeric',
                month: 'short',
                hour: '2-digit',
                minute: '2-digit'
            }),
            createdAt: now,
            lastMessageAt: now,
            preview: text.substring(0, 60),
            messages: []
        };
        sessions.unshift(session);
    }

    // Add message
    session.messages.push({
        role,
        text,
        timestamp: Date.now()
    });

    // Update preview and timestamp
    if (role !== 'system') {
        session.preview = text.substring(0, 60);
        session.lastMessageAt = Date.now();
    }

    // Keep only last 100 messages per chat to save space
    if (session.messages.length > 100) {
        session.messages = session.messages.slice(-100);
    }

    saveSessions(sessions);
    renderSessionList();
}

/**
 * Remove the last message from a chat session
 */
export function removeLastMessage(chatId: string): void {
    const sessions = getSessions();
    const session = sessions.find(s => s.id === chatId);
    if (!session || session.messages.length === 0) return;

    session.messages.pop();
    
    if (session.messages.length > 0) {
        const lastMsg = session.messages[session.messages.length - 1];
        session.preview = lastMsg.text.substring(0, 60);
    } else {
        session.preview = 'No messages';
    }
    
    saveSessions(sessions);
    // Silent update, no need to list render extensively
}

/**
 * Append text to the last AI message
 */
export function appendToLastAiMessage(chatId: string, text: string): void {
    const sessions = getSessions();
    const session = sessions.find(s => s.id === chatId);
    if (!session || session.messages.length === 0) return;

    for (let i = session.messages.length - 1; i >= 0; i--) {
        if (session.messages[i].role === 'ai') {
            session.messages[i].text += '\n\n' + text;
            session.preview = session.messages[i].text.substring(0, 60);
            saveSessions(sessions);
            renderSessionList();
            break;
        }
    }
}

/**
 * Replace text of the last AI message
 */
export function updateLastAiMessageText(chatId: string, newText: string): void {
    const sessions = getSessions();
    const session = sessions.find(s => s.id === chatId);
    if (!session || session.messages.length === 0) return;

    for (let i = session.messages.length - 1; i >= 0; i--) {
        if (session.messages[i].role === 'ai') {
            session.messages[i].text = newText;
            session.preview = session.messages[i].text.substring(0, 60);
            saveSessions(sessions);
            renderSessionList();
            break;
        }
    }
}

/**
 * Get messages for a chat session
 */
export function getMessages(chatId: string): ChatMessage[] {
    const session = getSession(chatId);
    return session?.messages || [];
}

/**
 * Delete a chat session
 */
export function deleteSession(id: string): void {
    const sessions = getSessions().filter(s => s.id !== id);
    saveSessions(sessions);

    // If deleted current chat, clear it
    if (getCurrentChatId() === id) {
        setCurrentChatId('');
    }

    renderSessionList();
}

/**
 * Render session list in sidebar
 */
export function renderSessionList(): void {
    const container = document.getElementById('history-list');
    if (!container) return;

    const sessions = getSessions();
    const currentId = getCurrentChatId();

    if (sessions.length === 0) {
        container.innerHTML = '<div class="empty-history">No chats yet</div>';
        return;
    }

    container.innerHTML = sessions.map(session => {
        const langFlag = session.language ? LANGUAGE_FLAGS[session.language] || '' : '';
        const langName = session.language || '';
        const modeIcon = session.mode === 'active' ? '🎭' : session.mode === 'grammar' ? '📚' : '📖';
        const levelStr = session.level || '';
        const dateStr = formatRelativeDate(session.lastMessageAt || session.createdAt);

        // Compact info line: 🇩🇪 German • A2 📖 • Feb 28
        const infoLine = [
            langFlag && langName ? `${langFlag} ${langName}` : '',
            levelStr ? `${levelStr} ${modeIcon}` : '',
            dateStr
        ].filter(Boolean).join(' • ');

        // Clean preview to prevent HTML injection breaking the layout
        const rawPreview = session.preview || 'No messages';
        const cleanPreview = rawPreview
            .replace(/<[^>]*>?/gm, '') // Remove HTML tags
            .replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;')
            .substring(0, 60);

        return `
        <div class="history-item ${session.id === currentId ? 'active' : ''}" data-id="${session.id}">
            <div class="history-item-content">
                <div class="history-item-title">${session.title}</div>
                <div class="history-item-meta">${infoLine}</div>
                <div class="history-item-preview">${cleanPreview}</div>
            </div>
            <div class="history-item-actions">
                <button class="history-item-edit" title="Rename" data-id="${session.id}">✏️</button>
                <button class="history-item-delete" title="Delete" data-id="${session.id}">×</button>
            </div>
        </div>
    `}).join('');

    // Add click handlers
    container.querySelectorAll('.history-item').forEach(item => {
        // Edit button
        item.querySelector('.history-item-edit')?.addEventListener('click', (e) => {
            e.stopPropagation();
            e.preventDefault();
            const id = (e.target as HTMLElement).dataset.id;
            if (id) showRenameDialog(id);
        });

        // Delete button
        item.querySelector('.history-item-delete')?.addEventListener('click', (e) => {
            e.stopPropagation();
            e.preventDefault();
            const id = (e.target as HTMLElement).dataset.id;
            if (id) showDeleteConfirmation(id, e.target as HTMLElement);
        });

        // Click to load
        item.addEventListener('click', (e) => {
            const target = e.target as HTMLElement;
            if (!target.classList.contains('history-item-delete') &&
                !target.classList.contains('history-item-edit')) {
                const id = (item as HTMLElement).dataset.id;
                if (id) loadSession(id);
            }
        });
    });
}

/**
 * Show inline delete confirmation
 */
function showDeleteConfirmation(id: string, _button: HTMLElement): void {
    // Check if confirmation already showing
    const existing = document.querySelector('.delete-confirm-modal');
    if (existing) existing.remove();

    // Create modal
    const modal = document.createElement('div');
    modal.className = 'delete-confirm-modal';
    modal.innerHTML = `
        <div class="delete-confirm-content">
            <p>Удалить этот чат?</p>
            <div class="delete-confirm-buttons">
                <button class="confirm-yes">Да</button>
                <button class="confirm-no">Нет</button>
            </div>
        </div>
    `;

    // Position near button
    document.body.appendChild(modal);

    // Add styles if not exist
    if (!document.getElementById('delete-confirm-style')) {
        const style = document.createElement('style');
        style.id = 'delete-confirm-style';
        style.textContent = `
            .delete-confirm-modal {
                position: fixed;
                top: 0;
                left: 0;
                right: 0;
                bottom: 0;
                background: rgba(0,0,0,0.5);
                display: flex;
                align-items: center;
                justify-content: center;
                z-index: 9999;
            }
            .delete-confirm-content {
                background: var(--surface-color, #1e1e2e);
                padding: 20px 30px;
                border-radius: 12px;
                text-align: center;
                box-shadow: 0 4px 20px rgba(0,0,0,0.5);
            }
            .delete-confirm-content p {
                margin: 0 0 15px 0;
                font-size: 16px;
                color: var(--text-color, #fff);
            }
            .delete-confirm-buttons {
                display: flex;
                gap: 10px;
                justify-content: center;
            }
            .delete-confirm-buttons button {
                padding: 8px 24px;
                border: none;
                border-radius: 6px;
                cursor: pointer;
                font-size: 14px;
                transition: opacity 0.2s;
            }
            .delete-confirm-buttons button:hover {
                opacity: 0.8;
            }
            .confirm-yes {
                background: #e74c3c;
                color: white;
            }
            .confirm-no {
                background: #555;
                color: white;
            }
        `;
        document.head.appendChild(style);
    }

    // Event handlers
    modal.querySelector('.confirm-yes')?.addEventListener('click', () => {
        deleteSession(id);
        modal.remove();
    });

    modal.querySelector('.confirm-no')?.addEventListener('click', () => {
        modal.remove();
    });

    // Close on backdrop click
    modal.addEventListener('click', (e) => {
        if (e.target === modal) modal.remove();
    });
}

/**
 * Rename a chat session
 */
export function renameSession(id: string, newTitle: string): void {
    const sessions = getSessions();
    const session = sessions.find(s => s.id === id);
    if (session) {
        session.title = newTitle.trim() || session.title;
        saveSessions(sessions);
        renderSessionList();
    }
}

/**
 * Show rename dialog for a chat
 */
function showRenameDialog(id: string): void {
    const session = getSession(id);
    if (!session) return;

    // Remove existing modal
    const existing = document.querySelector('.rename-modal');
    if (existing) existing.remove();

    // Create modal
    const modal = document.createElement('div');
    modal.className = 'rename-modal';
    modal.innerHTML = `
        <div class="rename-modal-content">
            <p>Переименовать чат</p>
            <input type="text" class="rename-input" value="${session.title}" placeholder="Название чата" />
            <div class="rename-buttons">
                <button class="rename-save">Сохранить</button>
                <button class="rename-cancel">Отмена</button>
            </div>
        </div>
    `;

    document.body.appendChild(modal);

    // Add styles if not exist
    if (!document.getElementById('rename-modal-style')) {
        const style = document.createElement('style');
        style.id = 'rename-modal-style';
        style.textContent = `
            .rename-modal {
                position: fixed;
                top: 0;
                left: 0;
                right: 0;
                bottom: 0;
                background: rgba(0,0,0,0.6);
                display: flex;
                align-items: center;
                justify-content: center;
                z-index: 9999;
            }
            .rename-modal-content {
                background: var(--surface-color, #1e1e2e);
                padding: 24px;
                border-radius: 12px;
                min-width: 300px;
                box-shadow: 0 4px 20px rgba(0,0,0,0.5);
            }
            .rename-modal-content p {
                margin: 0 0 15px 0;
                font-size: 16px;
                color: var(--text-color, #fff);
                font-weight: 600;
            }
            .rename-input {
                width: 100%;
                padding: 10px 12px;
                border: 1px solid #444;
                border-radius: 8px;
                background: #2a2a3a;
                color: #fff;
                font-size: 14px;
                box-sizing: border-box;
                margin-bottom: 15px;
            }
            .rename-input:focus {
                outline: none;
                border-color: var(--accent, #6366f1);
            }
            .rename-buttons {
                display: flex;
                gap: 10px;
                justify-content: flex-end;
            }
            .rename-buttons button {
                padding: 8px 20px;
                border: none;
                border-radius: 6px;
                cursor: pointer;
                font-size: 14px;
                transition: opacity 0.2s;
            }
            .rename-save {
                background: var(--accent, #6366f1);
                color: white;
            }
            .rename-cancel {
                background: #555;
                color: white;
            }
            .rename-buttons button:hover {
                opacity: 0.85;
            }
        `;
        document.head.appendChild(style);
    }

    // Focus input
    const input = modal.querySelector('.rename-input') as HTMLInputElement;
    input?.focus();
    input?.select();

    // Event handlers
    modal.querySelector('.rename-save')?.addEventListener('click', () => {
        const newTitle = input.value.trim();
        if (newTitle) {
            renameSession(id, newTitle);
        }
        modal.remove();
    });

    modal.querySelector('.rename-cancel')?.addEventListener('click', () => {
        modal.remove();
    });

    // Enter key
    input?.addEventListener('keypress', (e) => {
        if (e.key === 'Enter') {
            const newTitle = input.value.trim();
            if (newTitle) {
                renameSession(id, newTitle);
            }
            modal.remove();
        }
    });

    // Close on backdrop click
    modal.addEventListener('click', (e) => {
        if (e.target === modal) modal.remove();
    });

    // Escape key
    modal.addEventListener('keydown', (e) => {
        if (e.key === 'Escape') modal.remove();
    });
}

/**
 * Load a session and display its messages
 */
export function loadSession(id: string): void {
    console.log('[ChatSessions] Loading session:', id);

    // Update active state
    setCurrentChatId(id);
    document.querySelectorAll('.history-item').forEach(item => {
        item.classList.toggle('active', (item as HTMLElement).dataset.id === id);
    });

    // Clear current chat display
    const chatContainer = document.getElementById('chat-messages');
    if (!chatContainer) return;
    chatContainer.innerHTML = '';

    // Load messages from storage
    const messages = getMessages(id);
    console.log('[ChatSessions] Loading', messages.length, 'messages');

    // Render messages with proper structure (matching streaming-display format)
    messages.forEach(msg => {
        const msgDiv = document.createElement('div');
        msgDiv.className = `message ${msg.role}`;

        // Use message-bubble class to match streaming display format
        const bubbleDiv = document.createElement('div');
        bubbleDiv.className = msg.role === 'ai' ? 'message-bubble karaoke-text' : 'message-bubble';
        // AI messages: re-format through Vocabulary to restore styled dialogue blocks,
        // translations, and hint/answer buttons. This is needed because enrichment.ts
        // overwrites saved HTML with raw text via updateLastAiMessageText().
        if (msg.role === 'ai' && typeof (window as any).Vocabulary?.formatMessage === 'function') {
            // Strip any existing HTML tags first to get clean text for re-formatting
            const rawText = msg.text.replace(/<[^>]*>/g, '').trim();
            // If text looks like it has REPLICA markers or is unformatted, re-format it
            if (rawText.includes('REPLICA') || rawText.includes('Граммини') || !msg.text.includes('dialogue-block')) {
                bubbleDiv.innerHTML = (window as any).Vocabulary.formatMessage(msg.text);
            } else {
                // Already formatted HTML — use as-is
                bubbleDiv.innerHTML = msg.text;
            }
        } else {
            bubbleDiv.innerHTML = msg.text;
        }
        msgDiv.appendChild(bubbleDiv);

        const timeDiv = document.createElement('div');
        timeDiv.className = 'message-time';
        timeDiv.textContent = new Date(msg.timestamp).toLocaleTimeString();
        msgDiv.appendChild(timeDiv);

        chatContainer.appendChild(msgDiv);
    });

    // DISABLED: Auto-scroll - user controls scroll via floating button
    // chatContainer.scrollTop = chatContainer.scrollHeight;

    // Update app state
    if ((window as any).AppState) {
        (window as any).AppState.setState({ currentChatId: id });
    }
}

/**
 * Initialize on page load
 */
export function initChatSessions(): void {
    renderSessionList();

    // Restore last active chat
    const currentId = getCurrentChatId();
    if (currentId) {
        const session = getSession(currentId);
        if (session) {
            loadSession(currentId);
        }
    }

    console.log('[ChatSessions] Initialized with', getSessions().length, 'sessions');
}

