/**
 * Chat module - Message display and management
 */

import { getElements } from '../core/elements';
import { getState, addToHistory, setState } from '../core/state';
import { Vocabulary } from '../api/vocabulary';
import { saveMessage, getCurrentChatId } from './chat-sessions';

// Track new messages for floating button
let newMessageCount = 0;
// Track if user is "pinned" to bottom (auto-scroll enabled)
let isPinnedToBottom = true;

// Expose isPinnedToBottom for streaming-display.ts
(window as unknown as { isPinnedToBottom: boolean }).isPinnedToBottom = isPinnedToBottom;

/**
 * Auto-scroll to bottom if user is pinned (for use by streaming-display)
 */
export function autoScrollIfPinned(): void {
    if (isPinnedToBottom) {
        const container = document.getElementById('chat-messages');
        if (container) {
            requestAnimationFrame(() => {
                container.scrollTop = container.scrollHeight;
            });
        }
    }
}

// Expose globally for streaming-display
(window as unknown as { autoScrollIfPinned: () => void }).autoScrollIfPinned = autoScrollIfPinned;

/**
 * Increment new message counter and show floating button
 */
function incrementNewMessageCount(): void {
    newMessageCount++;
    updateScrollButton();
}

/**
 * Update the scroll-to-bottom button visibility and counter
 * Also auto-scroll if user is pinned to bottom
 */
function updateScrollButton(): void {
    const container = document.getElementById('chat-messages');
    const btn = document.getElementById('scroll-to-bottom-btn');
    const counter = document.getElementById('new-message-count');

    if (!container || !btn) return;

    if (isPinnedToBottom) {
        // User is pinned - always scroll to bottom on new messages
        btn.classList.add('hidden');
        newMessageCount = 0;
        // Use requestAnimationFrame to ensure DOM is updated BEFORE scrolling
        requestAnimationFrame(() => {
            container.scrollTop = container.scrollHeight;
        });
    } else if (newMessageCount > 0) {
        // User scrolled up, show button with counter
        btn.classList.remove('hidden');
        if (counter) {
            counter.textContent = newMessageCount.toString();
            counter.style.display = newMessageCount > 0 ? 'flex' : 'none';
        }
    }
}

/**
 * Handle user scroll - detect if they scrolled away from bottom
 */
function handleUserScroll(): void {
    const container = document.getElementById('chat-messages');
    if (!container) return;

    const distanceFromBottom = container.scrollHeight - container.scrollTop - container.clientHeight;
    const threshold = 100; // 100px threshold

    // If user scrolls up more than threshold, unpin
    if (distanceFromBottom > threshold) {
        isPinnedToBottom = false;
        (window as unknown as { isPinnedToBottom: boolean }).isPinnedToBottom = false;
    }
    // If user scrolls to bottom (manually or via button), re-pin
    if (distanceFromBottom < 20) {
        isPinnedToBottom = true;
        (window as unknown as { isPinnedToBottom: boolean }).isPinnedToBottom = true;
        newMessageCount = 0;
        const btn = document.getElementById('scroll-to-bottom-btn');
        if (btn) btn.classList.add('hidden');
    }
}

/**
 * Scroll to bottom smoothly and reset counter
 */
export function scrollToBottom(): void {
    const container = document.getElementById('chat-messages');
    if (container) {
        container.scrollTo({
            top: container.scrollHeight,
            behavior: 'smooth'
        });
        isPinnedToBottom = true; // Re-pin when user clicks scroll button
        newMessageCount = 0;
        const btn = document.getElementById('scroll-to-bottom-btn');
        if (btn) btn.classList.add('hidden');
    }
}

// Initialize scroll listener
export function initScrollListener(): void {
    const container = document.getElementById('chat-messages');
    if (container) {
        // Handle user scroll to detect if they scrolled away from bottom
        container.addEventListener('scroll', handleUserScroll);
    }

    // Create scroll button if not exists
    if (!document.getElementById('scroll-to-bottom-btn')) {
        const btn = document.createElement('button');
        btn.id = 'scroll-to-bottom-btn';
        btn.className = 'scroll-to-bottom-btn hidden';
        btn.innerHTML = `
            <span id="new-message-count" class="new-message-count">0</span>
            <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2">
                <path d="M19 14l-7 7m0 0l-7-7m7 7V3"/>
            </svg>
        `;
        btn.onclick = scrollToBottom;

        // Add to chat-section (the correct parent container)
        const chatSection = document.querySelector('.chat-section');
        if (chatSection) {
            chatSection.appendChild(btn);
        }
    }
}

export interface ChatMessage {
    role: 'user' | 'ai' | 'system';
    text: string;
    timestamp?: number;
    imageUrl?: string;
}

/**
 * Add a message to the chat
 */
export function addMessage(role: 'user' | 'ai', text: string, _audioUrl?: string | null, imageUrl?: string | null): void {
    const elements = getElements();
    const container = elements.chatContainer;
    if (!container) return;

    const msgDiv = document.createElement('div');
    msgDiv.className = `message ${role}`;

    // Add image if present
    if (imageUrl) {
        const img = document.createElement('img');
        img.src = imageUrl;
        img.className = 'message-image';
        msgDiv.appendChild(img);
    }

    // Add text
    const textDiv = document.createElement('div');
    textDiv.className = 'message-text';

    let displayText = text;
    if (role === 'ai') {
        // Format AI messages with vocabulary highlighting (also logs words)
        displayText = Vocabulary.formatMessage(text);
    }
    textDiv.innerHTML = displayText;

    msgDiv.appendChild(textDiv);

    // Image generation button removed (requires paid billing)

    // Add timestamp
    const timeDiv = document.createElement('div');
    timeDiv.className = 'message-time';
    timeDiv.textContent = new Date().toLocaleTimeString();
    msgDiv.appendChild(timeDiv);

    container.appendChild(msgDiv);
    // DISABLED: Auto-scroll - user controls scroll via floating button
    // container.scrollTop = container.scrollHeight;
    incrementNewMessageCount();

    // Save message to localStorage for persistence
    const chatId = getCurrentChatId() || getState().currentChatId;
    if (chatId) {
        saveMessage(chatId, role, displayText);
    }
}


/**
 * Add a system message
 */
export function addSystemMessage(text: string): void {
    const elements = getElements();
    const container = elements.chatContainer;
    if (!container) return;

    const msgDiv = document.createElement('div');
    msgDiv.className = 'message system';
    msgDiv.textContent = text;

    container.appendChild(msgDiv);
    // DISABLED: Auto-scroll
    // container.scrollTop = container.scrollHeight;
    incrementNewMessageCount();
}

/**
 * Clear all messages
 */
export function clearMessages(): void {
    const elements = getElements();
    if (elements.chatContainer) {
        elements.chatContainer.innerHTML = '';
    }
}

/**
 * Send a text message
 */
export async function sendTextMessage(): Promise<void> {
    const elements = getElements();
    const state = getState();
    const text = elements.textInput?.value?.trim() || '';

    if (!text && state.pendingAttachments.length === 0) return;

    // If not connected, use HTTP API
    if (!state.isConnected) {
        await sendViaHttp(text);
    } else {
        await sendViaWebSocket(text);
    }

    // Clear input
    if (elements.textInput) {
        elements.textInput.value = '';
    }
}

async function sendViaHttp(text: string): Promise<void> {
    const state = getState();
    const apiKey = localStorage.getItem('gemini_api_key');

    if (!apiKey) {
        addSystemMessage('❌ Set API key first');
        return;
    }

    // Add user message
    const imagePreview = state.pendingAttachments.find(a => a.type.startsWith('image/'))?.preview || null;
    addMessage('user', text || '[Image]', null, imagePreview);
    addToHistory({ role: 'user', parts: [{ text: text || '[Image]' }] });

    // Build request
    const customInstructions = localStorage.getItem('gemini_system_instruction') || '';
    const context = state.conversationHistory.map(m => ({
        role: m.role,
        text: m.parts?.[0]?.text || m.text || ''
    }));

    const body: Record<string, unknown> = {
        api_key: apiKey,
        message: text || '',
        context: context.slice(-10),
        custom_instructions: customInstructions
    };

    // Add image if attached
    const imageAtt = state.pendingAttachments.find(a => a.type.startsWith('image/'));
    if (imageAtt?.data) {
        body.image = imageAtt.data.includes(',')
            ? imageAtt.data.split(',')[1]
            : imageAtt.data;
    }

    try {
        const response = await fetch('/api/chat', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(body)
        });

        const data = await response.json();

        if (data.error) {
            addSystemMessage('❌ ' + data.error);
        } else if (data.text) {
            addMessage('ai', data.text);
            addToHistory({ role: 'model', parts: [{ text: data.text }] });
        }
    } catch (e) {
        addSystemMessage('❌ Request failed: ' + (e as Error).message);
    }
}

async function sendViaWebSocket(text: string): Promise<void> {
    const state = getState();

    addMessage('user', text);
    addToHistory({ role: 'user', parts: [{ text }] });

    // Save last user input for Continue button resend
    setState({ lastUserInput: text });

    const msg: Record<string, unknown> = { type: 'text', data: text };

    if (state.pendingAttachments.length > 0) {
        msg.attachments = state.pendingAttachments.map(a => ({
            type: a.type,
            data: a.data
        }));
    }

    state.ws?.send(JSON.stringify(msg));
}

// Setup event listeners for custom events
export function initChatListeners(): void {
    window.addEventListener('system-message', ((e: CustomEvent) => {
        addSystemMessage(e.detail.text);
    }) as EventListener);

    window.addEventListener('chat-message', ((e: CustomEvent) => {
        addMessage(e.detail.role, e.detail.text);
    }) as EventListener);

    // Listen for streaming display finalize
    window.addEventListener('streaming-finalize', ((e: CustomEvent) => {
        if (e.detail.text) {
            addMessage('ai', e.detail.text);
            addToHistory({ role: 'model', parts: [{ text: e.detail.text }] });
        }
    }) as EventListener);
}

/**
 * Show AI waiting indicator
 */
export function showAIWaiting(): void {
    const indicator = document.getElementById('ai-waiting');
    if (indicator) {
        indicator.classList.remove('hidden');
        // Auto-scroll disabled — user controls scroll via floating button
    }
}

/**
 * Hide AI waiting indicator
 */
export function hideAIWaiting(): void {
    const indicator = document.getElementById('ai-waiting');
    if (indicator) {
        indicator.classList.add('hidden');
    }
}



export const Chat = {
    addMessage,
    addSystemMessage,
    clearMessages,
    sendTextMessage,
    initListeners: initChatListeners,
    initScrollListener,
    scrollToBottom,
    showAIWaiting,
    hideAIWaiting,

};
