/**
 * Cheatsheet Module-Floating grammar helper
 * Tab 1:📋 Справочник — grammar tables by language + level
 * Tab 2:📝 Слова — word list + search + TTS
 */
import { t } from './i18n';

let cheatsheetWindow: HTMLElement | null = null;
let isDragging = false;
let isResizing = false;
let resizeDirection = '';

let dragOffset = { x: 0, y: 0 };
let resizeStart = { x: 0, y: 0, width: 0, height: 0 };
let wordsData: { words: string[], count: number, level: string } | null = null;

const SIZE_CACHE_KEY = 'cheatsheet_size';
const DEFAULT_SIZE = { width: 460, height: 520 };

