/**
 * Notifications Module (TypeScript)
 * Toast notifications and confirmation dialogs
 */

class NotificationsModule {
    private container: HTMLElement | null = null;

    /**
     * Show toast notification
     */
    showToast(message: string, duration = 3000): void {
        const container = this.getContainer();

        const toast = document.createElement('div');
        toast.className = 'toast';
        toast.innerHTML = message;

        container.appendChild(toast);

        // Use RAF for smoother animation
        requestAnimationFrame(() => {
            toast.classList.add('show');
        });

        setTimeout(() => {
            toast.classList.remove('show');
            setTimeout(() => toast.remove(), 300);
        }, duration);
    }

    private getContainer(): HTMLElement {
        if (!this.container) {
            this.container = document.getElementById('toast-container');
            if (!this.container) {
                this.container = document.createElement('div');
                this.container.id = 'toast-container';
                this.container.className = 'toast-container';
                document.body.appendChild(this.container);
            }
        }
        return this.container;
    }

    /**
     * Confirm action with modal
     */
    confirmAction(message: string, onConfirm: () => void): void {
        const overlay = document.createElement('div');
        overlay.className = 'confirm-overlay';
        overlay.innerHTML = `
            <div class="confirm-modal">
                <div class="confirm-message">${message}</div>
                <div class="confirm-buttons">
                    <button class="confirm-btn confirm-no">❌ Нет</button>
                    <button class="confirm-btn confirm-yes">✅ Да</button>
                </div>
            </div>
        `;

        const close = () => overlay.remove();

        overlay.querySelector('.confirm-no')!.addEventListener('click', close);
        overlay.querySelector('.confirm-yes')!.addEventListener('click', () => {
            close();
            onConfirm();
        });
        overlay.addEventListener('click', (e) => {
            if (e.target === overlay) close();
        });

        document.body.appendChild(overlay);
    }

    /**
     * Show log notification for vocabulary
     */
    showLogNotification(args: { term?: string; definition?: string }): void {
        const { term = 'Unknown', definition = '' } = args;
        if (term && definition) {
            this.showToast(`📚 ${term}: ${definition}`, 2000);
        }
    }
}

export const Notifications = new NotificationsModule();

// Global exports
if (typeof window !== 'undefined') {
    (window as any).Notifications = Notifications;
    (window as any).showToast = (msg: string, d?: number) => Notifications.showToast(msg, d);
    (window as any).confirmAction = (msg: string, cb: () => void) => Notifications.confirmAction(msg, cb);
    (window as any).showLogNotification = (args: { term?: string; definition?: string }) => Notifications.showLogNotification(args);
}

console.log('[Notifications] Module loaded (TS)');
