/**
 * DOM elements cache for type-safe access
 */
export interface AppElements {
    // Input
    textInput: HTMLTextAreaElement | null;
    sendBtn: HTMLButtonElement | null;
    attachBtn: HTMLButtonElement | null;
    fileInput: HTMLInputElement | null;

    // Controls
    saveBtn: HTMLButtonElement | null;
    newChatBtn: HTMLButtonElement | null;
    stopBtn: HTMLButtonElement | null;

    // Video
    videoSection: HTMLElement | null;
    videoPreview: HTMLVideoElement | null;
    videoPlaceholder: HTMLElement | null;
    cameraToggle: HTMLButtonElement | null;

    // Status
    statusText: HTMLElement | null;
    statusDot: HTMLElement | null;
    micLevel: HTMLElement | null;
    stopRow: HTMLElement | null;

    // Settings
    themeSelect: HTMLSelectElement | null;
    languageLevel: HTMLSelectElement | null;
    voiceSelect: HTMLSelectElement | null;

    // Chat
    chatList: HTMLElement | null;
    chatContainer: HTMLElement | null;
    contextMenu: HTMLElement | null;

    // Progress
    progressWidget: HTMLElement | null;
}

/**
 * Initialize all DOM elements
 */
export function initElements(): AppElements {
    return {
        // Input
        textInput: document.getElementById('text-input') as HTMLTextAreaElement,
        sendBtn: document.getElementById('send-btn') as HTMLButtonElement,
        attachBtn: document.getElementById('attach-btn') as HTMLButtonElement,
        fileInput: document.getElementById('file-input') as HTMLInputElement,

        // Controls
        saveBtn: document.getElementById('save-btn') as HTMLButtonElement,
        newChatBtn: document.getElementById('new-chat-btn') as HTMLButtonElement,
        stopBtn: document.getElementById('stop-btn') as HTMLButtonElement,

        // Video
        videoSection: document.getElementById('video-section'),
        videoPreview: document.getElementById('video-preview') as HTMLVideoElement,
        videoPlaceholder: document.getElementById('video-placeholder'),
        cameraToggle: document.getElementById('camera-toggle') as HTMLButtonElement,

        // Status
        statusText: document.getElementById('status-text'),
        statusDot: document.getElementById('status-dot'),
        micLevel: document.getElementById('mic-level-bar'),
        stopRow: document.getElementById('stop-row'),

        // Settings
        themeSelect: document.getElementById('theme-select') as HTMLSelectElement,
        languageLevel: document.getElementById('language-level') as HTMLSelectElement,
        voiceSelect: document.getElementById('voice-select') as HTMLSelectElement,

        // Chat
        chatList: document.getElementById('chat-list'),
        chatContainer: document.getElementById('chat-messages'),
        contextMenu: document.getElementById('context-menu'),

        // Progress
        progressWidget: document.getElementById('progress-widget'),
    };
}

// Global elements instance
let elements: AppElements;

export function getElements(): AppElements {
    if (!elements) {
        elements = initElements();
    }
    return elements;
}
