/**
 * Tooltip Hints — "?" icons next to label text (inline, to the right)
 */

import { t } from './i18n';

interface TooltipConfig {
    target: string;
    key: string;  // i18n translation key
}

const TOOLTIPS: TooltipConfig[] = [
    { target: '.settings-group:has(#api-key)', key: 'tip_apikey' },
    { target: '.settings-group:has(#voice-select)', key: 'tip_voice' },
    { target: '.settings-group:has(#speech-rate)', key: 'tip_speed' },
    { target: '.language-row', key: 'tip_langs' },
    { target: '.settings-group:has(#language-level)', key: 'tip_level' },
    { target: '.teacher-mode-group', key: 'tip_trainer' },
    { target: '.settings-group:has(#theme-select)', key: 'tip_theme' },
];

let activePopup: HTMLElement | null = null;

function closeActivePopup(): void {
    if (activePopup) {
        activePopup.remove();
        activePopup = null;
    }
}

function showTooltipPopup(btn: HTMLElement, key: string): void {
    closeActivePopup();

    const text = t(key);
    const popup = document.createElement('div');
    popup.className = 'tooltip-popup';
    popup.innerHTML = text.replace(/\\n/g, '<br>');
    document.body.appendChild(popup);
    activePopup = popup;

    const rect = btn.getBoundingClientRect();
    const popupW = 250;
    let left = rect.left - popupW - 10;
    if (left < 10) left = rect.right + 10;
    let top = rect.top - 10;
    if (top + 180 > window.innerHeight) top = window.innerHeight - 190;
    if (top < 10) top = 10;

    popup.style.left = `${left}px`;
    popup.style.top = `${top}px`;
    popup.style.width = `${popupW}px`;

    setTimeout(() => {
        const handler = (e: MouseEvent) => {
            if (!popup.contains(e.target as Node) && e.target !== btn) {
                closeActivePopup();
                document.removeEventListener('click', handler);
            }
        };
        document.addEventListener('click', handler);
    }, 50);
}

export function initTooltips(): void {
    for (const cfg of TOOLTIPS) {
        const target = document.querySelector(cfg.target) as HTMLElement;
        if (!target) continue;

        const btn = document.createElement('button');
        btn.className = 'tooltip-hint-btn';
        btn.textContent = '?';
        btn.type = 'button';
        btn.title = '?';

        btn.addEventListener('click', (e) => {
            e.stopPropagation();
            e.preventDefault();
            showTooltipPopup(btn, cfg.key);
        });

        // Insert INSIDE the first <label> — inline, to the right of text
        const label = target.querySelector('label');
        if (label) {
            label.appendChild(btn);
        } else {
            target.prepend(btn);
        }
    }

    document.addEventListener('keydown', (e) => {
        if (e.key === 'Escape') closeActivePopup();
    });
}
