/**
 * Screen Capture Module (TypeScript)
 * Handles video/screen capture and encoding for Gemini Live
 */

import type { ScreenCaptureOptions } from '../types';

class ScreenCaptureModule {
    private captureInterval: number | null = null;
    private lastScreenshot: string | null = null;
    private canvas: HTMLCanvasElement | null = null;
    private ctx: CanvasRenderingContext2D | null = null;

    /**
     * Start capturing frames from video element
     */
    start(
        videoElement: HTMLVideoElement,
        ws: WebSocket,
        options: ScreenCaptureOptions
    ): boolean {
        if (!videoElement?.srcObject) {
            console.log('[ScreenCapture] No video source');
            return false;
        }

        // Create reusable canvas (performance optimization)
        this.canvas = document.createElement('canvas');
        this.ctx = this.canvas.getContext('2d', { alpha: false })!;

        const interval = options.interval ?? 1000;

        this.captureInterval = window.setInterval(() => {
            if (!options.isConnected() || !ws || !videoElement.videoWidth) return;

            // Set canvas size
            this.canvas!.width = Math.min(videoElement.videoWidth, 1280);
            this.canvas!.height = Math.min(videoElement.videoHeight, 960);

            // Draw frame
            this.ctx!.drawImage(videoElement, 0, 0, this.canvas!.width, this.canvas!.height);

            // Encode as JPEG
            const dataUrl = this.canvas!.toDataURL('image/jpeg', 0.85);
            const base64 = dataUrl.slice(dataUrl.indexOf(',') + 1);

            this.lastScreenshot = dataUrl;

            // Send to server
            ws.send(JSON.stringify({ type: 'image', data: base64 }));
        }, interval);

        console.log('[ScreenCapture] Started');
        return true;
    }

    stop(): void {
        if (this.captureInterval) {
            clearInterval(this.captureInterval);
            this.captureInterval = null;
        }
        this.canvas = null;
        this.ctx = null;
        console.log('[ScreenCapture] Stopped');
    }

    getLastScreenshot(): string | null {
        return this.lastScreenshot;
    }

    openFullscreen(src: string): void {
        let lightbox = document.getElementById('screenshot-lightbox') as HTMLDivElement | null;

        if (!lightbox) {
            lightbox = document.createElement('div');
            lightbox.id = 'screenshot-lightbox';
            lightbox.className = 'screenshot-lightbox';
            lightbox.innerHTML = `
                <div class="lightbox-content">
                    <img class="lightbox-img" />
                    <button class="lightbox-close">✕</button>
                </div>
            `;
            lightbox.addEventListener('click', (e) => {
                const target = e.target as HTMLElement;
                if (target === lightbox || target.classList.contains('lightbox-close')) {
                    lightbox!.classList.remove('active');
                }
            });
            document.body.appendChild(lightbox);
        }

        (lightbox.querySelector('.lightbox-img') as HTMLImageElement).src = src;
        lightbox.classList.add('active');
    }
}

export const ScreenCapture = new ScreenCaptureModule();

// Click handler for context images
document.addEventListener('click', (e) => {
    const target = e.target as HTMLElement;
    if (target.classList.contains('context-img')) {
        ScreenCapture.openFullscreen((target as HTMLImageElement).src);
    }
});

// Global export
if (typeof window !== 'undefined') {
    (window as any).ScreenCapture = ScreenCapture;
    (window as any).openScreenshotFullscreen = (src: string) => ScreenCapture.openFullscreen(src);
}

console.log('[ScreenCapture] Module loaded (TS)');
